import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface SurveySubmission {
  name: string;
  email: string;
  satisfactionRating: string;
  featureInterests: string[];
  comments: string;
}

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: Submit Survey */
  submit?: (payload: SurveySubmission) => Promise<void> | void;
}

export default function GeneratedComponent({
  featureOptions = ['Feature A', 'Feature B', 'Feature C'],
  satisfactionLabels = [
    'Very Unsatisfied',
    'Unsatisfied',
    'Neutral',
    'Satisfied',
    'Very Satisfied',
  ],
  submit,
}: Props) {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({
    name: false,
    email: false,
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(null);

  const maxComments = 500;
  const totalSteps = 5;

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailRegex.test(email)
      ? 'Please enter a valid email address.'
      : '';

  const isStep1Valid = !!name.trim() && !!email.trim() && emailRegex.test(email);
  const isStep2Valid = !!satisfactionRating;
  const canGoNext = (step === 1 && isStep1Valid) || (step === 2 && isStep2Valid) || (step === 3 || step === 4);

  const satisfactionOptions = useMemo(
    () =>
      satisfactionLabels.slice(0, 5).map((label, index) => ({
        value: String(index + 1),
        label: `${index + 1} - ${label}`,
      })),
    [satisfactionLabels]
  );

  const progressValue = (step / totalSteps) * 100;

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, feature] : prev.filter((item) => item !== feature)
    );
  };

  const handleNext = () => {
    if (step === 1) {
      setTouched({ name: true, email: true });
      if (!isStep1Valid) return;
    }
    if (step === 2 && !isStep2Valid) return;
    setStep((prev) => Math.min(totalSteps, prev + 1));
  };

  const handleBack = () => {
    setStep((prev) => Math.max(1, prev - 1));
  };

  const handleSubmit = async () => {
    if (!submit) return;
    setFeedback(null);
    setIsSubmitting(true);

    const payload: SurveySubmission = {
      name: name.trim(),
      email: email.trim(),
      satisfactionRating,
      featureInterests,
      comments: comments.trim(),
    };

    try {
      await submit(payload);
      setFeedback({ type: 'success', message: 'Survey submitted successfully.' });
    } catch {
      setFeedback({ type: 'error', message: 'Submission failed. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={8}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            as="div"
          >
            Step {step} of {totalSteps}
          </Text>
          <Progress value={progressValue} max={100} size="md" />
        </Stack>

        {feedback && (
          <Alert variant={feedback.type === 'success' ? 'success' : 'error'}>
            {feedback.message}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Contact Information
            </Text>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              placeholder="Enter your name"
              error={nameError}
              onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
              aria-label="Name"
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              placeholder="Enter your email"
              error={emailError}
              onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
              aria-label="Email"
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Satisfaction Rating
            </Text>
            <RadioGroup
              label="How satisfied are you?"
              value={satisfactionRating}
              onChange={setSatisfactionRating}
              options={satisfactionOptions}
              direction="vertical"
              error={!isStep2Valid ? 'Please select a rating before continuing.' : ''}
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Feature Interests
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select all that apply.
            </Text>
            <Stack gap={8}>
              {featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={featureInterests.includes(feature)}
                  onChange={(checked) => toggleFeature(feature, checked)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Additional Comments
            </Text>
            <TextArea
              label="Comments (optional)"
              value={comments}
              onChange={setComments}
              maxLength={maxComments}
              showCount
              rows={6}
              placeholder="Share any additional thoughts..."
              aria-label="Additional comments"
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Review Your Answers
            </Text>
            <Card
              padding={16}
              border
              shadow="none"
              radius="md"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={8}>
                <Text variant="body"><strong>Name:</strong> {name || '—'}</Text>
                <Text variant="body"><strong>Email:</strong> {email || '—'}</Text>
                <Text variant="body">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfactionLabels[Number(satisfactionRating) - 1] || '—'}
                </Text>
                <Text variant="body">
                  <strong>Feature Interests:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                </Text>
                <Text variant="body">
                  <strong>Comments:</strong> {comments.trim() || 'No comments provided'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={12}>
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={step === 1 || isSubmitting}
            aria-label="Go to previous step"
          >
            Back
          </Button>

          {step < totalSteps ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!canGoNext || isSubmitting}
              aria-label="Go to next step"
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              loading={isSubmitting}
              disabled={isSubmitting}
              aria-label="Submit survey"
            >
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(undefined);

  const categoryColors = useMemo<Record<string, string>>(
    () => ({
      'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
      'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
      'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
      metalloid: 'var(--ggui-color-success-500, #22c55e)',
      nonmetal: 'var(--ggui-color-primary-600, #0284c7)',
      halogen: 'var(--ggui-color-warning-600, #d97706)',
      'noble gas': 'var(--ggui-color-success-600, #16a34a)',
      lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
      actinide: 'var(--ggui-color-error-600, #dc2626)',
      unknown: 'var(--ggui-color-neutral-500, #6b7280)',
    }),
    []
  );

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(
    () =>
      elements.filter((el) => {
        if (!normalizedQuery) return true;
        const n = (el.name ?? '').toLowerCase();
        const s = (el.symbol ?? '').toLowerCase();
        return n.includes(normalizedQuery) || s.includes(normalizedQuery);
      }),
    [elements, normalizedQuery]
  );

  const selectedElement = useMemo(
    () =>
      elements.find((el) => el.atomicNumber === selectedAtomicNumber) ??
      filteredElements[0] ??
      null,
    [elements, filteredElements, selectedAtomicNumber]
  );

  const categories = useMemo(() => {
    const unique = new Set<string>();
    elements.forEach((el) => {
      if (el.category) unique.add(el.category);
    });
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }, [elements]);

  const getCategoryColor = (category?: string) => {
    if (!category) return categoryColors.unknown;
    const key = category.toLowerCase();
    return categoryColors[key] ?? 'var(--ggui-color-neutral-400, #9ca3af)';
  };

  return (
    <Card
      padding={16}
      shadow="sm"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Text
          variant="label"
          size="xl"
          weight="semibold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          type="search"
          placeholder="Search by name or symbol..."
          value={query}
          onChange={setQuery}
          helperText="Type to filter elements by name or symbol."
        />

        <Card
          padding={12}
          shadow="none"
          border
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(48px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minHeight: '240px',
            }}
          >
            {filteredElements.map((el) => {
              const row = el.row ?? 1;
              const col = el.col ?? 1;
              const isActive = selectedElement?.atomicNumber === el.atomicNumber;

              return (
                <Button
                  key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? 'unknown'}`}
                  variant={isActive ? 'primary' : 'secondary'}
                  size="sm"
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                  aria-label={`${el.name ?? 'Unknown'} (${el.symbol ?? ''}) atomic number ${el.atomicNumber ?? 'unknown'}`}
                  style={{
                    gridRow: row,
                    gridColumn: col,
                    minHeight: '56px',
                    position: 'relative',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    border: `1px solid ${isActive ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`,
                    background: isActive
                      ? 'var(--ggui-color-container, #ede9fe)'
                      : getCategoryColor(el.category),
                    color: isActive
                      ? 'var(--ggui-color-onContainer, #4c1d95)'
                      : 'var(--ggui-color-onSurface, #18181b)',
                    boxShadow: isActive
                      ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'
                      : 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                    transition: 'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                  }}
                >
                  <span
                    style={{
                      position: 'absolute',
                      top: '4px',
                      left: '6px',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      fontWeight: 'var(--ggui-font-weight-medium, 500)',
                      lineHeight: 1,
                    }}
                  >
                    {el.atomicNumber ?? '—'}
                  </span>
                  <span
                    style={{
                      display: 'block',
                      width: '100%',
                      textAlign: 'center',
                      fontSize: 'var(--ggui-font-size-xl, 20px)',
                      fontWeight: 'var(--ggui-font-weight-bold, 700)',
                      lineHeight: 1.1,
                    }}
                  >
                    {el.symbol ?? '—'}
                  </span>
                </Button>
              );
            })}
          </div>
        </Card>

        <Card
          padding={12}
          shadow="none"
          border
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Text>
            {selectedElement ? (
              <Stack gap={4}>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Name: {selectedElement.name ?? '—'}
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Symbol: {selectedElement.symbol ?? '—'}
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Atomic Number: {selectedElement.atomicNumber ?? '—'}
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Atomic Weight: {selectedElement.atomicWeight ?? '—'}
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  Category: {selectedElement.category ?? '—'}
                </Text>
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No element selected.
              </Text>
            )}
          </Stack>
        </Card>

        <Card
          padding={12}
          shadow="none"
          border
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((category) => (
                <Stack
                  key={category}
                  direction="horizontal"
                  align="center"
                  gap={6}
                  style={{
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    padding: '4px 8px',
                    background: 'var(--ggui-color-surface, #fafafa)',
                  }}
                >
                  <span
                    aria-hidden="true"
                    style={{
                      width: '12px',
                      height: '12px',
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      background: getCategoryColor(category),
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                    }}
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                    {category}
                  </Text>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;

  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Chat',
    currentUser = '',
    participantCount,
    messages = [],
    sendMessage,
  } = props;

  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);

  const listRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(
    () => [...messages, ...streamMessages],
    [messages, streamMessages]
  );

  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      items: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      const prev = groups[groups.length - 1];
      if (prev && prev.sender === msg.sender) {
        prev.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });

    return groups;
  }, [allMessages]);

  const formatTime = (iso?: string) => {
    if (!iso) return '';
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return '';
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const scrollToBottom = (smooth = false) => {
    if (listRef.current) {
      listRef.current.scrollTo({
        top: listRef.current.scrollHeight,
        behavior: smooth ? 'smooth' : 'auto',
      });
    }
  };

  useEffect(() => {
    scrollToBottom(false);
  }, []);

  useEffect(() => {
    scrollToBottom(true);
  }, [allMessages.length]);

  // Stream Contract: listen for incoming agent data
  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const payload = customEvent.detail;
      if (payload && (payload.text || payload.sender || payload.timestamp)) {
        setStreamMessages((prev) => [...prev, payload]);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  const handleSend = () => {
    const trimmed = draft.trim();
    if (!trimmed) return;

    const payload = {
      text: trimmed,
      timestamp: new Date().toISOString(),
    };

    if (sendMessage) {
      sendMessage(payload);
    }

    setDraft('');
  };

  return (
    <Card
      padding="var(--ggui-spacing-4, 16px)"
      shadow="sm"
      border
      radius="lg"
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" justify="between" align="center">
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            as="div"
          >
            {title}
          </Text>
          {typeof participantCount === 'number' && (
            <Badge variant="primary" size="sm" pill>
              {participantCount}
            </Badge>
          )}
        </Stack>

        <Card
          padding="var(--ggui-spacing-2, 8px)"
          shadow="none"
          border
          radius="md"
        >
          <Stack
            gap="var(--ggui-spacing-2, 8px)"
            // @ts-ignore style passthrough for primitive wrapper
            style={{
              height: 'var(--ggui-chat-list-height, 340px)',
              overflowY: 'auto',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
            // @ts-ignore
            ref={listRef}
            aria-label="Message list"
          >
            {groupedMessages.map((group, groupIndex) => {
              const isMine = (group.sender || '') === currentUser;
              return (
                <Stack
                  key={`${group.sender || 'unknown'}-${groupIndex}`}
                  gap="var(--ggui-spacing-1, 4px)"
                  align={isMine ? 'end' : 'start'}
                >
                  {group.items.map((item, itemIndex) => (
                    <Card
                      key={`${groupIndex}-${itemIndex}-${item.timestamp || ''}-${item.text || ''}`}
                      padding="var(--ggui-spacing-2, 8px)"
                      radius="md"
                      shadow="none"
                      border
                      // @ts-ignore
                      style={{
                        maxWidth: '80%',
                        background: isMine
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                        transition: 'background-color 200ms ease-in-out',
                      }}
                    >
                      <Stack gap="var(--ggui-spacing-1, 4px)">
                        <Text
                          variant="caption"
                          weight="medium"
                          color={
                            isMine
                              ? 'var(--ggui-color-surface, #fafafa)'
                              : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                          }
                          as="div"
                        >
                          {item.sender || ''}
                        </Text>
                        <Text
                          variant="bodySmall"
                          color={
                            isMine
                              ? 'var(--ggui-color-surface, #fafafa)'
                              : 'var(--ggui-color-onSurface, #18181b)'
                          }
                          as="div"
                        >
                          {item.text || ''}
                        </Text>
                        <Text
                          variant="caption"
                          color={
                            isMine
                              ? 'var(--ggui-color-primary-100, #e0f2fe)'
                              : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                          }
                          as="div"
                          align={isMine ? 'right' : 'left'}
                        >
                          {formatTime(item.timestamp)}
                        </Text>
                      </Stack>
                    </Card>
                  ))}
                </Stack>
              );
            })}
          </Stack>
        </Card>

        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="end">
          <Input
            label=""
            placeholder="Type a message..."
            value={draft}
            onChange={setDraft}
            size="md"
            aria-label="Compose message"
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleSend();
              }
            }}
          />
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

