import React, { useEffect, useMemo, useState } from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Card,
  Box,
  Spinner,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

type ConnectionState = 'connecting' | 'connected' | 'disconnected';

export default function GeneratedComponent({
  stocks = [],
  lastUpdated,
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [connectionState, setConnectionState] = useState<ConnectionState>('connecting');
  const [isLoading, setIsLoading] = useState<boolean>(true);

  useEffect(() => {
    setLiveStocks(stocks);
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    let hasReceivedFirstPayload = false;
    let disconnectTimer: number | undefined;

    const scheduleDisconnectTimeout = () => {
      if (disconnectTimer) {
        window.clearTimeout(disconnectTimer);
      }
      disconnectTimer = window.setTimeout(() => {
        if (!hasReceivedFirstPayload) {
          setConnectionState('disconnected');
          setIsLoading(false);
        }
      }, 12000);
    };

    scheduleDisconnectTimeout();

    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{
        stocks?: Props['stocks'];
        lastUpdated?: string;
      }>;

      const detail = customEvent?.detail;
      if (!detail || typeof detail !== 'object') {
        return;
      }

      let hasValidPayloadField = false;

      if (Array.isArray(detail.stocks)) {
        const sanitizedStocks = detail.stocks.map((item) => ({
          symbol: typeof item?.symbol === 'string' ? item.symbol : undefined,
          name: typeof item?.name === 'string' ? item.name : undefined,
          price: typeof item?.price === 'number' && Number.isFinite(item.price) ? item.price : undefined,
          change: typeof item?.change === 'number' && Number.isFinite(item.change) ? item.change : undefined,
          changePercent:
            typeof item?.changePercent === 'number' && Number.isFinite(item.changePercent)
              ? item.changePercent
              : undefined,
        }));
        setLiveStocks(sanitizedStocks);
        hasValidPayloadField = true;
      }

      if (typeof detail.lastUpdated === 'string') {
        setLiveLastUpdated(detail.lastUpdated);
        hasValidPayloadField = true;
      }

      if (hasValidPayloadField) {
        hasReceivedFirstPayload = true;
        setIsLoading(false);
        setConnectionState('connected');
        scheduleDisconnectTimeout();
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);

    return () => {
      if (disconnectTimer) {
        window.clearTimeout(disconnectTimer);
      }
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  const formattedLastUpdated = useMemo(() => {
    if (!liveLastUpdated) return 'Not available';
    const parsed = new Date(liveLastUpdated);
    if (Number.isNaN(parsed.getTime())) return liveLastUpdated;
    return parsed.toLocaleString();
  }, [liveLastUpdated]);

  const getTrend = (changePercent?: number): 'up' | 'down' | 'flat' => {
    const value = changePercent ?? 0;
    if (value > 0) return 'up';
    if (value < 0) return 'down';
    return 'flat';
  };

  const formatPrice = (value?: number) => (value ?? 0).toFixed(2);

  const formatSigned = (value?: number) => {
    const amount = value ?? 0;
    const sign = amount > 0 ? '+' : amount < 0 ? '-' : '';
    return `${sign}${Math.abs(amount).toFixed(2)}`;
  };

  const formatSignedPercent = (value?: number) => `${formatSigned(value)}%`;

  const trendColor = (trend: 'up' | 'down' | 'flat') => {
    if (trend === 'up') return 'var(--ggui-color-success-600, #16a34a)';
    if (trend === 'down') return 'var(--ggui-color-error-600, #dc2626)';
    return 'var(--ggui-color-onSurfaceVariant, #52525b)';
  };

  return (
    <Container
      maxWidth="xl"
      padding="var(--ggui-spacing-6, 24px)"
    >
      <Stack
        gap="var(--ggui-spacing-6, 24px)"
      >
        <Box
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
          padding="var(--ggui-spacing-4, 16px)"
          style={{ border: '1px solid var(--ggui-color-outline, #d4d4d8)' }}
          aria-label="Stock ticker dashboard"
        >
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Stack direction="horizontal" justify="between" align="center" wrap>
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                Market Watch
              </Heading>

              <Stack gap="var(--ggui-spacing-1, 4px)" aria-live="polite">
                <Text
                  variant="bodySmall"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Last Updated: {formattedLastUpdated}
                </Text>

                {connectionState === 'connecting' && (
                  <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                    <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Connecting to live market feed...
                    </Text>
                  </Stack>
                )}

                {connectionState === 'connected' && (
                  <Text variant="caption" color="var(--ggui-color-success-600, #16a34a)">
                    Live
                  </Text>
                )}
              </Stack>
            </Stack>

            {connectionState === 'disconnected' && (
              <Alert variant="warning" title="Connection status">
                Live feed disconnected
              </Alert>
            )}

            <Box
              role="list"
              aria-busy={isLoading}
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(1, minmax(0, 1fr))',
                gap: 'var(--ggui-spacing-4, 16px)',
              }}
            >
              <style>
                {`
                  @media (min-width: 1024px) {
                    .ggui-stock-grid {
                      grid-template-columns: repeat(3, minmax(0, 1fr));
                    }
                  }
                `}
              </style>

              <Box
                className="ggui-stock-grid"
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(1, minmax(0, 1fr))',
                  gap: 'var(--ggui-spacing-4, 16px)',
                }}
              >
                {liveStocks.map((stock, index) => {
                  const trend = getTrend(stock.changePercent);
                  const color = trendColor(trend);
                  const arrow = trend === 'up' ? '▲' : trend === 'down' ? '▼' : '';

                  return (
                    <Card
                      key={`${stock.symbol ?? 'stock'}-${index}`}
                      role="listitem"
                      shadow="sm"
                      radius="lg"
                      border
                      padding="var(--ggui-spacing-4, 16px)"
                      style={{
                        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        borderColor: color,
                        transition: 'border-color 200ms ease-in-out, color 200ms ease-in-out',
                      }}
                    >
                      <Stack gap="var(--ggui-spacing-2, 8px)">
                        <Stack direction="horizontal" justify="between" align="center">
                          <Text
                            as="span"
                            size="2xl"
                            weight="bold"
                            color="var(--ggui-color-onSurface, #18181b)"
                          >
                            {stock.symbol ?? '—'}
                          </Text>
                          <Text as="span" variant="label" color={color}>
                            {arrow ? `${arrow} ${formatSignedPercent(stock.changePercent)}` : formatSignedPercent(stock.changePercent)}
                          </Text>
                        </Stack>

                        <Text
                          variant="bodySmall"
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        >
                          {stock.name ?? 'Unknown Company'}
                        </Text>

                        <Stack direction="horizontal" justify="between" align="center" wrap>
                          <Text
                            variant="bodyLarge"
                            weight="semibold"
                            color="var(--ggui-color-onSurface, #18181b)"
                          >
                            ${formatPrice(stock.price)}
                          </Text>
                          <Text variant="label" color={color}>
                            {formatSigned(stock.change)} ({formatSignedPercent(stock.changePercent)})
                          </Text>
                        </Stack>
                      </Stack>
                    </Card>
                  );
                })}
              </Box>
            </Box>
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = ['😀', '😎', '🚀', '🌟'],
  roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
  onComplete,
}: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(initialProfile.avatar ?? avatarOptions[0] ?? '');
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);

  const emailValid = useMemo(
    () => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()),
    [email]
  );

  const step1Valid = name.trim().length > 0 && emailValid;
  const step2Valid = role.trim().length > 0;

  const canNext = step === 1 ? step1Valid : step === 2 ? step2Valid : true;

  const emailError =
    touchedEmail && email.trim().length > 0 && !emailValid
      ? 'Please enter a valid email format.'
      : undefined;

  const nextStep = () => {
    if (!canNext) return;
    setStep((s) => Math.min(3, s + 1));
  };

  const prevStep = () => setStep((s) => Math.max(1, s - 1));

  const handleComplete = () => {
    onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        border
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          maxWidth: '640px',
          margin: '0 auto',
        }}
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
              aria-live="polite"
            >
              Step {step} of 3
            </Text>
            <Progress value={step} max={3} size="md" />
          </Stack>

          <Card
            padding={16}
            shadow="none"
            radius="md"
            border
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
            }}
          >
            {step === 1 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  aria-label="Name input"
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={(value) => {
                    setEmail(value);
                    if (!touchedEmail) setTouchedEmail(true);
                  }}
                  onBlur={() => setTouchedEmail(true)}
                  required
                  error={emailError}
                  placeholder="Enter your email"
                  aria-label="Email input"
                />

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Avatar Selection
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {avatarOptions.map((option) => (
                      <Button
                        key={option}
                        variant={avatar === option ? 'primary' : 'outline'}
                        size="md"
                        onClick={() => setAvatar(option)}
                        aria-label={`Select avatar ${option}`}
                      >
                        {option}
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={roleOptions.map((r) => ({ value: r, label: r }))}
                  placeholder="Select your role"
                  required
                />

                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Theme preference
                  </Text>
                  <Toggle
                    label={theme === 'dark' ? 'Dark mode' : 'Light mode'}
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                    size="md"
                  />
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Name: {name || '-'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Email: {email || '-'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Avatar: {avatar || '-'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Role: {role || '-'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Email Notifications: {emailNotifications ? 'On' : 'Off'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Theme: {theme}
                </Text>
              </Stack>
            )}
          </Card>

          <Stack direction="horizontal" justify="between" gap={12}>
            <Button
              variant="ghost"
              onClick={prevStep}
              disabled={step === 1}
              aria-label="Go back"
            >
              Go Back
            </Button>

            {step < 3 ? (
              <Button
                variant="primary"
                onClick={nextStep}
                disabled={!canNext}
                aria-label="Next step"
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleComplete}
                aria-label="Complete setup"
              >
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
      {`__GGUI_META__{"category":"Forms","description":"A 3-step onboarding wizard with validation, progress indication, preferences, review, and completion callback."}`}
    </>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: Submit Survey */
  onSubmit?: (answers: {
    name: string;
    email: string;
    satisfactionRating: string;
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
}

export default function GeneratedComponent({
  featureOptions = ['Feature A', 'Feature B', 'Feature C'],
  satisfactionLabels = [
    'Very Unsatisfied',
    'Unsatisfied',
    'Neutral',
    'Satisfied',
    'Very Satisfied',
  ],
  onSubmit = async () => {},
}: Props) {
  const [step, setStep] = useState(1);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [touched, setTouched] = useState({
    name: false,
    email: false,
    satisfactionRating: false,
  });

  const [submitting, setSubmitting] = useState(false);
  const [submitState, setSubmitState] = useState<{
    type: 'success' | 'error' | null;
    message: string;
  }>({ type: null, message: '' });

  const maxCommentLength = 500;
  const totalSteps = 5;

  const isValidEmail = (value: string) =>
    /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

  const nameError =
    touched.name && !name.trim() ? 'Name is required.' : undefined;
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !isValidEmail(email)
      ? 'Please enter a valid email address.'
      : undefined;
  const ratingError =
    touched.satisfactionRating && !satisfactionRating
      ? 'Please select a satisfaction rating.'
      : undefined;

  const stepValid = useMemo(() => {
    if (step === 1) return !!name.trim() && !!email.trim() && isValidEmail(email);
    if (step === 2) return !!satisfactionRating;
    if (step === 3) return true;
    if (step === 4) return comments.length <= maxCommentLength;
    return true;
  }, [step, name, email, satisfactionRating, comments]);

  const satisfactionOptions = useMemo(
    () =>
      satisfactionLabels.map((label, index) => ({
        value: String(index + 1),
        label: `${index + 1} - ${label}`,
      })),
    [satisfactionLabels]
  );

  const toggleFeature = (option: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, option] : prev.filter((item) => item !== option)
    );
  };

  const handleNext = () => {
    if (step === 1) {
      setTouched((prev) => ({ ...prev, name: true, email: true }));
    }
    if (step === 2) {
      setTouched((prev) => ({ ...prev, satisfactionRating: true }));
    }
    if (stepValid && step < totalSteps) {
      setStep((s) => s + 1);
      setSubmitState({ type: null, message: '' });
    }
  };

  const handleBack = () => {
    if (step > 1) {
      setStep((s) => s - 1);
      setSubmitState({ type: null, message: '' });
    }
  };

  const handleSubmit = async () => {
    setTouched((prev) => ({
      ...prev,
      name: true,
      email: true,
      satisfactionRating: true,
    }));

    const finalValid =
      !!name.trim() && !!email.trim() && isValidEmail(email) && !!satisfactionRating;
    if (!finalValid) {
      setSubmitState({
        type: 'error',
        message: 'Please complete required answers before submitting.',
      });
      setStep(1);
      return;
    }

    setSubmitting(true);
    setSubmitState({ type: null, message: '' });

    try {
      await onSubmit({
        name: name.trim(),
        email: email.trim(),
        satisfactionRating,
        featureInterests,
        comments,
      });
      setSubmitState({
        type: 'success',
        message: 'Survey submitted successfully.',
      });
    } catch {
      setSubmitState({
        type: 'error',
        message: 'Submission failed. Please try again.',
      });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Step {step} of {totalSteps}
          </Text>
          <Progress value={step} max={totalSteps} size="md" />
        </Stack>

        {submitState.type && (
          <Alert variant={submitState.type === 'success' ? 'success' : 'error'}>
            {submitState.message}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Tell us about yourself
            </Text>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              placeholder="Enter your name"
              error={nameError}
              onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
              aria-label="Name"
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              placeholder="you@example.com"
              error={emailError}
              onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
              aria-label="Email"
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Satisfaction Rating
            </Text>
            <RadioGroup
              label="How satisfied are you? (1-5)"
              value={satisfactionRating}
              onChange={(value) => {
                setSatisfactionRating(value);
                setTouched((prev) => ({ ...prev, satisfactionRating: true }));
              }}
              options={satisfactionOptions}
              error={ratingError}
              direction="vertical"
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Feature Interests
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select all that apply.
            </Text>
            <Stack gap={8}>
              {featureOptions.map((option) => (
                <Checkbox
                  key={option}
                  label={option}
                  checked={featureInterests.includes(option)}
                  onChange={(checked) => toggleFeature(option, checked)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Additional Comments
            </Text>
            <TextArea
              label="Comments (optional)"
              value={comments}
              onChange={setComments}
              placeholder="Share any additional feedback..."
              rows={6}
              maxLength={maxCommentLength}
              showCount
              helperText={`${comments.length}/${maxCommentLength} characters`}
              aria-label="Survey comments"
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold">
              Review Your Answers
            </Text>
            <Card
              padding={16}
              border
              radius="md"
              shadow="none"
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={8}>
                <Text variant="bodySmall">
                  <strong>Name:</strong> {name || '—'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Email:</strong> {email || '—'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfactionRating
                    ? satisfactionOptions.find((o) => o.value === satisfactionRating)?.label
                    : '—'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Feature Interests:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                </Text>
                <Text variant="bodySmall">
                  <strong>Comments:</strong> {comments.trim() || 'No comments'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={12}>
          <Button variant="ghost" onClick={handleBack} disabled={step === 1 || submitting}>
            Back
          </Button>

          {step < totalSteps ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!stepValid || submitting}
              aria-label="Next step"
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              loading={submitting}
              disabled={submitting}
              aria-label="Submit survey"
            >
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const DEFAULT_CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-success-600, #16a34a)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
  lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return elements;
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
    });
  }, [elements, normalizedQuery]);

  const selectedElement =
    elements.find((el) => (el.atomicNumber ?? -1) === selectedAtomicNumber) ?? null;

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => set.add((el.category ?? 'unknown').toLowerCase()));
    return Array.from(set).sort((a, b) => a.localeCompare(b));
  }, [elements]);

  return (
    <Card
      padding={16}
      shadow="sm"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          placeholder="Search by name or symbol"
          value={query}
          onChange={setQuery}
          type="search"
          aria-label="Search elements by name or symbol"
        />

        <Card
          padding={12}
          border
          radius="md"
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
            overflowX: 'auto',
          }}
        >
          <div
            role="grid"
            aria-label="Interactive periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(52px, 1fr))',
              gridAutoRows: '64px',
              gap: '6px',
              minWidth: '980px',
            }}
          >
            {filteredElements.map((el, idx) => {
              const categoryKey = (el.category ?? 'unknown').toLowerCase();
              const bg = DEFAULT_CATEGORY_COLORS[categoryKey] ?? DEFAULT_CATEGORY_COLORS.unknown;
              const isSelected = (el.atomicNumber ?? -1) === selectedAtomicNumber;

              return (
                <button
                  key={`${el.atomicNumber ?? idx}-${el.symbol ?? 'x'}`}
                  type="button"
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                  aria-label={`Element ${el.name ?? 'Unknown'} ${el.symbol ?? ''}`}
                  style={{
                    gridColumn: `${el.col ?? 1}`,
                    gridRow: `${el.row ?? 1}`,
                    position: 'relative',
                    border: isSelected
                      ? '2px solid var(--ggui-color-onSurface, #18181b)'
                      : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    background: bg,
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    cursor: 'pointer',
                    padding: '6px',
                    transition:
                      'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'var(--ggui-shape-shadow-sm)',
                    outline: 'none',
                  }}
                >
                  <Text
                    as="span"
                    variant="caption"
                    color="var(--ggui-color-onSurface, #18181b)"
                    style={{ position: 'absolute', top: 4, left: 6, opacity: 0.85 }}
                  >
                    {el.atomicNumber ?? '—'}
                  </Text>
                  <Text
                    as="span"
                    size="xl"
                    weight="bold"
                    align="center"
                    color="var(--ggui-color-onSurface, #18181b)"
                    style={{ display: 'block', lineHeight: '52px' }}
                  >
                    {el.symbol ?? '?'}
                  </Text>
                </button>
              );
            })}
          </div>
        </Card>

        <Card
          padding={12}
          border
          radius="md"
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Text>
            {selectedElement ? (
              <Stack gap={4}>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Name: <strong>{selectedElement.name ?? 'Unknown'}</strong>
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Symbol: <strong>{selectedElement.symbol ?? '—'}</strong>
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Atomic Number: <strong>{selectedElement.atomicNumber ?? '—'}</strong>
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Atomic Weight: <strong>{selectedElement.atomicWeight ?? '—'}</strong>
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Category: <strong>{selectedElement.category ?? 'unknown'}</strong>
                </Text>
              </Stack>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card
          padding={12}
          border
          radius="md"
          shadow="none"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(170px, 1fr))',
                gap: '8px',
              }}
            >
              {categories.map((category) => {
                const color = DEFAULT_CATEGORY_COLORS[category] ?? DEFAULT_CATEGORY_COLORS.unknown;
                return (
                  <div
                    key={category}
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: '8px',
                      border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      padding: '6px 8px',
                      background: 'var(--ggui-color-surface, #fafafa)',
                    }}
                  >
                    <span
                      aria-hidden="true"
                      style={{
                        width: 12,
                        height: 12,
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        background: color,
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      }}
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {category}
                    </Text>
                  </div>
                );
              })}
            </div>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

