import React, { useEffect, useMemo, useState } from 'react';
import {
  Alert,
  Badge,
  Box,
  Card,
  Container,
  Heading,
  Spinner,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = undefined,
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [connectionState, setConnectionState] = useState<'connecting' | 'live' | 'stale'>('connecting');
  const [isLoading, setIsLoading] = useState<boolean>(true);

  useEffect(() => {
    setLiveStocks(stocks);
    if (stocks.length > 0) {
      setIsLoading(false);
      setConnectionState((prev) => (prev === 'connecting' ? 'live' : prev));
    }
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    let staleTimeout: number | undefined;

    const refreshStaleTimer = () => {
      if (staleTimeout) window.clearTimeout(staleTimeout);
      staleTimeout = window.setTimeout(() => {
        setConnectionState('stale');
      }, 15000);
    };

    const handleAgentData = (event: Event) => {
      const custom = event as CustomEvent<{ stocks?: Props['stocks']; lastUpdated?: string }>;
      const detail = custom?.detail;
      if (!detail || typeof detail !== 'object') return;

      if (Array.isArray(detail.stocks)) {
        setLiveStocks(detail.stocks);
      }
      if (typeof detail.lastUpdated === 'string') {
        setLiveLastUpdated(detail.lastUpdated);
      }

      setConnectionState('live');
      setIsLoading(false);
      refreshStaleTimer();
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    refreshStaleTimer();

    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
      if (staleTimeout) window.clearTimeout(staleTimeout);
    };
  }, []);

  const statusBadgeVariant = useMemo(() => {
    if (connectionState === 'live') return 'success' as const;
    if (connectionState === 'stale') return 'warning' as const;
    return 'info' as const;
  }, [connectionState]);

  const formatSigned = (value: number) => `${value >= 0 ? '+' : ''}${value.toFixed(2)}`;
  const formatPrice = (value: number) => value.toFixed(2);

  return (
    <Box
      background="var(--ggui-color-surface, #fafafa)"
      style={{ minHeight: '100%' }}
      aria-label="Stock ticker dashboard"
    >
      <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Stack direction="horizontal" justify="between" align="center" wrap>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>

            <Stack
              direction="horizontal"
              gap="var(--ggui-spacing-4, 16px)"
              align="center"
              wrap
              aria-live="polite"
            >
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated:{' '}
                {liveLastUpdated
                  ? new Date(liveLastUpdated).toLocaleString()
                  : 'Not available'}
              </Text>

              <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                {(isLoading || connectionState === 'connecting') && (
                  <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
                )}
                <Badge variant={statusBadgeVariant} size="sm">
                  {connectionState === 'connecting'
                    ? 'Connecting'
                    : connectionState === 'live'
                    ? 'Live'
                    : 'Stale'}
                </Badge>
              </Stack>
            </Stack>
          </Stack>

          {isLoading && (
            <Alert variant="info" title="Connecting to live market feed">
              Waiting for stock stream updates...
            </Alert>
          )}

          {!isLoading && liveStocks.length === 0 && (
            <Alert variant="info" title="No stock data available">
              No stocks to display right now. Waiting for live updates.
            </Alert>
          )}

          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {liveStocks.map((stock, index) => {
              const price = typeof stock.price === 'number' ? stock.price : 0;
              const change = typeof stock.change === 'number' ? stock.change : 0;
              const changePercent =
                typeof stock.changePercent === 'number' ? stock.changePercent : 0;
              const isPositive =
                typeof stock.change === 'number'
                  ? stock.change >= 0
                  : changePercent >= 0;

              const accentColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';

              const arrow = isPositive ? '▲' : '▼';

              return (
                <Card
                  key={stock.symbol ?? String(index)}
                  padding={16}
                  shadow="sm"
                  border
                  radius="lg"
                  role="article"
                  aria-label={`${stock.symbol ?? '—'} ${
                    stock.name ?? 'Unknown Company'
                  } current price ${formatPrice(price)}`}
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: accentColor,
                    transition: 'border-color 200ms ease-in-out, color 200ms ease-in-out',
                    outline: 'none',
                  }}
                  tabIndex={0}
                  onFocus={(e) => {
                    (e.currentTarget as HTMLDivElement).style.outline =
                      '2px solid var(--ggui-color-primary-600, #0284c7)';
                    (e.currentTarget as HTMLDivElement).style.outlineOffset = '2px';
                  }}
                  onBlur={(e) => {
                    (e.currentTarget as HTMLDivElement).style.outline = 'none';
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {stock.symbol ?? '—'}
                    </Text>

                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {stock.name ?? 'Unknown Company'}
                    </Text>

                    <Text
                      variant="bodyLarge"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      ${formatPrice(price)}
                    </Text>

                    <Stack direction="horizontal" gap={8} align="center">
                      <Text variant="bodySmall" color={accentColor}>
                        {formatSigned(change)}
                      </Text>
                      <Text variant="bodySmall" color={accentColor}>
                        {arrow} {formatSigned(changePercent)}%
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </Box>
        </Stack>
      </Container>
      <style>
        {`
          @media (min-width: 1024px) {
            [aria-label="Stock ticker dashboard"] > div > div > div:last-child {
              grid-template-columns: repeat(3, minmax(0, 1fr));
            }
          }
        `}
      </style>
    </Box>
  );
}

export const __GGUI_META__ = {
  category: 'dashboard',
  description:
    'A real-time stock ticker dashboard with live stream updates, connection status, and responsive stock cards.',
};

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = ['😀', '🚀', '🎨', '🧠'],
  roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
  onComplete,
}: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(initialProfile.avatar ?? avatarOptions[0] ?? '');
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const emailError = email.length > 0 && !emailRegex.test(email) ? 'Please enter a valid email address.' : '';
  const nameError = name.trim().length === 0 ? 'Name is required.' : '';

  const step1Valid = name.trim().length > 0 && emailRegex.test(email);
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  const canNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);

  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const handleNext = () => {
    if (step < 3 && canNext) setStep((s) => s + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const handleComplete = () => {
    if (!step1Valid || !step2Valid) return;
    onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        border
      >
        <Stack gap={16}>
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Step {step} of 3
            </Text>
            <Progress value={progressValue} max={100} size="md" variant="default" />
          </Stack>

          <Stack
            gap={16}
            style={
              motionEnabled
                ? { animation: 'ggui-fadeIn 200ms ease-out' }
                : undefined
            }
          >
            {step === 1 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={name.trim().length === 0 ? '' : undefined}
                  helperText={nameError}
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={emailError || undefined}
                />

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Choose an avatar
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {avatarOptions.map((emoji) => (
                      <Button
                        key={emoji}
                        variant={avatar === emoji ? 'primary' : 'outline'}
                        size="md"
                        aria-label={`Select avatar ${emoji}`}
                        onClick={() => setAvatar(emoji)}
                      >
                        {emoji}
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  required
                  options={roleOptions.map((r) => ({ value: r, label: r }))}
                />

                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />

                <Toggle
                  label={`Theme preference: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>

                <Card
                  padding={16}
                  shadow="none"
                  border
                  radius="md"
                >
                  <Stack gap={8}>
                    <Text variant="body"><strong>Name:</strong> {name || '-'}</Text>
                    <Text variant="body"><strong>Email:</strong> {email || '-'}</Text>
                    <Text variant="body"><strong>Avatar:</strong> {avatar || '-'}</Text>
                    <Text variant="body"><strong>Role:</strong> {role || '-'}</Text>
                    <Text variant="body">
                      <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                    </Text>
                    <Text variant="body"><strong>Theme:</strong> {theme}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Stack>

          <Stack direction="horizontal" justify="between" gap={8}>
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>

            <Stack direction="horizontal" gap={8}>
              {step < 3 ? (
                <Button variant="primary" onClick={handleNext} disabled={!canNext}>
                  Next
                </Button>
              ) : (
                <>
                  <Button variant="outline" onClick={handleBack}>
                    Go Back
                  </Button>
                  <Button variant="primary" onClick={handleComplete} disabled={!step1Valid || !step2Valid}>
                    Complete Setup
                  </Button>
                </>
              )}
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </>
  );
}

