import React, { FormEvent, useMemo, useState } from 'react';
import {
  Alert,
  Badge,
  Box,
  Button,
  Card,
  Checkbox,
  Container,
  Divider,
  Heading,
  Input,
  Progress,
  RadioGroup,
  Stack,
  Text,
  TextArea,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  onSubmit?: (payload: {
    respondent: { name: string; email: string };
    satisfactionRating: string;
    selectedFeatures: string[];
    comments: string;
  }) => Promise<void> | void;
  title?: string;
  description?: string;
  stepTitles?: [string, string, string, string, string];
  nameLabel?: string;
  emailLabel?: string;
  commentsLabel?: string;
  commentsPlaceholder?: string;
  satisfactionQuestion?: string;
  featureQuestion?: string;
  nextLabel?: string;
  backLabel?: string;
  reviewLabel?: string;
  submitLabel?: string;
  submittingLabel?: string;
  successMessage?: string;
  errorMessage?: string;
  reviewSectionLabels?: {
    respondent?: string;
    satisfaction?: string;
    features?: string;
    comments?: string;
    noFeatures?: string;
    noComments?: string;
  };
  emailInvalidMessage?: string;
  requiredMessage?: string;
  maxComments?: number;
}

export default function GeneratedComponent({
  featureOptions,
  satisfactionLabels,
  onSubmit,
  title = 'Customer Survey',
  description = 'Please complete all steps before submitting your response.',
  stepTitles = ['Contact Info', 'Satisfaction', 'Feature Interests', 'Comments', 'Review'],
  nameLabel = 'Name',
  emailLabel = 'Email',
  commentsLabel = 'Additional Comments',
  commentsPlaceholder = 'Share any additional feedback...',
  satisfactionQuestion = 'How satisfied are you?',
  featureQuestion = 'Which features are you interested in?',
  nextLabel = 'Next',
  backLabel = 'Back',
  reviewLabel = 'Review',
  submitLabel = 'Submit Survey',
  submittingLabel = 'Submitting...',
  successMessage = 'Survey submitted successfully.',
  errorMessage = 'Something went wrong. Please try again.',
  reviewSectionLabels = {
    respondent: 'Respondent',
    satisfaction: 'Satisfaction',
    features: 'Feature Interests',
    comments: 'Comments',
    noFeatures: 'None selected',
    noComments: 'No comments provided',
  },
  emailInvalidMessage = 'Enter a valid email address.',
  requiredMessage = 'This field is required.',
  maxComments = 500,
}: Props) {
  const totalSteps = 5;
  const [currentStep, setCurrentStep] = useState(0);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [touched, setTouched] = useState({
    name: false,
    email: false,
    satisfactionRating: false,
    features: false,
    comments: false,
  });

  const [attemptedStep, setAttemptedStep] = useState<Record<number, boolean>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);
  const [submitError, setSubmitError] = useState('');

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const trimmedName = name.trim();
  const trimmedEmail = email.trim();

  const nameError =
    (touched.name || attemptedStep[0]) && !trimmedName ? requiredMessage : '';
  const emailError =
    (touched.email || attemptedStep[0]) && !trimmedEmail
      ? requiredMessage
      : (touched.email || attemptedStep[0]) && !emailRegex.test(trimmedEmail)
      ? emailInvalidMessage
      : '';

  const satisfactionError =
    (touched.satisfactionRating || attemptedStep[1]) && !satisfactionRating
      ? requiredMessage
      : '';

  const stepValid = useMemo(() => {
    if (currentStep === 0) return !!trimmedName && emailRegex.test(trimmedEmail);
    if (currentStep === 1) return !!satisfactionRating;
    return true;
  }, [currentStep, trimmedName, trimmedEmail, satisfactionRating]);

  const stepProgress = ((currentStep + 1) / totalSteps) * 100;

  const satisfactionOptions = satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  const resolvedSatisfaction =
    satisfactionLabels[Number(satisfactionRating) - 1] || satisfactionRating || '—';

  const markCurrentStepTouched = () => {
    if (currentStep === 0) {
      setTouched((prev) => ({ ...prev, name: true, email: true }));
    }
    if (currentStep === 1) {
      setTouched((prev) => ({ ...prev, satisfactionRating: true }));
    }
    setAttemptedStep((prev) => ({ ...prev, [currentStep]: true }));
  };

  const handleNext = () => {
    if (!stepValid) {
      markCurrentStepTouched();
      return;
    }
    setSubmitError('');
    setSubmitSuccess(false);
    setCurrentStep((prev) => Math.min(prev + 1, totalSteps - 1));
  };

  const handleBack = () => {
    setSubmitError('');
    setSubmitSuccess(false);
    setCurrentStep((prev) => Math.max(prev - 1, 0));
  };

  const toggleFeature = (option: string, checked: boolean) => {
    setSelectedFeatures((prev) =>
      checked ? [...prev, option] : prev.filter((item) => item !== option)
    );
  };

  const handleSubmit = async (e?: FormEvent) => {
    e?.preventDefault();
    if (currentStep !== 4 || isSubmitting) return;

    setIsSubmitting(true);
    setSubmitError('');
    setSubmitSuccess(false);

    const payload = {
      respondent: { name: trimmedName, email: trimmedEmail },
      satisfactionRating,
      selectedFeatures,
      comments,
    };

    try {
      await Promise.resolve(onSubmit?.(payload));
      setSubmitSuccess(true);
    } catch (err) {
      const thrown = err instanceof Error ? err.message : '';
      setSubmitError(thrown || errorMessage);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Container
      maxWidth="md"
      padding={24}
    >
      <Stack gap={24}>
        <Card
          padding={24}
          shadow="md"
          radius="lg"
          border
        >
          <form onSubmit={handleSubmit} aria-label={title}>
            <Stack gap={20}>
              <Stack gap={8}>
                <Stack direction="horizontal" justify="between" align="center" wrap>
                  <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                    {title}
                  </Heading>
                  <Badge variant="primary" size="sm" pill>
                    {`Step ${currentStep + 1} of ${totalSteps}`}
                  </Badge>
                </Stack>

                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {description}
                </Text>

                <Stack gap={8}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {`Step ${currentStep + 1} of ${totalSteps} · ${stepTitles[currentStep]}`}
                  </Text>
                  <Progress value={stepProgress} max={100} size="md" variant="default" />
                </Stack>
              </Stack>

              <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" />

              <Stack gap={16}>
                {currentStep === 0 && (
                  <Stack gap={16}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      {stepTitles[0]}
                    </Text>
                    <Input
                      size="md"
                      label={nameLabel}
                      value={name}
                      onChange={(value) => {
                        setName(value);
                        if (submitError) setSubmitError('');
                      }}
                      required
                      error={nameError || undefined}
                      onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
                    />
                    <Input
                      size="md"
                      label={emailLabel}
                      type="email"
                      value={email}
                      onChange={(value) => {
                        setEmail(value);
                        if (submitError) setSubmitError('');
                      }}
                      required
                      error={emailError || undefined}
                      onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
                    />
                  </Stack>
                )}

                {currentStep === 1 && (
                  <Stack gap={16}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      {stepTitles[1]}
                    </Text>
                    <RadioGroup
                      label={satisfactionQuestion}
                      value={satisfactionRating}
                      onChange={(value) => {
                        setSatisfactionRating(value);
                        if (submitError) setSubmitError('');
                      }}
                      direction="vertical"
                      options={satisfactionOptions}
                      error={satisfactionError || undefined}
                    />
                  </Stack>
                )}

                {currentStep === 2 && (
                  <Stack gap={12}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      {featureQuestion}
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {stepTitles[2]}
                    </Text>
                    <Stack gap={8}>
                      {featureOptions.map((option) => (
                        <Checkbox
                          key={option}
                          label={option}
                          checked={selectedFeatures.includes(option)}
                          onChange={(checked) => toggleFeature(option, checked)}
                        />
                      ))}
                    </Stack>
                  </Stack>
                )}

                {currentStep === 3 && (
                  <Stack gap={16}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      {stepTitles[3]}
                    </Text>
                    <TextArea
                      label={commentsLabel}
                      placeholder={commentsPlaceholder}
                      value={comments}
                      onChange={(value) => {
                        setComments(value);
                        if (submitError) setSubmitError('');
                      }}
                      rows={6}
                      maxLength={maxComments}
                      showCount
                      autoResize={false}
                      helperText={`${reviewLabel}: ${stepTitles[4]}`}
                    />
                  </Stack>
                )}

                {currentStep === 4 && (
                  <Stack gap={16}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      {stepTitles[4]}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {reviewLabel}
                    </Text>

                    <Box
                      padding={16}
                      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                    >
                      <Stack gap={8}>
                        <Text variant="label">{reviewSectionLabels.respondent || 'Respondent'}</Text>
                        <Text variant="body">{trimmedName || '—'}</Text>
                        <Text variant="body">{trimmedEmail || '—'}</Text>
                      </Stack>
                    </Box>

                    <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                    <Box
                      padding={16}
                      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                    >
                      <Stack gap={8}>
                        <Text variant="label">
                          {reviewSectionLabels.satisfaction || 'Satisfaction'}
                        </Text>
                        <Text variant="body">{resolvedSatisfaction}</Text>
                      </Stack>
                    </Box>

                    <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                    <Box
                      padding={16}
                      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                    >
                      <Stack gap={8}>
                        <Text variant="label">{reviewSectionLabels.features || 'Feature Interests'}</Text>
                        {selectedFeatures.length > 0 ? (
                          <Stack gap={4}>
                            {selectedFeatures.map((feature) => (
                              <Text key={feature} variant="body">
                                {feature}
                              </Text>
                            ))}
                          </Stack>
                        ) : (
                          <Text variant="body">
                            {reviewSectionLabels.noFeatures || 'None selected'}
                          </Text>
                        )}
                      </Stack>
                    </Box>

                    <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                    <Box
                      padding={16}
                      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                    >
                      <Stack gap={8}>
                        <Text variant="label">{reviewSectionLabels.comments || 'Comments'}</Text>
                        <Text variant="body">
                          {comments.trim() || reviewSectionLabels.noComments || 'No comments provided'}
                        </Text>
                      </Stack>
                    </Box>
                  </Stack>
                )}
              </Stack>

              <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" />

              <Stack direction="horizontal" justify="between" align="center" wrap>
                <Button
                  type="button"
                  variant="ghost"
                  size="md"
                  onClick={handleBack}
                  disabled={isSubmitting || currentStep === 0}
                >
                  {backLabel}
                </Button>

                <Stack direction="horizontal" gap={8}>
                  {currentStep < 4 ? (
                    <Button
                      type="button"
                      variant="primary"
                      size="md"
                      onClick={handleNext}
                      disabled={isSubmitting || !stepValid}
                    >
                      {nextLabel}
                    </Button>
                  ) : (
                    <Button
                      type="submit"
                      variant="primary"
                      size="md"
                      loading={isSubmitting}
                      disabled={isSubmitting}
                    >
                      {isSubmitting ? submittingLabel : submitLabel}
                    </Button>
                  )}
                </Stack>
              </Stack>

              {submitSuccess && (
                <Alert variant="success" title={successMessage}>
                  {successMessage}
                </Alert>
              )}

              {!!submitError && (
                <Alert variant="error" title={errorMessage}>
                  {submitError}
                </Alert>
              )}
            </Stack>
          </form>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(
    elements[0]?.atomicNumber
  );

  const categoryColorMap = useMemo<Record<string, string>>(
    () => ({
      'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
      'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
      'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
      metalloid: 'var(--ggui-color-success-500, #22c55e)',
      nonmetal: 'var(--ggui-color-success-600, #16a34a)',
      halogen: 'var(--ggui-color-warning-600, #d97706)',
      'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
      lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
      actinide: 'var(--ggui-color-error-600, #dc2626)',
      unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
    }),
    []
  );

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return elements;
    return elements.filter((el) => {
      const n = (el.name ?? '').toLowerCase();
      const s = (el.symbol ?? '').toLowerCase();
      return n.includes(normalizedQuery) || s.includes(normalizedQuery);
    });
  }, [elements, normalizedQuery]);

  const selectedElement = useMemo(
    () =>
      elements.find((el) => el.atomicNumber === selectedAtomicNumber) ??
      filteredElements[0],
    [elements, filteredElements, selectedAtomicNumber]
  );

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      set.add((el.category ?? 'unknown').toLowerCase());
    });
    return Array.from(set).sort();
  }, [elements]);

  return (
    <Card
      padding={16}
      shadow="sm"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Text
          variant="label"
          size="xl"
          weight="semibold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          type="search"
          value={query}
          onChange={setQuery}
          placeholder="Search by name or symbol"
          helperText="Filters table as you type"
          aria-label="Search elements by name or symbol"
        />

        <Card
          padding={12}
          border
          shadow="none"
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(48px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
            }}
          >
            {filteredElements.map((el) => {
              const categoryKey = (el.category ?? 'unknown').toLowerCase();
              const cellColor =
                categoryColorMap[categoryKey] ??
                'var(--ggui-color-neutral-400, #9ca3af)';
              const isSelected =
                selectedElement?.atomicNumber !== undefined &&
                selectedElement.atomicNumber === el.atomicNumber;

              return (
                <Button
                  key={`${el.atomicNumber ?? el.symbol ?? Math.random()}`}
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                  aria-label={`Select element ${el.name ?? 'Unknown'} (${el.symbol ?? '?'})`}
                  style={{
                    gridColumn: el.col ?? 'auto',
                    gridRow: el.row ?? 'auto',
                    minHeight: 64,
                    padding: 'var(--ggui-spacing-1, 4px)',
                    border: `1px solid ${
                      isSelected
                        ? 'var(--ggui-color-onSurface, #18181b)'
                        : 'var(--ggui-color-outline, #d4d4d8)'
                    }`,
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    background: 'var(--ggui-color-surface, #fafafa)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    position: 'relative',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    transition:
                      'transform 150ms ease, box-shadow 150ms ease, border-color 150ms ease',
                    boxShadow: isSelected
                      ? 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))'
                      : 'none',
                  }}
                >
                  <Text
                    as="span"
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    style={{
                      position: 'absolute',
                      top: 4,
                      left: 4,
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      lineHeight: 1,
                    }}
                  >
                    {el.atomicNumber ?? ''}
                  </Text>
                  <Text
                    as="span"
                    weight="bold"
                    size="lg"
                    style={{
                      textAlign: 'center',
                      color: cellColor,
                    }}
                  >
                    {el.symbol ?? '?'}
                  </Text>
                </Button>
              );
            })}
          </div>
        </Card>

        <Card
          padding={12}
          border
          shadow="none"
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Stack gap={6}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Element Details
            </Text>
            {selectedElement ? (
              <>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  Name: {selectedElement.name ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  Symbol: {selectedElement.symbol ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  Atomic Number: {selectedElement.atomicNumber ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  Atomic Weight: {selectedElement.atomicWeight ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                  Category: {selectedElement.category ?? 'unknown'}
                </Text>
              </>
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No element selected.
              </Text>
            )}
          </Stack>
        </Card>

        <Card
          padding={12}
          border
          shadow="none"
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" wrap gap={8}>
              {categories.map((cat) => {
                const swatchColor =
                  categoryColorMap[cat] ?? 'var(--ggui-color-neutral-400, #9ca3af)';
                return (
                  <Stack
                    key={cat}
                    direction="horizontal"
                    align="center"
                    gap={6}
                    style={{
                      padding: '4px 8px',
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                      background: 'var(--ggui-color-surface, #fafafa)',
                    }}
                  >
                    <span
                      aria-hidden="true"
                      style={{
                        width: 10,
                        height: 10,
                        borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                        background: swatchColor,
                        display: 'inline-block',
                      }}
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                      {cat}
                    </Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send Message — Called when user sends a message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount,
  messages = [],
  sendMessage = () => {},
}: Props) {
  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>([]);
  const listRef = useRef<HTMLDivElement>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  useEffect(() => {
    const el = listRef.current;
    if (el) el.scrollTop = el.scrollHeight;
  }, []);

  useEffect(() => {
    const el = listRef.current;
    if (el) el.scrollTop = el.scrollHeight;
  }, [allMessages]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const incoming = customEvent.detail;
      if (incoming && (incoming.text || incoming.sender || incoming.timestamp)) {
        setStreamMessages((prev) => [...prev, incoming]);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  const formatTimestamp = (timestamp?: string) => {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    if (Number.isNaN(date.getTime())) return timestamp;
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    sendMessage({ text, timestamp: new Date().toISOString() });
    setDraft('');
  };

  return (
    <Card
      padding={0}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        height: '100%',
      }}
    >
      <Stack gap={0} style={{ height: '100%' }}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Text
            variant="label"
            weight="semibold"
            color="var(--ggui-color-onSurface, #18181b)"
            as="div"
          >
            {title}
          </Text>
          {typeof participantCount === 'number' && (
            <Badge variant="primary" size="sm" aria-label="Participant count">
              {participantCount}
            </Badge>
          )}
        </Stack>

        <Stack
          gap={0}
          style={{
            flex: 1,
            minHeight: 0,
            overflow: 'hidden',
          }}
        >
          <Stack
            gap="var(--ggui-spacing-2, 8px)"
            style={{
              padding: 'var(--ggui-spacing-4, 16px)',
              overflowY: 'auto',
              flex: 1,
              minHeight: 0,
            }}
            ref={listRef}
            aria-label="Message list"
          >
            {allMessages.map((message, index) => {
              const sender = message.sender || 'Unknown';
              const isCurrentUser = sender === currentUser;
              const prevSender = index > 0 ? allMessages[index - 1]?.sender || 'Unknown' : null;
              const startsGroup = sender !== prevSender;

              return (
                <Stack
                  key={`${sender}-${message.timestamp || index}-${index}`}
                  align={isCurrentUser ? 'end' : 'start'}
                  gap={startsGroup ? 'var(--ggui-spacing-1, 4px)' : '2px'}
                >
                  {startsGroup && (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="div"
                    >
                      {sender}
                    </Text>
                  )}

                  <Card
                    padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                    radius="lg"
                    border={false}
                    shadow="none"
                    style={{
                      maxWidth: '80%',
                      background: isCurrentUser
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      color: isCurrentUser
                        ? 'var(--ggui-color-neutral-50, #f9fafb)'
                        : 'var(--ggui-color-onSurface, #18181b)',
                      transition: 'background-color 200ms ease-in-out',
                    }}
                  >
                    <Stack gap={4}>
                      <Text
                        variant="bodySmall"
                        color="inherit"
                        as="div"
                      >
                        {message.text || ''}
                      </Text>
                      <Text
                        variant="caption"
                        color={isCurrentUser ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                        align="right"
                        as="div"
                      >
                        {formatTimestamp(message.timestamp)}
                      </Text>
                    </Stack>
                  </Card>
                </Stack>
              );
            })}
          </Stack>
        </Stack>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-2, 8px)"
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Input
            label="Message"
            placeholder="Type a message..."
            value={draft}
            onChange={setDraft}
            aria-label="Compose message"
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleSend();
              }
            }}
          />
          <Button
            variant="primary"
            size="md"
            disabled={!draft.trim()}
            onClick={handleSend}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated,
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);

  useEffect(() => {
    setLiveStocks(stocks);
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    let timeoutId: ReturnType<typeof setTimeout> | undefined;
    timeoutId = setTimeout(() => setIsConnecting(false), 1200);

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const payload = customEvent.detail || {};

      if (Array.isArray(payload.stocks)) {
        setLiveStocks(payload.stocks);
      }
      if (typeof payload.lastUpdated === 'string') {
        setLiveLastUpdated(payload.lastUpdated);
      }
      setIsConnecting(false);
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => {
      if (timeoutId) clearTimeout(timeoutId);
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, []);

  const formattedTimestamp = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const d = new Date(liveLastUpdated);
    if (Number.isNaN(d.getTime())) return liveLastUpdated;
    return d.toLocaleString();
  }, [liveLastUpdated]);

  const showLoading = isConnecting && liveStocks.length === 0;

  return (
    <Stack
      gap="var(--ggui-spacing-4, 16px)"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      <Card
        border
        shadow="sm"
        radius="lg"
        padding="var(--ggui-spacing-4, 16px)"
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-2, 8px)">
          <Text as="div" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Text>
          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {isConnecting ? 'Connecting live feed…' : 'Live feed connected'}
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formattedTimestamp}
            </Text>
          </Stack>
        </Stack>
      </Card>

      {showLoading ? (
        <Card
          border
          padding="var(--ggui-spacing-6, 24px)"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Loading stock data…
          </Text>
        </Card>
      ) : (
        <Stack
          gap="var(--ggui-spacing-4, 16px)"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
          }}
          aria-label="Stock ticker cards"
        >
          {liveStocks.map((stock, index) => {
            const symbol = stock.symbol ?? '—';
            const name = stock.name ?? 'Unknown Company';
            const price = stock.price ?? 0;
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;

            const isPositive = change >= 0;
            const trendColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const arrow = isPositive ? '▲' : '▼';

            return (
              <Card
                key={`${symbol}-${index}`}
                border
                shadow="sm"
                radius="lg"
                padding="var(--ggui-spacing-4, 16px)"
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: trendColor,
                  transition: 'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                }}
                aria-label={`${symbol} stock card`}
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text as="div" size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {symbol}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                    {name}
                  </Text>
                  <Text as="div" size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    ${price.toFixed(2)}
                  </Text>
                  <Text variant="bodySmall" color={trendColor}>
                    {change >= 0 ? '+' : ''}
                    {change.toFixed(2)}
                  </Text>
                  <Text variant="label" color={trendColor}>
                    {arrow} {changePercent >= 0 ? '+' : ''}
                    {changePercent.toFixed(2)}%
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </Stack>
      )}
    </Stack>
  );
}

import React, { useMemo, useState } from 'react';
import {
