  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent({
  initialProfile = {
    name: '',
    email: '',
    avatar: '',
    role: '',
    emailNotifications: true,
    theme: 'light',
  },
  avatarOptions = ['😀', '😎', '🚀', '🧠'],
  roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
  complete,
}: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(initialProfile.avatar ?? avatarOptions[0] ?? '');
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({ name: false, email: false });

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameValid = name.trim().length > 0;
  const step1Valid = nameValid && emailValid;
  const step2Valid = role.trim().length > 0;

  const nameError = touched.name && !nameValid ? 'Name is required' : undefined;
  const emailError = touched.email && !emailValid ? 'Please enter a valid email address' : undefined;

  const canNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);

  const goNext = () => {
    if (step === 1) {
      setTouched({ name: true, email: true });
      if (!step1Valid) return;
    }
    if (step === 2 && !step2Valid) return;
    setStep((s) => Math.min(3, s + 1));
  };

  const goBack = () => setStep((s) => Math.max(1, s - 1));

  const onComplete = () => {
    const payload = { name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme };
    if (complete) complete(payload);
  };

  const transitionStyle = motionEnabled
    ? { animation: 'ggui-slideInUp 200ms ease-out' }
    : undefined;

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        border
      >
        <Stack gap={20}>
          <Stack gap={6}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Onboarding Wizard
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {step} of 3
            </Text>
            <Progress value={step} max={3} size="md" />
          </Stack>

          <Card
            padding={16}
            shadow="none"
            border
            radius="md"
          >
            <Stack gap={16} style={transitionStyle}>
              {step === 1 && (
                <Stack gap={14}>
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    Profile Setup
                  </Text>

                  <Input
                    label="Name"
                    value={name}
                    onChange={(v) => {
                      setTouched((t) => ({ ...t, name: true }));
                      setName(v);
                    }}
                    required
                    error={nameError}
                    placeholder="Enter your full name"
                    aria-label="Name"
                  />

                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={(v) => {
                      setTouched((t) => ({ ...t, email: true }));
                      setEmail(v);
                    }}
                    required
                    error={emailError}
                    placeholder="name@example.com"
                    aria-label="Email"
                  />

                  <Stack gap={8}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      Select Avatar
                    </Text>
                    <Stack direction="horizontal" wrap gap={8}>
                      {avatarOptions.map((option) => {
                        const selected = option === avatar;
                        return (
                          <Button
                            key={option}
                            variant={selected ? 'primary' : 'outline'}
                            size="sm"
                            onClick={() => setAvatar(option)}
                            aria-label={`Select avatar ${option}`}
                          >
                            {option}
                          </Button>
                        );
                      })}
                    </Stack>
                  </Stack>
                </Stack>
              )}

              {step === 2 && (
                <Stack gap={14}>
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    Preferences
                  </Text>

                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    placeholder="Select your role"
                    required
                    options={roleOptions.map((r) => ({ value: r, label: r }))}
                  />

                  <Toggle
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                    size="md"
                  />

                  <RadioGroup
                    label="Theme preference"
                    value={theme}
                    onChange={setTheme}
                    direction="horizontal"
                    options={[
                      { value: 'light', label: 'Light' },
                      { value: 'dark', label: 'Dark' },
                    ]}
                  />
                </Stack>
              )}

              {step === 3 && (
                <Stack gap={12}>
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    Review & Confirm
                  </Text>
                  <Card padding={12} shadow="none" border radius="md">
                    <Stack gap={8}>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                        <strong>Name:</strong> {name || '—'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                        <strong>Email:</strong> {email || '—'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                        <strong>Avatar:</strong> {avatar || '—'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                        <strong>Role:</strong> {role || '—'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                        <strong>Email notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                        <strong>Theme:</strong> {theme}
                      </Text>
                    </Stack>
                  </Card>
                </Stack>
              )}
            </Stack>
          </Card>

          <Stack direction="horizontal" justify="between" align="center">
            <Button
              variant="ghost"
              size="md"
              onClick={goBack}
              disabled={step === 1}
              aria-label="Go back"
            >
              Back
            </Button>

            {step < 3 ? (
              <Button
                variant="primary"
                size="md"
                onClick={goNext}
                disabled={!canNext}
                aria-label="Go to next step"
              >
                Next
              </Button>
            ) : (
              <Stack direction="horizontal" gap={8}>
                <Button variant="outline" size="md" onClick={goBack} aria-label="Edit previous steps">
                  Go Back
                </Button>
                <Button variant="primary" size="md" onClick={onComplete} aria-label="Complete setup">
                  Complete Setup
                </Button>
              </Stack>
            )}
          </Stack>
        </Stack>
      </Card>
      {`__GGUI_META__{"category":"Form","description":"A 3-step onboarding wizard with profile setup, preferences, validation, progress indicator, and final review/complete action."}`}
    </>
  );
}

