import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit Survey callback */
  onSubmit?: (payload: {
    name: string;
    email: string;
    satisfaction: { value: string; label: string };
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;

  /** Optional UI copy defaults */
  title?: string;
  stepTitles?: string[];
  nameLabel?: string;
  emailLabel?: string;
  commentsLabel?: string;
  commentsPlaceholder?: string;
  nextLabel?: string;
  backLabel?: string;
  reviewTitle?: string;
  submitLabel?: string;
}

export default function GeneratedComponent({
  featureOptions = ['Analytics', 'Automations', 'Integrations'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit,
  title = 'Multi-Step Survey',
  stepTitles = ['Basic Info', 'Satisfaction', 'Feature Interests', 'Comments', 'Review'],
  nameLabel = 'Name',
  emailLabel = 'Email',
  commentsLabel = 'Additional Comments',
  commentsPlaceholder = 'Share anything else you would like us to know...',
  nextLabel = 'Next',
  backLabel = 'Back',
  reviewTitle = 'Review Your Responses',
  submitLabel = 'Submit Survey',
}: Props) {
  const totalSteps = 5;
  const [step, setStep] = useState(1);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [touched, setTouched] = useState({ name: false, email: false });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(null);

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required.'
      : touched.email && !emailValid
      ? 'Please enter a valid email address.'
      : '';

  const stepValid = useMemo(() => {
    if (step === 1) return Boolean(name.trim()) && Boolean(email.trim()) && emailValid;
    if (step === 2) return Boolean(satisfaction);
    return true;
  }, [step, name, email, emailValid, satisfaction]);

  const satisfactionOptions = satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  const progressValue = (step / totalSteps) * 100;

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? (prev.includes(feature) ? prev : [...prev, feature]) : prev.filter((f) => f !== feature),
    );
  };

  const goNext = () => {
    if (step === 1) {
      setTouched({ name: true, email: true });
      if (!stepValid) return;
    }
    if (step === 2 && !stepValid) return;
    setStep((s) => Math.min(totalSteps, s + 1));
  };

  const goBack = () => {
    setFeedback(null);
    setStep((s) => Math.max(1, s - 1));
  };

  const handleSubmit = async () => {
    if (!onSubmit) return;
    setIsSubmitting(true);
    setFeedback(null);

    const selectedIndex = Number(satisfaction) - 1;
    const payload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: {
        value: satisfaction,
        label: satisfactionLabels[selectedIndex] ?? '',
      },
      featureInterests,
      comments: comments.trim(),
    };

    try {
      await onSubmit(payload);
      setFeedback({ type: 'success', message: 'Survey submitted successfully.' });
    } catch (e) {
      setFeedback({ type: 'error', message: 'Submission failed. Please try again.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        animation: 'ggui-fadeIn 200ms ease-out',
      } as React.CSSProperties}
    >
      <Stack gap={16}>
        <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          {title}
        </Text>

        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {step} of {totalSteps}
          </Text>
          <Progress value={progressValue} max={100} size="md" variant="default" />
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {stepTitles[step - 1] ?? `Step ${step}`}
          </Text>
        </Stack>

        {feedback ? (
          <Alert variant={feedback.type === 'success' ? 'success' : 'error'} title={feedback.type === 'success' ? 'Success' : 'Error'}>
            {feedback.message}
          </Alert>
        ) : null}

        {step === 1 && (
          <Stack gap={12}>
            <Input
              label={nameLabel}
              value={name}
              onChange={(v) => {
                setName(v);
                if (!touched.name) setTouched((t) => ({ ...t, name: true }));
              }}
              required
              error={nameError}
              placeholder="Enter your name"
              aria-label={nameLabel}
            />
            <Input
              label={emailLabel}
              type="email"
              value={email}
              onChange={(v) => {
                setEmail(v);
                if (!touched.email) setTouched((t) => ({ ...t, email: true }));
              }}
              required
              error={emailError}
              placeholder="Enter your email"
              aria-label={emailLabel}
            />
          </Stack>
        )}

        {step === 2 && (
          <RadioGroup
            label="How satisfied are you?"
            value={satisfaction}
            onChange={setSatisfaction}
            options={satisfactionOptions}
            error={!satisfaction ? 'Please select a rating.' : ''}
          />
        )}

        {step === 3 && (
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Which features interest you?
            </Text>
            {featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={featureInterests.includes(feature)}
                onChange={(checked) => toggleFeature(feature, checked)}
              />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <TextArea
            label={commentsLabel}
            value={comments}
            onChange={setComments}
            placeholder={commentsPlaceholder}
            maxLength={500}
            showCount
            helperText="Optional"
            aria-label={commentsLabel}
          />
        )}

        {step === 5 && (
          <Stack gap={10}>
            <Text variant="bodyLarge" weight="semibold">
              {reviewTitle}
            </Text>
            <Text>
              <Text as="span" weight="medium">Name: </Text>
              <Text as="span">{name || '-'}</Text>
            </Text>
            <Text>
              <Text as="span" weight="medium">Email: </Text>
              <Text as="span">{email || '-'}</Text>
            </Text>
            <Text>
              <Text as="span" weight="medium">Satisfaction: </Text>
              <Text as="span">{satisfactionLabels[Number(satisfaction) - 1] || '-'}</Text>
            </Text>
            <Text>
              <Text as="span" weight="medium">Feature Interests: </Text>
              <Text as="span">{featureInterests.length ? featureInterests.join(', ') : '-'}</Text>
            </Text>
            <Text>
              <Text as="span" weight="medium">Comments: </Text>
              <Text as="span">{comments || '-'}</Text>
            </Text>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" align="center" gap={12}>
          <Button variant="ghost" onClick={goBack} disabled={step === 1 || isSubmitting}>
            {backLabel}
          </Button>

          {step < totalSteps ? (
            <Button variant="primary" onClick={goNext} disabled={!stepValid || isSubmitting}>
              {nextLabel}
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit} loading={isSubmitting} disabled={isSubmitting || !onSubmit}>
              {submitLabel}
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  lanthanide: 'var(--ggui-color-warning-600, #d97706)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-primary-300, #7dd3fc)',
  metalloid: 'var(--ggui-color-info-500, #06b6d4)',
  'polyatomic nonmetal': 'var(--ggui-color-success-500, #22c55e)',
  'diatomic nonmetal': 'var(--ggui-color-success-600, #16a34a)',
  halogen: 'var(--ggui-color-primary-600, #0284c7)',
  'noble gas': 'var(--ggui-color-primary-700, #0369a1)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

const getCategoryColor = (category?: string): string => {
  if (!category) return categoryColorMap.unknown;
  return categoryColorMap[category.toLowerCase()] ?? 'var(--ggui-color-neutral-400, #9ca3af)';
};

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return elements;
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
    });
  }, [elements, normalizedQuery]);

  const selectedElement =
    elements.find((el) => el.atomicNumber === selectedAtomicNumber) ?? null;

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      if (el.category) set.add(el.category);
    });
    return Array.from(set).sort((a, b) => a.localeCompare(b));
  }, [elements]);

  return (
    <Card
      padding={16}
      shadow="sm"
      border
      radius="lg"
    >
      <Stack gap={16}>
        <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          type="search"
          value={query}
          onChange={setQuery}
          placeholder="Search by name or symbol"
          aria-label="Search elements by name or symbol"
        />

        <div
          role="grid"
          aria-label="Periodic table grid"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            background: 'var(--ggui-color-surface, #fafafa)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
            padding: 'var(--ggui-spacing-2, 8px)',
