import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract callback: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
  /** Interaction: Converse */
  onSubmit?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount,
  messages = [],
  sendMessage,
  onSubmit,
}: Props) {
  const [draft, setDraft] = useState<string>('');
  const [streamMessages, setStreamMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);
  const listRef = useRef<HTMLDivElement>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      items: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });

    return groups;
  }, [allMessages]);

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages.length]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const payload = customEvent.detail;
      if (!payload || (typeof payload !== 'object')) return;

      setStreamMessages((prev) => [
        ...prev,
        {
          sender: payload.sender ?? 'Agent',
          text: payload.text ?? '',
          timestamp: payload.timestamp ?? new Date().toISOString(),
        },
      ]);
    };

    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  const formatTimestamp = (iso?: string) => {
    if (!iso) return '';
    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;

    const payload = {
      text,
      timestamp: new Date().toISOString(),
    };

    if (sendMessage) sendMessage(payload);
    if (onSubmit) onSubmit(payload);
    setDraft('');
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card
      padding="var(--ggui-spacing-4, 16px)"
      border
      radius="lg"
      shadow="sm"
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" justify="between" align="center">
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            as="div"
          >
            {title}
          </Text>
          {typeof participantCount === 'number' && (
            <Badge variant="primary" size="sm" aria-label="Participant count">
              {participantCount}
            </Badge>
          )}
        </Stack>

        <Card
          padding="var(--ggui-spacing-2, 8px)"
          border
          radius="md"
          shadow="none"
        >
          <div
            ref={listRef}
            role="log"
            aria-live="polite"
            aria-label="Chat messages"
            style={{
              maxHeight: 'var(--ggui-spacing-12, 48px)',
              minHeight: '280px',
              overflowY: 'auto',
              background: 'var(--ggui-color-surface, #fafafa)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-2, 8px)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            }}
          >
            <Stack gap="var(--ggui-spacing-2, 8px)">
              {groupedMessages.map((group, groupIndex) => {
                const isOwn = (group.sender ?? '') === currentUser;
                return (
                  <Stack
                    key={`${group.sender ?? 'unknown'}-${groupIndex}`}
                    align={isOwn ? 'end' : 'start'}
                    gap="var(--ggui-spacing-1, 4px)"
                  >
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="div"
                    >
                      {group.sender ?? 'Unknown'}
                    </Text>

                    {group.items.map((message, messageIndex) => (
                      <Card
                        key={`${group.sender ?? 'unknown'}-${message.timestamp ?? messageIndex}-${messageIndex}`}
                        padding="var(--ggui-spacing-2, 8px)"
                        border={false}
                        radius="md"
                        shadow="none"
                      >
                        <div
                          style={{
                            background: isOwn
                              ? 'var(--ggui-color-primary-600, #0284c7)'
                              : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                            color: isOwn
                              ? 'var(--ggui-color-surface, #fafafa)'
                              : 'var(--ggui-color-onSurface, #18181b)',
                            borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                            padding: 'var(--ggui-spacing-2, 8px)',
                            maxWidth: '75%',
                            transition: 'background-color 200ms ease-in-out, color 200ms ease-in-out',
                          }}
                        >
                          <Stack gap="var(--ggui-spacing-1, 4px)">
                            <Text
                              variant="bodySmall"
                              color="inherit"
                              as="div"
                            >
                              {message.text ?? ''}
                            </Text>
                            <Text
                              variant="caption"
                              color="inherit"
                              as="div"
                              align="right"
                            >
                              {formatTimestamp(message.timestamp)}
                            </Text>
                          </Stack>
                        </div>
                      </Card>
                    ))}
                  </Stack>
                );
              })}
            </Stack>
          </div>
        </Card>

        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="end">
          <div style={{ flex: 1 }}>
            <Input
              label="Type a message"
              value={draft}
              onChange={setDraft}
              placeholder="Write a message..."
              aria-label="Message input"
              onKeyDown={handleKeyDown}
            />
          </div>
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const {
    stocks = [
      { symbol: 'AAPL', name: 'Apple Inc.', price: 189.45, change: 1.21, changePercent: 0.64 },
      { symbol: 'MSFT', name: 'Microsoft Corp.', price: 421.38, change: -2.56, changePercent: -0.60 },
      { symbol: 'NVDA', name: 'NVIDIA Corp.', price: 973.32, change: 8.44, changePercent: 0.87 },
    ],
    lastUpdated = '',
  } = props;

  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(stocks.length === 0);

  useEffect(() => {
    setLiveStocks(stocks);
    setLiveLastUpdated(lastUpdated);
    setIsLoading(stocks.length === 0);
  }, [stocks, lastUpdated]);

  useEffect(() => {
    const timer = window.setTimeout(() => {
      setIsConnecting(false);
    }, 1200);

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const detail = customEvent.detail || {};

      if (Array.isArray(detail.stocks)) {
        setLiveStocks(detail.stocks);
        setIsLoading(detail.stocks.length === 0);
      }
      if (typeof detail.lastUpdated === 'string') {
        setLiveLastUpdated(detail.lastUpdated);
      } else {
        setLiveLastUpdated(new Date().toISOString());
      }
      setIsConnecting(false);
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => {
      window.clearTimeout(timer);
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, []);

  const formattedUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Stack
      gap="var(--ggui-spacing-6, 24px)"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-6, 24px)',
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="center"
        wrap
        gap="var(--ggui-spacing-2, 8px)"
      >
        <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
          Market Watch
        </Text>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          Last Updated: {formattedUpdated}
        </Text>
      </Stack>

      {isConnecting && (
        <Card
          padding="var(--ggui-spacing-4, 16px)"
          border
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
            <Spinner size={18} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Connecting to live market feed…
            </Text>
          </Stack>
        </Card>
      )}

      {isLoading ? (
        <Card
          padding="var(--ggui-spacing-6, 24px)"
          border
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack align="center" gap="var(--ggui-spacing-2, 8px)">
            <Spinner size={24} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Loading stock prices…
            </Text>
          </Stack>
        </Card>
      ) : (
        <div
          role="list"
          aria-label="Stock ticker cards"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          {liveStocks.map((stock, index) => {
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;
            const isPositive = change >= 0;
            const trendColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const arrow = isPositive ? '▲' : '▼';

            return (
              <Card
                key={`${stock.symbol ?? 'stock'}-${index}`}
                padding="var(--ggui-spacing-4, 16px)"
                radius="lg"
                shadow="sm"
                border
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: trendColor,
                  transition:
                    'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                }}
                role="listitem"
                aria-label={`${stock.symbol ?? 'Unknown'} stock card`}
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {stock.symbol ?? '—'}
                  </Text>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    truncate
                  >
                    {stock.name ?? 'Unknown Company'}
                  </Text>
                  <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    {(stock.price ?? 0).toFixed(2)}
                  </Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                    <Text variant="label" color={trendColor}>
                      {change >= 0 ? '+' : ''}
                      {change.toFixed(2)}
                    </Text>
                    <Text variant="label" color={trendColor}>
                      {arrow} {changePercent >= 0 ? '+' : ''}
                      {changePercent.toFixed(2)}%
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>
      )}
    </Stack>
  );
}

export const __GGUI_META__ = {
  category: 'dashboard',
  description:
    'Stock ticker dashboard with market header, live-updating responsive stock cards, trend color coding, and agent stream connection/loading states.',
};

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);

  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions?.[0] ?? ''
  );

  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const emailRegex = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/, []);
  const emailValid = emailRegex.test(email.trim());
  const nameValid = name.trim().length > 0;

  const step1Valid = nameValid && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');

  const canNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);
  const progressValue = (step / 3) * 100;

  const handleNext = () => {
    if (!canNext) return;
    setStep((s) => Math.min(3, s + 1));
  };

  const handleBack = () => {
    setStep((s) => Math.max(1, s - 1));
  };

  const handleComplete = () => {
    if (!step1Valid || !step2Valid) return;
    props.onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <Card
      padding={24}
      shadow="md"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <MotionKeyframes />
      <Stack gap={20}>
        <Stack gap={8}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            aria-live="polite"
          >
            Step {step} of 3
          </Text>
          <Progress value={progressValue} max={100} size="md" />
        </Stack>

        <Stack
          gap={16}
          style={{
            animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
          }}
          key={step}
        >
          {step === 1 && (
            <Stack gap={16}>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                Profile Setup
              </Text>

              <Input
                label="Name"
                value={name}
                onChange={setName}
                required
                placeholder="Enter your name"
                error={!nameValid && name.length > 0 ? 'Name is required' : undefined}
              />

              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                required
                placeholder="you@example.com"
                error={email.length > 0 && !emailValid ? 'Please enter a valid email address' : undefined}
              />

              <Stack gap={8}>
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Choose an avatar
                </Text>
                <Stack direction="horizontal" gap={8} wrap>
                  {props.avatarOptions.map((option) => {
                    const selected = avatar === option;
                    return (
                      <Button
                        key={option}
                        variant={selected ? 'primary' : 'outline'}
                        size="md"
                        aria-label={`Select avatar ${option}`}
                        onClick={() => setAvatar(option)}
                      >
                        {option}
                      </Button>
                    );
                  })}
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                Preferences
              </Text>

              <Select
                label="Role"
                value={role}
                onChange={setRole}
                placeholder="Select your role"
                required
                options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                error={!step2Valid && role.trim().length === 0 ? 'Role is required' : undefined}
              />

              <Toggle
                label="Email notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
                size="md"
              />

              <Toggle
                label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                checked={theme === 'dark'}
                onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                size="md"
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={12}>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                Review & Confirm
              </Text>

              <Card
                padding={16}
                border
                shadow="none"
                radius="md"
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                }}
              >
                <Stack gap={8}>
                  <Text variant="body"><strong>Name:</strong> {name || '-'}</Text>
                  <Text variant="body"><strong>Email:</strong> {email || '-'}</Text>
                  <Text variant="body"><strong>Avatar:</strong> {avatar || '-'}</Text>
                  <Text variant="body"><strong>Role:</strong> {role || '-'}</Text>
                  <Text variant="body">
                    <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                  </Text>
                  <Text variant="body"><strong>Theme:</strong> {theme}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </Stack>

        <Stack direction="horizontal" justify="between" align="center">
          <Button
            variant="ghost"
            size="md"
            onClick={handleBack}
            disabled={step === 1}
            aria-label="Go back to previous step"
          >
            Go Back
          </Button>

          {step < 3 ? (
            <Button
              variant="primary"
              size="md"
              onClick={handleNext}
              disabled={!canNext}
              aria-label="Proceed to next step"
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              size="md"
              onClick={handleComplete}
              disabled={!step1Valid || !step2Valid}
              aria-label="Complete setup"
            >
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard displays current weather details and a multi-day forecast.
 * It uses GGUI primitives and semantic tokens for consistent theme integration.
 * No hardcoded values are used for layout logic; all data is prop-driven.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 24, low: 16 },
    { day: 'Tue', icon: '⛅', high: 22, low: 15 },
    { day: 'Wed', icon: '☁️', high: 20, low: 14 },
    { day: 'Thu', icon: '🌧️', high: 18, low: 13 },
    { day: 'Fri', icon: '☀️', high: 23, low: 15 },
  ],
}: Props) {
  // Simple emoji mapping if an icon is not explicitly provided
  const getIcon = (conditionStr: string = '') => {
    const c = conditionStr.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud') || c.includes('overcast')) return '☁️';
    if (c.includes('rain') || c.includes('shower') || c.includes('drizzle')) return '🌧️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('snow') || c.includes('ice')) return '❄️';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '🌡️';
  };

  const displayUnit = `°${unit}`;

  return (
    <Card 
      padding={24} 
      shadow="md" 
      radius="xl" 
      border={true}
    >
      <Stack gap={24}>
        {/* Current Weather Overview */}
        <Stack direction="horizontal" justify="between" align="center">
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {getIcon(condition)} {condition}
            </Text>
          </Stack>

          <Stack direction="horizontal" align="start" gap={2}>
            <Text 
              size="4xl" 
              weight="bold" 
              color="var(--ggui-color-primary-600, #0284c7)"
            >
              {Math.round(temperature)}
            </Text>
            <Box margin="4px 0 0 0">
              <Text weight="semibold" size="xl" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {displayUnit}
              </Text>
            </Box>
          </Stack>
        </Stack>

        {/* Core Weather Metrics */}
        <Stack direction="horizontal" gap={32}>
          <Stack gap={2}>
            <Text 
              variant="caption" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)" 
              weight="medium"
            >
              HUMIDITY
            </Text>
            <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {humidity}%
            </Text>
          </Stack>
          <Stack gap={2}>
            <Text 
              variant="caption" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)" 
              weight="medium"
            >
              WIND
            </Text>
            <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" wrap={true} gap={16}>
          {forecast.map((item, index) => (
            <Box 
              key={`${item.day || 'day'}-${index}`} 
              paddingX={8}
              paddingY={4}
              style={{ flex: '1 1 0', textAlign: 'center', minWidth: '60px' }}
            >
              <Stack align="center" gap={8}>
                <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day}
                </Text>
                <Text size="xl" aria-hidden="true">
                  {item.icon || getIcon(condition)}
                </Text>
                <Stack gap={2} align="center">
                  <Text weight="bold" size="sm" color="var(--ggui-color-onSurface, #18181b)">
                    {item.high}{displayUnit}
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.low}{displayUnit}
                  </Text>
                </Stack>
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Card, Stack, Text, Heading, Button, Input, TextArea, RadioGroup, Checkbox, Progress, Divider, Box, Container
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: any) => void;
}

export default function SurveyForm({ featureOptions = [], satisfactionLabels = [], onSubmit }: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({ name: '', email: '', satisfaction: '', features: [] as string[], comments: '' });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);

  const radioOptions = useMemo(() => satisfactionLabels.map((l, i) => ({ value: String(i + 1), label: l })), [satisfactionLabels]);

  const handleSubmit = async () => {
    setIsSubmitting(true);
    await new Promise(r => setTimeout(r, 800));
    if (onSubmit) onSubmit(formData);
    setIsSubmitting(false);
    setIsSubmitted(true);
  };

  const isStep1Valid = formData.name.length > 0 && formData.email.includes('@');

  if (isSubmitted) {
    return (
      <Container maxWidth="sm">
        <Card padding={32} border radius="xl" shadow="md">
          <Stack align="center" gap={16}>
            <Heading level={2}>Success</Heading>
            <Text align="center">Your feedback has been submitted successfully.</Text>
            <Button variant="primary" onClick={() => setIsSubmitted(false)}>Start Over</Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="sm" padding={16}>
      <Card padding={32} border radius="xl" shadow="lg">
        <Stack gap={32}>
          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="end">
              <Heading level={2}>Survey</Heading>
              <Text weight="bold" color="var(--ggui-color-primary-600)">Step {step > 4 ? 4 : step} of 4</Text>
            </Stack>
            <Progress value={step > 4 ? 4 : step} max={4} />
          </Stack>

          <Box style={{ minHeight: '360px' }}>
            {step === 1 && (
              <Stack gap={24}>
                <Stack gap={4}>
                  <Text as="label" {...({ htmlFor: 'name' } as any)}>Full Name</Text>
                  <Input label="Name" id="name" value={formData.name} onChange={(v: string) => setFormData(p => ({ ...p, name: v }))} required />
                </Stack>
                <Stack gap={4}>
                  <Text as="label" {...({ htmlFor: 'email' } as any)}>Email Address</Text>
                  <Input label="Email" id="email" type="email" value={formData.email} onChange={(v: string) => setFormData(p => ({ ...p, email: v }))} required />
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <RadioGroup label="Satisfaction Rating" value={formData.satisfaction} onChange={(v: string) => setFormData(p => ({ ...p, satisfaction: v }))} options={radioOptions} />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text weight="medium">Select interested features:</Text>
                {featureOptions.map(opt => (
                  <Checkbox key={opt} label={opt} checked={formData.features.includes(opt)} onChange={(c: boolean) => setFormData(p => ({ ...p, features: c ? [...p.features, opt] : p.features.filter(f => f !== opt) }))} />
                ))}
              </Stack>
            )}

            {step === 4 && (
              <TextArea label="Additional Feedback" value={formData.comments} onChange={(v: string) => setFormData(p => ({ ...p, comments: v }))} maxLength={500} showCount />
            )}

            {step === 5 && (
              <Stack gap={16}>
                <Heading level={4}>Review</Heading>
                <Divider />
                <Text variant="bodySmall"><strong>Name:</strong> {formData.name}</Text>
                <Text variant="bodySmall"><strong>Email:</strong> {formData.email}</Text>
                <Text variant="bodySmall"><strong>Satisfaction:</strong> {formData.satisfaction}</Text>
                <Text variant="bodySmall"><strong>Features:</strong> {formData.features.join(', ')}</Text>
              </Stack>
            )}
          </Box>

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={() => setStep(s => s - 1)} disabled={step === 1}>Back</Button>
            {step < 5 ? (
              <Button variant="primary" onClick={() => setStep(s => s + 1)} disabled={step === 1 && !isStep1Valid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>Submit Survey</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Stack,
  Box,
  Text,
  Heading,
  Card,
  Container,
  Divider,
  Badge
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<ElementData>;
}

/**
 * Maps standard periodic table categories to design system color tokens.
 */
const getCategoryColor = (category?: string): string => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('noble gas')) return 'var(--ggui-color-info-500, #06b6d4)';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-600, #dc2626)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-500, #f59e0b)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-neutral-400, #9ca3af)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-neutral-500, #6b7280)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-success-600, #16a34a)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-success-400, #4ade80)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-300, #7dd3fc)';
  if (cat.includes('actinide')) return 'var(--ggui-color-primary-500, #0ea5e9)';
  return 'var(--ggui-color-neutral-300, #d1d5db)';
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSymbol, setSelectedSymbol] = useState<string | null>(null);

  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lowerSearch = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(lowerSearch) ||
        el.symbol?.toLowerCase().includes(lowerSearch)
    );
  }, [elements, searchTerm]);

  // Track if an element is in the filtered set for visual dimming
  const filteredMap = useMemo(() => {
    const map = new Set<string>();
    filteredElements.forEach((el) => {
      if (el.symbol) map.add(el.symbol);
    });
    return map;
  }, [filteredElements]);

  const selectedElement = useMemo(
    () => elements.find((el) => el.symbol === selectedSymbol),
    [elements, selectedSymbol]
  );

  const categories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center" wrap>
          <Stack gap={4}>
            <Heading level={2}>Periodic Table of Elements</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Explore chemical properties and relationships
            </Text>
          </Stack>
          <Box style={{ minWidth: '300px' }}>
            <SearchField
              value={searchTerm}
              onChange={setSearchTerm}
              placeholder="Search by name or symbol..."
              size="md"
            />
          </Box>
        </Stack>

        {/* Legend */}
        <Stack direction="horizontal" gap={8} wrap align="center">
          <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
            LEGEND:
          </Text>
          {categories.map((cat) => (
            <Stack key={cat} direction="horizontal" gap={4} align="center">
              <Box
                style={{
                  width: 'var(--ggui-spacing-3, 12px)',
                  height: 'var(--ggui-spacing-3, 12px)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  backgroundColor: getCategoryColor(cat),
                }}
              />
              <Text variant="caption" size="xs">
                {cat}
              </Text>
            </Stack>
          ))}
        </Stack>

        {/* Periodic Table Grid */}
        <Box
          style={{
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-4, 16px)',
            cursor: 'default',
          }}
        >
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(52px, 1fr))',
              gridTemplateRows: 'repeat(10, minmax(52px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '1000px',
            }}
          >
            {elements.map((el) => {
              const symbol = el.symbol || '';
              const isFiltered = filteredMap.has(symbol);
              const isSelected = selectedSymbol === symbol;
              const categoryColor = getCategoryColor(el.category);

              return (
                <button
                  key={symbol || el.atomicNumber}
                  onClick={() => symbol && setSelectedSymbol(symbol)}
                  aria-label={`Element ${el.name}, Atomic Number ${el.atomicNumber}`}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    padding: 0,
                    border: 'none',
                    background: 'none',
                    cursor: 'pointer',
                    outline: 'none',
                    transition: 'transform 100ms ease-in-out',
                  }}
                >
                  <Card
                    padding="var(--ggui-spacing-1, 4px)"
                    shadow={isSelected ? 'md' : 'none'}
                    radius="sm"
                    border
                    style={{
                      height: '100%',
                      width: '100%',
                      display: 'flex',
                      flexDirection: 'column',
                      justifyContent: 'center',
                      alignItems: 'center',
                      position: 'relative',
                      backgroundColor: isFiltered
                        ? 'var(--ggui-color-surface)'
                        : 'var(--ggui-color-surfaceVariant)',
                      borderColor: isSelected
                        ? 'var(--ggui-color-primary-500)'
                        : 'var(--ggui-color-outlineVariant)',
                      opacity: isFiltered ? 1 : 0.3,
                      borderTop: `4px solid ${categoryColor}`,
                      transform: isSelected ? 'scale(1.05)' : 'none',
                      zIndex: isSelected ? 10 : 1,
                    }}
                  >
                    <Text
                      variant="caption"
                      size="xs"
                      style={{
                        position: 'absolute',
                        top: '2px',
                        left: '4px',
                        fontSize: '10px',
                        fontWeight: '600',
                      }}
                    >
                      {el.atomicNumber}
                    </Text>
                    <Text
                      variant="body"
                      weight="bold"
                      style={{
                        fontSize: '18px',
                        lineHeight: 1,
                      }}
                    >
                      {symbol}
                    </Text>
                  </Card>
                </button>
              );
            })}
          </div>
        </Box>

        {/* Details Panel */}
        <Box style={{ minHeight: '180px' }}>
          {selectedElement ? (
            <Card padding="var(--ggui-spacing-6, 24px)" radius="lg" shadow="md" border>
              <Stack direction="horizontal" gap={32} align="center" wrap>
                <Box
                  style={{
                    width: '100px',
                    height: '100px',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'center',
                    alignItems: 'center',
                    backgroundColor: getCategoryColor(selectedElement.category),
                    borderRadius: 'var(--ggui-shape-radius-md)',
                    color: 'var(--ggui-color-surface, #ffffff)',
                  }}
                >
                  <Text variant="caption" weight="bold" color="inherit">
                    {selectedElement.atomicNumber}
                  </Text>
                  <Text size="4xl" weight="bold" color="inherit">
                    {selectedElement.symbol}
                  </Text>
                </Box>

                <Stack gap={16} style={{ flex: 1 }}>
                  <Stack gap={4}>
                    <Stack direction="horizontal" gap={12} align="center">
                      <Heading level={3}>{selectedElement.name}</Heading>
                      <Badge variant="primary">{selectedElement.category}</Badge>
                    </Stack>
                    <Divider margin="var(--ggui-spacing-2, 8px)" />
                  </Stack>

                  <Stack direction="horizontal" gap={48} wrap>
                    <Stack gap={2}>
                      <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                        ATOMIC WEIGHT
                      </Text>
                      <Text variant="bodyLarge" weight="semibold">
                        {selectedElement.atomicWeight} u
                      </Text>
                    </Stack>
                    <Stack gap={2}>
                      <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                        ATOMIC NUMBER
                      </Text>
                      <Text variant="bodyLarge" weight="semibold">
                        {selectedElement.atomicNumber}
                      </Text>
                    </Stack>
                    <Stack gap={2}>
                      <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                        SYMBOL
                      </Text>
                      <Text variant="bodyLarge" weight="semibold">
                        {selectedElement.symbol}
                      </Text>
                    </Stack>
                  </Stack>
                </Stack>

                <Box>
                  <button
                    onClick={() => setSelectedSymbol(null)}
                    style={{
                      padding: 'var(--ggui-spacing-2, 8px)',
                      background: 'none',
                      border: 'none',
                      cursor: 'pointer',
                      color: 'var(--ggui-color-onSurfaceVariant)',
                    }}
                    aria-label="Close details"
                  >
                    <svg
                      width="20"
                      height="20"
                      viewBox="0 0 24 24"
                      fill="none"
                      stroke="currentColor"
                      strokeWidth="2"
                    >
                      <path d="M18 6L6 18M6 6l12 12" />
                    </svg>
                  </button>
                </Box>
              </Stack>
            </Card>
          ) : (
            <Card
              padding="var(--ggui-spacing-8, 32px)"
              radius="lg"
              border
              style={{
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'center',
                backgroundColor: 'var(--ggui-color-surfaceVariant)',
                borderStyle: 'dashed',
              }}
            >
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Select an element to view detailed information
              </Text>
            </Card>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useEffect } from 'react';
import {
  Card,
  Stack,
  Heading,
  Badge,
} from '@ggui-ai/design/primitives';
import { ChatWindow } from '@ggui-ai/design/compositions';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<Message>;
  /** Action: Send Message */
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

/**
 * ChatInterface - A real-time bidirectional chat component.
 * Uses ChatWindow composition for standard accessibility and features.
 */
export default function ChatInterface(props: Props) {
  const { title, currentUser, participantCount, messages = [], sendMessage } = props;

  // Stream Contract implementation
  useEffect(() => {
    const handler = (event: any) => console.debug('Stream event:', event.detail);
    addEventListener('ggui:agent-data' as any, handler);
    return () => removeEventListener('ggui:agent-data' as any, handler);
  }, []);

  // Map messages to ChatMessage structure
  const mappedMessages = messages.map((m, i) => ({
    id: `${m.timestamp}-${i}`,
    content: m.text || '',
    sender: {
      id: m.sender || 'Unknown',
      name: m.sender || 'Unknown',
    },
    timestamp: m.timestamp || new Date().toISOString(),
  }));

  const handleSend = (content: string) => {
    sendMessage({
      text: content,
      timestamp: new Date().toISOString(),
    });
  };

  return (
    <Card 
      padding={0} 
      shadow="md" 
      border 
      radius="xl" 
      style={{ 
        height: '600px', 
        display: 'flex', 
        flexDirection: 'column', 
        backgroundColor: 'var(--ggui-color-surface)' 
      }}
    >
      <ChatWindow
        header={
          <Stack 
            direction="horizontal" 
            justify="between" 
            align="center" 
            style={{ padding: 'var(--ggui-spacing-4, 16px)', width: '100%', borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}
          >
            <Heading level={4}>{title}</Heading>
            {participantCount !== undefined && (
              <Badge variant="primary" size="sm">
                {participantCount} participants
              </Badge>
            )}
          </Stack>
        }
        messages={mappedMessages}
        currentUserId={currentUser}
        onSendMessage={handleSend}
        placeholder="Type a message..."
      />
    </Card>
  );
}

