import React, { useState, useEffect } from 'react';
import { Container, Card, Stack, Text, Heading, Icon, Spinner, Box, Divider, Badge } from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  lastUpdated?: string;
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

export default function StockTickerDashboard(props: Props) {
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState(props.lastUpdated);
  const [isLive, setIsLive] = useState(false);

  useEffect(() => {
    setStocks(props.stocks || []);
    setLastUpdated(props.lastUpdated);
  }, [props.stocks, props.lastUpdated]);

  useEffect(() => {
    const handleEvent = (event: any) => {
      const detail = event.detail;
      if (detail?.stocks) { setStocks(detail.stocks); setIsLive(true); }
      if (detail?.lastUpdated) { setLastUpdated(detail.lastUpdated); }
    };

    // Listen for agent stream data
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleEvent as any);
    }
    return () => {
      if (typeof removeEventListener !== 'undefined') {
        removeEventListener('ggui:agent-data', handleEvent as any);
      }
    };
  }, []);

  if (!stocks || stocks.length === 0) {
    return (
      <Container padding={64} center>
        <Stack align="center" gap={16}>
          <Spinner />
          <Text variant="bodyLarge">Waiting for Feed...</Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap={4}>
            <Heading level={1}>Market Watch</Heading>
            <Stack direction="horizontal" align="center" gap={8}>
              {isLive && (
                <Badge variant="success" size="sm" pill>
                  <Stack direction="horizontal" gap={4} align="center">
                    <div style={{ width: 6, height: 6, borderRadius: '50%', background: 'currentColor' }} />
                    LIVE
                  </Stack>
                </Badge>
              )}
              <Text variant="caption">
                Updated: {lastUpdated ? new Date(lastUpdated).toLocaleTimeString() : '---'}
              </Text>
            </Stack>
          </Stack>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant)" />

        <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
          {stocks.map((s, i) => {
            const up = (s.change || 0) >= 0;
            const c = up ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';

            return (
              <Box 
                key={s.symbol || i}
                borderRadius="var(--ggui-shape-radius-lg)"
                background="var(--ggui-color-surface)"
                style={{ border: `1.5px solid ${c}`, overflow: 'hidden' }}
              >
                <Card padding={16} radius="none" border={false} shadow="none">
                  <Stack gap={16}>
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={2}>
                        <Text size="xl" weight="bold">{s.symbol}</Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" truncate>{s.name}</Text>
                      </Stack>
                      <Icon name={up ? 'chevron-up' : 'chevron-down'} color={c} size={20} />
                    </Stack>
                    <Stack gap={4}>
                      <Text size="3xl" weight="bold">${s.price?.toFixed(2) ?? '0.00'}</Text>
                      <Text color={c} weight="semibold" size="sm">
                        {up ? '+' : ''}{s.change?.toFixed(2)} ({s.changePercent?.toFixed(2)}%)
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              </Box>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

