import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Divider,
  Box,
  Spacer,
  Container
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Callback on completion */
  complete?: (data: any) => void;
}

/**
 * OnboardingWizard component provides a 3-step setup flow for user profiles.
 * Includes profile details, preference settings, and a final review step.
 */
export default function OnboardingWizard(props: Props) {
  const { initialProfile, avatarOptions, roleOptions, complete } = props;

  // --- State Management ---
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions && avatarOptions.length > 0 ? avatarOptions[0] : ''),
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  // --- Validation ---
  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = formData.name.trim().length > 0 && validateEmail(formData.email);
  const isStep2Valid = formData.role !== '';

  const updateField = (field: string, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const progressValue = (step / 3) * 100;

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-12, 48px) var(--ggui-spacing-4, 16px)">
      <Card padding={32} shadow="md" radius="xl">
        <Stack gap={24}>
          <Heading level={2} align="center">Setup Wizard</Heading>

          <Box margin="0 0 var(--ggui-spacing-4, 16px) 0">
            <Stack gap={12}>
              <Stack direction="horizontal" justify="between" align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {step} of 3</Text>
                <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
                  {step === 1 ? 'Profile Details' : step === 2 ? 'Preferences' : 'Final Review'}
                </Text>
              </Stack>
              <Progress value={progressValue} size="sm" variant="default" />
            </Stack>
          </Box>

          <Box style={{ minHeight: '340px' }}>
            {/* Step 1: Profile Setup */}
            {step === 1 && (
              <Stack gap={20}>
                <Input
                  label="Name"
                  placeholder="Enter your name"
                  value={formData.name}
                  onChange={(val) => updateField('name', val)}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={(val) => updateField('email', val)}
                  required
                  error={formData.email && !validateEmail(formData.email) ? 'Invalid email format' : undefined}
                />
                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">Choose an Avatar</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions.map((avatar) => (
                      <Button
                        key={avatar}
                        variant={formData.avatar === avatar ? 'primary' : 'outline'}
                        onPress={() => updateField('avatar', avatar)}
                        style={{ fontSize: '24px', minWidth: '56px', height: '56px' }}
                      >
                        {avatar}
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {/* Step 2: Preferences */}
            {step === 2 && (
              <Stack gap={20}>
                <Select
                  label="Role"
                  placeholder="Select a role"
                  value={formData.role}
                  onChange={(val) => updateField('role', val)}
                  required
                  options={roleOptions.map(r => ({ value: r, label: r }))}
                />
                <Box padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)">
                  <Stack gap={16}>
                    <Toggle
                      label="Notifications"
                      checked={formData.emailNotifications}
                      onChange={(val) => updateField('emailNotifications', val)}
                    />
                    <Divider margin={4} />
                    <Stack direction="horizontal" align="center" justify="between">
                      <Text variant="bodySmall">Theme</Text>
                      <Stack direction="horizontal" gap={8}>
                        <Button 
                          size="sm" 
                          variant={formData.theme === 'light' ? 'primary' : 'ghost'} 
                          onPress={() => updateField('theme', 'light')}
                        >
                          Light
                        </Button>
                        <Button 
                          size="sm" 
                          variant={formData.theme === 'dark' ? 'primary' : 'ghost'} 
                          onPress={() => updateField('theme', 'dark')}
                        >
                          Dark
                        </Button>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}

            {/* Step 3: Review & Confirm */}
            {step === 3 && (
              <Stack gap={24}>
                <Card padding={20} border shadow="none">
                  <Stack gap={16}>
                    <Heading level={4}>Summary</Heading>
                    <Divider margin={0} />
                    <Stack direction="horizontal" gap={16} align="center">
                      <Box 
                        padding={12} 
                        background="var(--ggui-color-surface, #fafafa)" 
                        borderRadius={9999} 
                        style={{ fontSize: '32px' }}
                      >
                        {formData.avatar}
                      </Box>
                      <Stack gap={2}>
                        <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{formData.name}</Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
                      </Stack>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={8}>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                        <Text variant="bodySmall" weight="medium">{formData.role}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text>
                        <Text variant="bodySmall" weight="medium">{formData.emailNotifications ? 'On' : 'Off'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                        <Text variant="bodySmall" weight="medium" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin={8} />

          <Stack direction="horizontal" justify="between">
            <Box style={{ minWidth: '80px' }}>
              {step > 1 && (
                <Button variant="ghost" onPress={() => setStep(step - 1)}>
                  Go Back
                </Button>
              )}
            </Box>
            {step < 3 ? (
              <Button 
                variant="primary" 
                onPress={() => setStep(step + 1)} 
                disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)}
              >
                Next Step
              </Button>
            ) : (
              <Button variant="primary" onPress={() => complete?.(formData)}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

