import React, { useState, useMemo } from 'react';
import {
  Stack,
  Card,
  Text,
  Heading,
  Input,
  TextArea,
  Button,
  Progress,
  Checkbox,
  RadioGroup,
  Divider,
  Container,
  Box,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Callback when survey is submitted */
  onSubmit?: (data: SurveyData) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

export default function GeneratedComponent({
  featureOptions = ['Mobile Access', 'Advanced Analytics', 'Cloud Sync', 'Team Collaboration'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit,
}: Props) {
  const [step, setStep] = useState(0);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canGoNext = useMemo(() => {
    if (step === 0) return formData.name.trim() !== '' && isEmailValid(formData.email);
    if (step === 1) return formData.satisfaction !== '';
    return true;
  }, [step, formData.name, formData.email, formData.satisfaction]);

  const toggleFeature = (f: string) => {
    setFormData((prev) => ({
      ...prev,
      features: prev.features.includes(f)
        ? prev.features.filter((x) => x !== f)
        : [...prev.features, f],
    }));
  };

  const stepsTotal = 5;

  const handleNext = () => setStep((s) => Math.min(s + 1, stepsTotal - 1));
  const handleBack = () => setStep((s) => Math.max(s - 1, 0));

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      await new Promise((resolve) => setTimeout(resolve, 1000));
      onSubmit?.(formData);
      setIsSuccess(true);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSuccess) {
    return (
      <Container maxWidth="md" padding={24}>
        <Card padding={32} radius="xl" border={true} shadow="md">
          <Stack gap={24} align="center">
            <Alert variant="success" title="Submission Successful">
              Thank you for participating in our survey! Your feedback has been recorded.
            </Alert>
            <Button variant="outline" onClick={() => { setStep(0); setIsSuccess(false); setFormData({ name: '', email: '', satisfaction: '', features: [], comments: '' }); }}>
              Take Survey Again
            </Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding={24}>
      <Card padding={32} shadow="md" radius="xl" border={true}>
        <Stack gap={32}>
          <Stack gap={12}>
            <Stack direction="horizontal" justify="between" align="end">
              <Heading level={2}>Product Survey</Heading>
              <Text variant="label" color="var(--ggui-color-primary-600)">Step {step + 1} of {stepsTotal}</Text>
            </Stack>
            <Progress value={step + 1} max={stepsTotal} />
          </Stack>

          <Box>
            {step === 0 && (
              <Stack gap={24}>
                <Heading level={3}>Step 1: Contact Information</Heading>
                <Input label="Full Name" required placeholder="Enter your full name" value={formData.name} onChange={(val) => setFormData({ ...formData, name: val })} />
                <Input label="Email Address" required type="email" placeholder="name@example.com" value={formData.email} onChange={(val) => setFormData({ ...formData, email: val })} error={formData.email && !isEmailValid(formData.email) ? 'Invalid email format' : undefined} />
              </Stack>
            )}

            {step === 1 && (
              <Stack gap={24}>
                <Heading level={3}>Step 2: Satisfaction Rating</Heading>
                <RadioGroup
                  label="How satisfied are you with our service?"
                  value={formData.satisfaction}
                  onChange={(val) => setFormData({ ...formData, satisfaction: val })}
                  options={satisfactionLabels.map((l, i) => ({ label: l, value: String(i + 1) }))}
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={3}>Step 3: Feature Interests</Heading>
                <Text variant="bodySmall">Which features would you like to see improved? (Select all that apply)</Text>
                <Stack gap={12}>
                  {featureOptions.map((f) => (
                    <Checkbox
                      key={f}
                      label={f}
                      checked={formData.features.includes(f)}
                      onChange={() => toggleFeature(f)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={3}>Step 4: Additional Feedback</Heading>
                <TextArea
                  label="Any additional comments?"
                  placeholder="Tell us what you think..."
                  value={formData.comments}
                  onChange={(val) => setFormData({ ...formData, comments: val })}
                  maxLength={500}
                  showCount
                />
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={24}>
                <Heading level={3}>Final Review</Heading>
                <Box padding={24} background="var(--ggui-color-surfaceVariant)" borderRadius={12}>
                  <Stack gap={16}>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-neutral-500)">Full Name</Text>
                      <Text weight="medium">{formData.name}</Text>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-neutral-500)">Email</Text>
                      <Text weight="medium">{formData.email}</Text>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-neutral-500)">Satisfaction</Text>
                      <Text weight="medium">{satisfactionLabels[parseInt(formData.satisfaction) - 1] || 'None'}</Text>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-neutral-500)">Features</Text>
                      <Text weight="medium">{formData.features.join(', ') || 'No features selected'}</Text>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider margin={0} />

          <Stack direction="horizontal" justify="between">
            <Button variant="secondary" onClick={handleBack} disabled={step === 0 || isSubmitting}>
              Back
            </Button>
            {step === stepsTotal - 1 ? (
              <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>
                Submit Survey
              </Button>
            ) : (
              <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                Next Step
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

