const CATEGORY_TEXT_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-error-700, #b91c1c)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-700, #b45309)',
  'transition-metal': 'var(--ggui-color-neutral-700, #374151)',
  'post-transition-metal': 'var(--ggui-color-primary-700, #0369a1)',
  'metalloid': 'var(--ggui-color-success-700, #15803d)',
  'polyatomic-nonmetal': 'var(--ggui-color-info-700, #0e7490)',
  'diatomic-nonmetal': 'var(--ggui-color-success-800, #166534)',
  'noble-gas': 'var(--ggui-color-info-800, #155e75)',
  'lanthanide': 'var(--ggui-color-primary-800, #075985)',
  'actinide': 'var(--ggui-color-error-800, #991b1b)',
};

const CATEGORY_LABELS: Record<string, string> = {
