};

/**
 * Interactive Periodic Table of Elements.
 * Displays elements in a CSS grid, allows filtering by name or symbol,
 * and provides detailed information on click.
 */
export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSymbol, setSelectedSymbol] = useState<string | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lowTerm = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(lowTerm) ||
        el.symbol?.toLowerCase().includes(lowTerm)
    );
  }, [elements, searchTerm]);

  const selectedElement = useMemo(
    () => elements.find((el) => el.symbol === selectedSymbol),
    [elements, selectedSymbol]
  );

  const categories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats);
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Header and Search */}
        <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-4, 16px)">
          <Heading level={2}>Periodic Table</Heading>
          <Box style={{ width: '100%', maxWidth: '320px' }}>
            <SearchField
              value={searchTerm}
              onChange={setSearchTerm}
              placeholder="Filter by name or symbol..."
            />
          </Box>
        </Stack>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4, 16px)" radius="md">
          <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" wrap align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Legend:
            </Text>
            {categories.map((cat) => (
              <Box
                key={cat}
                paddingX="var(--ggui-spacing-2, 8px)"
                paddingY="var(--ggui-spacing-1, 4px)"
                borderRadius="var(--ggui-shape-radius-sm, 4px)"
                background={CATEGORY_COLORS[cat] || 'var(--ggui-color-neutral-100)'}
                style={{ 
                  border: '1px solid var(--ggui-color-outlineVariant)',
                  whiteSpace: 'nowrap'
                }}
              >
                <Text
                  variant="caption"
                  weight="medium"
                  color={CATEGORY_TEXT_COLORS[cat] || 'var(--ggui-color-neutral-700)'}
                >
                  {CATEGORY_LABELS[cat] || cat}
                </Text>
              </Box>
            ))}
          </Stack>
        </Card>

        {/* Table Grid Wrapper */}
        <Box
          style={{
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(48px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '900px',
            }}
          >
            {elements.map((el) => {
              const isMatch = filteredElements.some((fel) => fel.symbol === el.symbol);
              const isSelected = selectedSymbol === el.symbol;
              const bgColor = CATEGORY_COLORS[el.category || ''] || 'var(--ggui-color-neutral-100)';
              const textColor = CATEGORY_TEXT_COLORS[el.category || ''] || 'var(--ggui-color-neutral-700)';

              return (
                <button
                  key={el.symbol}
                  onClick={() => setSelectedSymbol(el.symbol || null)}
                  aria-label={`View details for ${el.name}`}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    aspectRatio: '1',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'center',
                    alignItems: 'center',
                    position: 'relative',
                    cursor: 'pointer',
                    backgroundColor: isMatch ? bgColor : 'var(--ggui-color-surface)',
                    opacity: isMatch ? 1 : 0.3,
                    border: isSelected
                      ? '2px solid var(--ggui-color-primary-600)'
                      : '1px solid var(--ggui-color-outlineVariant)',
                    borderRadius: 'var(--ggui-shape-radius-sm)',
                    transition: 'all 150ms ease-in-out',
                    zIndex: isSelected ? 10 : 1,
                    padding: 0,
                    outline: 'none',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                  }}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      setSelectedSymbol(el.symbol || null);
                    }
                  }}
                >
                  <Box
                    style={{
                      position: 'absolute',
                      top: 'var(--ggui-spacing-1, 4px)',
                      left: 'var(--ggui-spacing-1, 4px)',
                    }}
                  >
                    <Text size="xs" color={textColor} weight="semibold">
                      {el.atomicNumber}
                    </Text>
                  </Box>
                  <Text
                    size="xl"
                    weight="bold"
                    color={textColor}
                    style={{ lineHeight: 1 }}
                  >
                    {el.symbol}
                  </Text>
                </button>
              );
            })}
          </Box>
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Box style={{ animation: 'ggui-slideInUp 300ms ease-out' }}>
            <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="lg">
              <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)" align="center" wrap>
                <Box
                  padding="var(--ggui-spacing-6, 24px)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  background={CATEGORY_COLORS[selectedElement.category || ''] || 'var(--ggui-color-neutral-100)'}
                  style={{
                    width: '140px',
                    height: '140px',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'center',
                    alignItems: 'center',
                    border: '1px solid var(--ggui-color-outline)',
                  }}
                >
                  <Text variant="caption" weight="bold" color={CATEGORY_TEXT_COLORS[selectedElement.category || '']}>
                    {selectedElement.atomicNumber}
                  </Text>
                  <Text size="4xl" weight="bold" color={CATEGORY_TEXT_COLORS[selectedElement.category || '']}>
                    {selectedElement.symbol}
                  </Text>
                  <Text variant="caption" weight="medium" color={CATEGORY_TEXT_COLORS[selectedElement.category || '']}>
                    {selectedElement.atomicWeight}
                  </Text>
                </Box>

                <Stack gap="var(--ggui-spacing-3, 12px)" style={{ flex: 1, minWidth: '300px' }}>
                  <Heading level={3}>{selectedElement.name}</Heading>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="center" wrap>
                    <Badge variant="primary">{CATEGORY_LABELS[selectedElement.category || ''] || selectedElement.category}</Badge>
                    <Divider orientation="vertical" margin="var(--ggui-spacing-2, 8px)" />
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      Atomic Weight: <strong>{selectedElement.atomicWeight}</strong>
                    </Text>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-2, 8px)" />
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                    The element <strong>{selectedElement.name}</strong> ({selectedElement.symbol}) belongs to the <strong>{selectedElement.category?.replace(/-/g, ' ')}</strong> group. It has an atomic number of <strong>{selectedElement.atomicNumber}</strong> and a relative atomic mass of <strong>{selectedElement.atomicWeight}</strong>.
                  </Text>
                </Stack>
              </Stack>
            </Card>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

