import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Stack, 
  Text, 
  Heading, 
  Box, 
  Spinner,
  Icon
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard - A live market watch dashboard that displays
 * stock prices and updates in real-time via the agent-data stream.
 */
export default function StockTickerDashboard({ 
  stocks: initialStocks = [], 
  lastUpdated: initialLastUpdated 
}: Props) {
  // Local state to handle real-time updates from the stream
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [isInitialLoad, setIsInitialLoad] = useState(!initialStocks || initialStocks.length === 0);

  // Listen for real-time agent data updates (Stream Contract)
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data) {
        if (data.stocks && Array.isArray(data.stocks)) {
          setStocks(data.stocks);
          setIsInitialLoad(false);
        }
        if (data.lastUpdated) {
          setLastUpdated(data.lastUpdated);
        }
      }
    };

    // Use global listener for the stream contract
    addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => {
      removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, []);

  // Format price as USD currency
  const formatCurrency = (val?: number) => {
    if (val === undefined) return '$0.00';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
    }).format(val);
  };

  // Format ISO timestamp to local time string
  const formatTime = (iso?: string) => {
    if (!iso) return 'Pending update...';
    try {
      return new Date(iso).toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit' 
      });
    } catch {
      return 'Invalid timestamp';
    }
  };

  // Loading state when waiting for initial data
  if (isInitialLoad && (!stocks || stocks.length === 0)) {
    return (
      <Container padding={48}>
        <Stack align="center" justify="center" gap={16}>
          <Spinner size={48} color="var(--ggui-color-primary-600)" />
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
            Connecting to market data feed...
          </Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        {/* Dashboard Header */}
        <Stack direction="horizontal" justify="between" align="end" wrap gap={12}>
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface)">Market Watch</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Live portfolio and market performance tracking
            </Text>
          </Stack>

          <Box 
            paddingX={12} 
            paddingY={6} 
            borderRadius="var(--ggui-shape-radius-full)" 
            background="var(--ggui-color-surfaceVariant)"
          >
            <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant)">
              Last Sync: {formatTime(lastUpdated)}
            </Text>
          </Box>
        </Stack>

        {/* Responsive grid of stock cards (3 per row on desktop, 1 on mobile) */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={24}>
          {stocks.map((stock) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const statusColor = isPositive 
              ? 'var(--ggui-color-success-600, #16a34a)' 
              : 'var(--ggui-color-error-600, #dc2626)';
            const statusBg = isPositive
              ? 'var(--ggui-color-success-50, #f0fdf4)'
              : 'var(--ggui-color-error-50, #fef2f2)';

            return (
              <Box 
                key={stock.symbol || Math.random().toString()}
                padding={24}
                borderRadius="var(--ggui-shape-radius-xl)"
                background="var(--ggui-color-surface)"
                style={{ 
                  border: `2px solid ${statusColor}`,
                  boxShadow: 'var(--ggui-shape-shadow-sm)',
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 'var(--ggui-spacing-6, 24px)',
                  transition: 'transform 0.2s ease, box-shadow 0.2s ease'
                }}
              >
                {/* Symbol and Status Badge Row */}
                <Stack direction="horizontal" justify="between" align="start" gap={8}>
                  <Stack gap={2}>
                    <Text 
                      size="xl" 
                      weight="bold" 
                      color="var(--ggui-color-onSurface)"
                      truncate
                    >
                      {stock.symbol}
                    </Text>
                    <Text 
                      variant="bodySmall" 
                      color="var(--ggui-color-onSurfaceVariant)" 
                      truncate
                    >
                      {stock.name}
                    </Text>
                  </Stack>

                  <Box 
                    paddingX={8} 
                    paddingY={4} 
                    borderRadius="var(--ggui-shape-radius-md)" 
                    background={statusBg}
                  >
                    <Stack direction="horizontal" gap={4} align="center">
                      <Text size="xs" weight="bold" color={statusColor}>
                        {isPositive ? '▲' : '▼'}
                      </Text>
                      <Text size="xs" weight="bold" color={statusColor}>
                        {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                      </Text>
                    </Stack>
                  </Box>
                </Stack>

                {/* Pricing Block */}
                <Stack gap={4}>
                  <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface)">
                    {formatCurrency(stock.price)}
                  </Text>
                  <Text 
                    size="sm" 
                    weight="semibold" 
                    color={statusColor}
                  >
                    {isPositive ? '+' : '-'}{Math.abs(stock.change ?? 0).toFixed(2)} ({isPositive ? '+' : ''}{stock.changePercent?.toFixed(2)}%)
                  </Text>
                </Stack>
              </Box>
            );
          })}
        </CardGrid>

        {/* Empty state fallback if no data is available after connection */}
        {stocks.length === 0 && !isInitialLoad && (
          <Box 
            padding={64} 
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-xl)"
            style={{ border: '1px dashed var(--ggui-color-outline)' }}
          >
            <Stack align="center" gap={16}>
              <Icon name="search" size={48} color="var(--ggui-color-onSurfaceVariant)" />
              <Stack gap={4} align="center">
                <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                  Empty Watchlist
                </Text>
                <Text color="var(--ggui-color-onSurfaceVariant)" align="center">
                  Live market data is connected but no stocks were found to display.
                </Text>
              </Stack>
            </Stack>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Divider,
  Box,
  Spacer,
  Icon,
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  onComplete: (data: any) => void;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function GeneratedComponent(props: Props) {
  const { avatarOptions, roleOptions, initialProfile = {}, onComplete } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: (avatarOptions && avatarOptions.length > 0) ? (initialProfile.avatar || avatarOptions[0]) : '',
    role: initialProfile.role || '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme || 'light',
  });

  const isStep1Valid = useMemo(() => {
    return (
      formData.name.trim().length > 0 &&
      EMAIL_REGEX.test(formData.email) &&
      formData.avatar.length > 0
    );
  }, [formData.name, formData.email, formData.avatar]);

  const isStep2Valid = useMemo(() => {
    return formData.role.length > 0;
  }, [formData.role]);

  const handleNext = () => {
    if (step < 3) setStep(step + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleComplete = () => {
    onComplete(formData);
  };

  const stepProgress = (step / 3) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="xl" border={true}>
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={2}>Onboarding</Heading>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {step} of 3</Text>
            </Stack>
            <Progress value={stepProgress} />
          </Stack>

          <Box style={{ minHeight: '340px' }}>
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Heading level={4}>Profile Setup</Heading>
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="label">FullName</Text>
                    <Input label="FullName" value={formData.name} onChange={(v) => setFormData(p => ({ ...p, name: v }))} required />
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="label">EmailAddress</Text>
                    <Input label="EmailAddress" value={formData.email} onChange={(v) => setFormData(p => ({ ...p, email: v }))} required />
                  </Stack>
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text variant="label">Avatar</Text>
                    <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
                      {avatarOptions.map((emoji) => (
                        <button
                          key={emoji}
                          type="button"
                          onClick={() => setFormData(p => ({ ...p, avatar: emoji }))}
                          style={{
                            width: 'var(--ggui-spacing-12, 48px)', height: 'var(--ggui-spacing-12, 48px)', fontSize: '24px', cursor: 'pointer',
                            border: `2px solid ${formData.avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}`,
                            borderRadius: 'var(--ggui-shape-radius-lg)',
                            background: formData.avatar === emoji ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                          }}
                        >
                          {emoji}
                        </button>
                      ))}
                    </Stack>
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Heading level={4}>Preferences</Heading>
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Select label="Role" value={formData.role} onChange={(v) => setFormData(p => ({ ...p, role: v }))} options={roleOptions.map(r => ({ value: r, label: r }))} />
                  <Toggle checked={formData.emailNotifications} onChange={(v) => setFormData(p => ({ ...p, emailNotifications: v }))} label="EnableNotifications" />
                  <Toggle checked={formData.theme === 'dark'} onChange={(v) => setFormData(p => ({ ...p, theme: v ? 'dark' : 'light' }))} label="DarkMode" />
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Heading level={4}>Review</Heading>
                <Box padding="var(--ggui-spacing-6, 24px)" borderRadius="var(--ggui-shape-radius-lg)" background="var(--ggui-color-surfaceVariant)">
                  <Text variant="bodySmall">Name: {formData.name}</Text>
                  <Text variant="bodySmall">Email: {formData.email}</Text>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider margin={0} />

          <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" justify="between">
            {step > 1 && <Button variant="outline" onClick={handleBack}>Back</Button>}
            {step === 1 && <Spacer size="flex" />}
            {step < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={step === 1 ? !isStep1Valid : !isStep2Valid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleComplete}>Complete</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

