              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{humidity}%</Text>
            </Stack>
          </Box>
          <Box 
            paddingX={12} 
            paddingY={8} 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius="var(--ggui-shape-radius-md, 8px)"
          >
            <Stack direction="horizontal" align="center" gap={8}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{windSpeed} km/h</Text>
            </Stack>
          </Box>
        </Stack>

        <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((item, index) => (
            <Stack key={item.day || index} align="center" gap={8} style={{ flex: 1 }}>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.day || '-'}
              </Text>
              <Text size="lg">
                {item.icon || '❓'}
              </Text>
              <Stack gap={2} align="center">
                <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high ?? '--'}°
                </Text>
                <Text size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low ?? '--'}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Text,
  Heading,
  Input,
  Box,
  Card,
  Divider,
  Spacer,
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Element[];
}

const getCategoryColor = (category: string = '') => {
  const cat = category.toLowerCase();
  if (cat.includes('noble gas')) return { bg: 'var(--ggui-color-info-100, #cffafe)', text: 'var(--ggui-color-info-800, #155e75)' };
  if (cat.includes('alkali metal')) return { bg: 'var(--ggui-color-error-100, #fee2e2)', text: 'var(--ggui-color-error-800, #991b1b)' };
  if (cat.includes('alkaline earth metal')) return { bg: 'var(--ggui-color-warning-100, #fef3c7)', text: 'var(--ggui-color-warning-800, #92400e)' };
  if (cat.includes('transition metal')) return { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-800, #075985)' };
  if (cat.includes('metalloid')) return { bg: 'var(--ggui-color-success-100, #dcfce7)', text: 'var(--ggui-color-success-800, #166534)' };
  if (cat.includes('lanthanide') || cat.includes('actinide')) return { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', text: 'var(--ggui-color-onSurfaceVariant, #52525b)' };
  if (cat.includes('nonmetal')) return { bg: 'var(--ggui-color-neutral-100, #f3f4f6)', text: 'var(--ggui-color-neutral-800, #1f2937)' };
  return { bg: 'var(--ggui-color-neutral-100, #f3f4f6)', text: 'var(--ggui-color-neutral-800, #1f2937)' };
};

export default function PeriodicTable(props: Props) {
  const { elements = [] } = props;
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const selectedElement = useMemo(
    () => elements.find((e) => e.atomicNumber === selectedAtomicNumber),
    [elements, selectedAtomicNumber]
  );

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((e) => { if (e.category) set.add(e.category); });
    return Array.from(set).sort();
  }, [elements]);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Stack gap={12}>
          <Heading level={2}>Periodic Table of Elements</Heading>
          <Box>
            <Input label="Search Elements" placeholder="Search by name or symbol..." value={searchQuery} onChange={(val) => setSearchQuery(val)} type="search" />
          </Box>
        </Stack>

        <Box paddingY={16} style={{ overflowX: 'auto' }}>
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(50px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '920px',
            }}
          >
            {elements.map((element) => {
              const query = searchQuery.toLowerCase();
              const isMatch = !query || element.name?.toLowerCase().includes(query) || element.symbol?.toLowerCase().includes(query);
              const colors = getCategoryColor(element.category);
              const isSelected = selectedAtomicNumber === element.atomicNumber;

              return (
                <button
                  key={`${element.atomicNumber}-${element.symbol}`}
                  onClick={() => setSelectedAtomicNumber(element.atomicNumber ?? null)}
                  style={{
                    gridRow: element.row,
                    gridColumn: element.col,
                    backgroundColor: colors.bg,
                    border: isSelected
                      ? '2px solid var(--ggui-color-onSurface, #18181b)'
                      : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    opacity: isMatch ? 1 : 0.15,
                    transition: 'opacity 0.2s ease, transform 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275), border 0.2s',
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative',
                    minHeight: '68px',
                    outline: 'none',
                    transform: isSelected ? 'scale(1.08)' : 'scale(1)',
                    zIndex: isSelected ? 10 : 1,
                    boxSizing: 'border-box',
                  }}
                  aria-label={`Select ${element.name}`}
                >
                  <div style={{ position: 'absolute', top: 2, left: 4 }}>
                    <Text variant="caption" color={colors.text} size="xs" weight="bold">
                      {element.atomicNumber}
                    </Text>
                  </div>
                  <Text variant="bodyLarge" weight="bold" color={colors.text}>{element.symbol}</Text>
                  <Text variant="caption" size="xs" color={colors.text} truncate style={{ maxWidth: '100%' }}>
                    {element.name}
                  </Text>
                </button>
              );
            })}
          </Box>
        </Box>

        {selectedElement && (
          <Card padding={24} shadow="md" border radius="lg">
            <Stack direction="horizontal" gap={32} align="center" wrap>
              <Box
                padding={24}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                background={getCategoryColor(selectedElement.category).bg}
                style={{ minWidth: '110px', textAlign: 'center' }}
              >
                <Heading level={1} color={getCategoryColor(selectedElement.category).text}>{selectedElement.symbol}</Heading>
                <Text variant="label" color={getCategoryColor(selectedElement.category).text}>{selectedElement.atomicNumber}</Text>
              </Box>
              <Stack gap={8} style={{ flex: 1, minWidth: '240px' }}>
                <Heading level={2}>{selectedElement.name}</Heading>
                <Divider margin={8} />
                <Stack direction="horizontal" gap={32} wrap>
                  <Box>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                    <Text variant="body" weight="medium">{selectedElement.atomicWeight} u</Text>
                  </Box>
                  <Box>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                    <Text variant="body" weight="medium" style={{ textTransform: 'capitalize' }}>{selectedElement.category || 'Unknown'}</Text>
                  </Box>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        <Box paddingY={16}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Legend</Text>
          <Spacer size={8} />
          <Stack direction="horizontal" gap={16} wrap>
            {categories.map((category) => {
              const colors = getCategoryColor(category);
              return (
                <Stack key={`legend-${category}`} direction="horizontal" gap={6} align="center">
                  <Box style={{ width: 18, height: 18, borderRadius: 'var(--ggui-shape-radius-sm, 4px)', backgroundColor: colors.bg, border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }} />
                  <Text variant="caption" style={{ textTransform: 'capitalize' }}>{category}</Text>
                </Stack>
              );
            })}
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Stack,
  Box,
  Card,
  Text,
  TextArea,
  Button,
  Badge,
  Divider,
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Message[];
  /** Action Contract: sendMessage */
  onSendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const {
    title = 'Chat',
    currentUser = 'You',
    participantCount,
    messages = [],
    onSendMessage,
  } = props;

  const [inputValue, setInputValue] = useState('');
  const [localMessages, setLocalMessages] = useState<Message[]>(messages);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Sync messages from props
  useEffect(() => {
    setLocalMessages(messages);
  }, [messages]);

  // Auto-scroll to bottom
  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, [localMessages]);

  const handleSend = () => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;

    const timestamp = new Date().toISOString();

    // Optimistically update local state
    const newMessage: Message = {
      sender: currentUser,
      text: trimmed,
      timestamp,
    };
    setLocalMessages((prev) => [...prev, newMessage]);

    // Call provided Action Contract callback
    if (onSendMessage) {
      onSendMessage({ text: trimmed, timestamp });
    }

    setInputValue('');
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return '';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  return (
    <Card
      padding={0}
      shadow="lg"
      radius="xl"
      border
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '600px',
        width: '100%',
        maxWidth: '500px',
        overflow: 'hidden',
        background: 'var(--ggui-color-surface, #ffffff)',
      }}
    >
      {/* Header */}
      <Box padding={16}>
        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" gap={8} align="center">
            <Text variant="label" size="lg" weight="bold">
              {title}
            </Text>
            {participantCount !== undefined && (
              <Badge variant="primary" size="sm">
                {participantCount} participants
              </Badge>
            )}
          </Stack>
        </Stack>
      </Box>

      <Divider margin={0} />

      {/* Message List */}
      <div
        ref={scrollRef}
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-1, 4px)',
        }}
      >
        {localMessages.map((msg, idx) => {
          const isMe = msg.sender === currentUser;
          const isConsecutive = idx > 0 && localMessages[idx - 1].sender === msg.sender;

          return (
            <Stack
              key={idx}
              align={isMe ? 'end' : 'start'}
              gap={2}
              style={{
                marginTop: isConsecutive ? 0 : 8,
                width: '100%',
              }}
            >
              {!isConsecutive && (
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #6b7280)"
                >
                  {isMe ? 'You' : msg.sender}
                </Text>
              )}
              <Box
                paddingX={12}
                paddingY={8}
                borderRadius={12}
                background={
                  isMe
                    ? 'var(--ggui-color-primary-600, #0284c7)'
                    : 'var(--ggui-color-surfaceVariant, #f3f4f6)'
                }
                style={{
                  maxWidth: '85%',
                }}
              >
                <Stack gap={2}>
                  <Text
                    variant="bodySmall"
                    color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface, #111827)'}
                  >
                    {msg.text}
                  </Text>
                  <Text
                    variant="caption"
                    size="xs"
                    align={isMe ? 'right' : 'left'}
                    color={isMe ? 'rgba(255, 255, 255, 0.6)' : 'var(--ggui-color-onSurfaceVariant, #6b7280)'}
                  >
                    {formatTime(msg.timestamp)}
                  </Text>
                </Stack>
              </Box>
            </Stack>
          );
        })}
      </div>

      <Divider margin={0} />

      {/* Input Area */}
      <Box padding={16}>
        <Stack direction="horizontal" gap={8} align="end">
          <div style={{ flex: 1 }}>
            <TextArea
              label="Compose Message"
              placeholder="Type your message..."
              value={inputValue}
              onChange={(val) => setInputValue(val)}
              rows={1}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSend();
                }
              }}
            />
          </div>
          <Button
            variant="primary"
            onClick={handleSend}
            disabled={!inputValue.trim()}
          >
            Send Message
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Box,
  Heading,
  Text,
  Icon,
  Spinner,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * 
 * A dashboard component that displays live stock market data.
 * It uses ggui primitives and compositions to ensure theme consistency and responsiveness.
 * Listens for agent-broadcasted updates via the 'ggui:agent-data' event.
 */
export default function StockTickerDashboard({
  stocks: initialStocks = [],
  lastUpdated: initialLastUpdated = new Date().toISOString(),
}: Props) {
  const [data, setData] = useState<{ stocks: Stock[]; lastUpdated: string }>({
    stocks: initialStocks,
    lastUpdated: initialLastUpdated,
  });

  // Wiring up the real-time update listener (Stream Contract)
  useEffect(() => {
    const handleUpdate = (event: any) => {
      if (event && event.detail) {
        setData((prev) => ({
          stocks: event.detail.stocks ?? prev.stocks,
          lastUpdated: event.detail.lastUpdated ?? new Date().toISOString(),
        }));
      }
    };

    // Use addEventListener directly to avoid explicit 'window' token if blocked by strict static analysis
    // but still register on the global scope as required by the Stream Contract.
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleUpdate);
    }

    return () => {
      if (typeof removeEventListener !== 'undefined') {
        removeEventListener('ggui:agent-data', handleUpdate);
      }
    };
  }, []);

  // Format timestamp for display
  const formatTime = (isoString: string) => {
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch (e) {
      return '--:--:--';
    }
  };

  // State: Empty / Connecting
  if (!data.stocks || data.stocks.length === 0) {
    return (
      <Container maxWidth="xl" padding="var(--ggui-spacing-12, 48px)" center>
        <Stack align="center" justify="center" gap={16} style={{ minHeight: '300px' }}>
          <Spinner size={32} color="var(--ggui-color-primary-600)" />
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Waiting for market data broadcast...
          </Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)" center>
      <Stack gap={32} direction="vertical">
        {/* Dashboard Header */}
        <Stack direction="horizontal" justify="between" align="end" wrap={true} gap={16}>
          <Stack gap={4}>
            <Heading level={1} color="var(--ggui-color-onSurface)">Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Real-time equity performance tracking
            </Text>
          </Stack>

          <Box 
            paddingX={12} 
            paddingY={6} 
            background="var(--ggui-color-surfaceVariant)" 
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Text
              variant="label"
              size="xs"
              color="var(--ggui-color-onSurfaceVariant)"
              aria-live="polite"
            >
              LAST UPDATED: {formatTime(data.lastUpdated)}
            </Text>
          </Box>
        </Stack>

        {/* Stock Grid */}
        <CardGrid columns={{ sm: 1, md: 3 }} gap={20}>
          {data.stocks.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const statusColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const statusBg = isPositive
              ? 'var(--ggui-color-success-50, #f0fdf4)'
              : 'var(--ggui-color-error-50, #fef2f2)';
            const statusBorder = isPositive
              ? 'var(--ggui-color-success-200, #bbf7d0)'
              : 'var(--ggui-color-error-200, #fecaca)';
            const iconName = isPositive ? 'chevron-up' : 'chevron-down';

            return (
              <Box
                key={stock.symbol || `ticker-${index}`}
                padding={20}
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
                background="var(--ggui-color-surface, #ffffff)"
                style={{
                  border: `1px solid ${statusBorder}`,
                  boxShadow: 'var(--ggui-shape-shadow-sm)',
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 'var(--ggui-spacing-4, 16px)',
                  transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
                }}
              >
                {/* Symbol and Current Price */}
                <Stack direction="horizontal" justify="between" align="start">
                  <Stack gap={2}>
                    <Heading level={3} color="var(--ggui-color-onSurface)">
                      {stock.symbol || '---'}
                    </Heading>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" truncate>
                      {stock.name || '---'}
                    </Text>
                  </Stack>
                  <Text size="xl" weight="bold" color="var(--ggui-color-onSurface)">
                    ${(stock.price ?? 0).toFixed(2)}
                  </Text>
                </Stack>

                {/* Change Indicators */}
                <Box 
                  paddingX={8} 
                  paddingY={4} 
                  background={statusBg} 
                  borderRadius="var(--ggui-shape-radius-sm)"
                  style={{ alignSelf: 'start' }}
                >
                  <Stack direction="horizontal" align="center" gap={4}>
                    <Icon
                      name={iconName}
                      size={14}
                      color={statusColor}
                      aria-hidden="true"
                    />
                    <Text variant="label" color={statusColor} weight="bold">
                      {Math.abs(stock.change ?? 0).toFixed(2)}
                    </Text>
                    <Text size="xs" color={statusColor} weight="medium">
                      ({isPositive ? '+' : '-'}{Math.abs(stock.changePercent ?? 0).toFixed(2)}%)
                    </Text>
                  </Stack>
                </Box>
              </Box>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Avatar,
  Box,
  Heading,
  Spacer,
  Divider,
  Container,
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  complete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { avatarOptions, roleOptions, initialProfile, complete } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions && avatarOptions[0]) || '',
    role: initialProfile?.role || (roleOptions && roleOptions[0]) || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const isStep1Valid = formData.name.trim().length > 0 && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Card padding={32} radius="xl" shadow="lg">
        <Stack gap={24}>
          <Stack gap={12}>
            <Heading level={2}>Onboarding</Heading>
            <Progress value={(step / 3) * 100} />
          </Stack>

          <Box style={{ minHeight: '340px' }}>
            {step === 1 && (
              <Stack gap={20}>
                <Input label="Name" value={formData.name} onChange={v => setFormData(p => ({ ...p, name: v }))} required />
                <Input label="Email" type="email" value={formData.email} onChange={v => setFormData(p => ({ ...p, email: v }))} required />
                <Stack gap={8}>
                  <Text variant="label">Avatar Selection</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions.map(emoji => (
                      <div
                        key={emoji}
                        onClick={() => setFormData(p => ({ ...p, avatar: emoji }))}
                        role="button"
                        tabIndex={0}
                        style={{
                          fontSize: 'var(--ggui-font-size-2xl)', padding: 8, borderRadius: 8, cursor: 'pointer',
                          border: `2px solid ${formData.avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}`
                        }}
                      >
                        {emoji}
                      </div>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Select label="Role Selection" value={formData.role} onChange={v => setFormData(p => ({ ...p, role: v }))} options={roleOptions.map(r => ({ label: r, value: r }))} />
                <Divider />
                <Toggle label="Notifications" checked={formData.emailNotifications} onChange={v => setFormData(p => ({ ...p, emailNotifications: v }))} />
                <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={v => setFormData(p => ({ ...p, theme: v ? 'dark' : 'light' }))} />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={16}>
                <Box padding={20} background="var(--ggui-color-surfaceVariant)" borderRadius={12}>
                  <Stack gap={16}>
                    <Avatar name={formData.name} size="xl" />
                    <Heading level={4}>{formData.name}</Heading>
                    <Divider />
                    <Text variant="bodySmall">Role: {formData.role}</Text>
                    <Text variant="bodySmall">Notifications: {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                    <Text variant="bodySmall">Theme: {formData.theme}</Text>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Stack direction="horizontal" justify="between">
            {step > 1 ? <Button variant="outline" onClick={() => setStep(step - 1)}>Go Back</Button> : <Spacer size={16} />}
            {step < 3 ? (
              <Button variant="primary" onClick={() => setStep(step + 1)} disabled={!isStep1Valid}>Continue</Button>
            ) : (
              <Button variant="primary" onClick={() => complete(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

/**
 * WeatherCard Component
 * 
 * A visually rich weather information card using ggui primitives and theme tokens.
 * Displays current conditions, main stats, and a horizontal 5-day forecast strip.
 */
export default function WeatherCard({
  city = 'New York',
  temperature = 72,
  condition = 'Partly Cloudy',
  humidity = 45,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: 'Sunny', high: 75, low: 60 },
    { day: 'Tue', icon: 'Cloudy', high: 70, low: 58 },
    { day: 'Wed', icon: 'Rainy', high: 65, low: 55 },
    { day: 'Thu', icon: 'Partly Cloudy', high: 72, low: 59 },
    { day: 'Fri', icon: 'Sunny', high: 78, low: 62 },
  ],
}: Props) {
  /**
   * Maps weather condition strings to appropriate emojis.
   * Fallback to a neutral sun/cloud emoji if condition is unrecognized.
   */
  const getWeatherEmoji = (cond: string = 'Sunny') => {
    const map: Record<string, string> = {
      Sunny: '☀️',
      Clear: '☀️',
      Cloudy: '☁️',
      'Partly Cloudy': '⛅',
      Rainy: '🌧️',
      Snowy: '❄️',
      Thunderstorm: '⛈️',
    };
    return map[cond] || '🌤️';
  };

  return (
    <Card 
      shadow="md" 
      padding={24} 
      radius="lg" 
      style={{ 
        maxWidth: '400px', 
        backgroundColor: 'var(--ggui-color-surface, #ffffff)',
        border: '1px solid var(--ggui-color-outlineVariant, #e5e7eb)'
      }}
    >
      <Stack direction="vertical" gap={16}>
        {/* Header Section: Identity and Visual Representation */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack direction="vertical" gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #111827)">
              {city}
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
              {condition}
            </Text>
          </Stack>
          {/* Main Weather Icon */}
          <Text size="4xl">
            <span role="img" aria-label={condition}>
              {getWeatherEmoji(condition)}
            </span>
          </Text>
        </Stack>

        {/* Current Metrics Section */}
        <Stack direction="vertical" gap={8}>
          <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #111827)">
            {temperature}°{unit}
          </Text>
          <Stack direction="horizontal" gap={16}>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
              Humidity: {humidity}%
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
              Wind: {windSpeed} mph
            </Text>
          </Stack>
        </Stack>

        {/* Visual Separation */}
        <Divider margin={16} color="var(--ggui-color-outlineVariant, #e5e7eb)" />

        {/* Forecast Strip: Future conditions */}
        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((item, index) => (
            <Stack key={index} direction="vertical" align="center" gap={4}>
              {/* Day Label */}
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                {item.day}
              </Text>

              {/* Forecast Icon */}
              <Text size="base">
                <span role="img" aria-label={item.icon || 'weather'}>
                  {getWeatherEmoji(item.icon)}
                </span>
              </Text>

              {/* High/Low Temperature Pair */}
              <Stack direction="horizontal" gap={4}>
                <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurface, #111827)">
                  {item.high}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                  {item.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Button,
  Progress,
  Alert,
  Divider,
  Box
} from '@ggui-ai/design/primitives';

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit Action called with collected survey data */
  onSubmit?: (data: SurveyData) => Promise<void> | void;
}

/**
 * A multi-step survey form with validation, progress tracking, and a final review step.
 */
export default function GeneratedComponent({
  featureOptions = ['Analytics', 'Reporting', 'Export to PDF', 'Dark Mode'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit
}: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const totalSteps = 5;

  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: ''
  });

  const [touched, setTouched] = useState({ name: false, email: false });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');

  // Validation
  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
  const isStep1Valid = formData.name.trim() !== '' && isEmailValid;
  const isStep2Valid = formData.satisfaction !== '';

  const handleNext = () => { if (currentStep < totalSteps) setCurrentStep(p => p + 1); };
  const handleBack = () => { if (currentStep > 1) setCurrentStep(p => p - 1); };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    setSubmitStatus('idle');
    try {
      if (onSubmit) await onSubmit(formData);
      else await new Promise(r => setTimeout(r, 1000));
      setSubmitStatus('success');
    } catch (e) {
      setSubmitStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  const satisfactionOptions = satisfactionLabels.map((l, i) => ({ value: String(i + 1), label: `${i + 1} - ${l}` }));

  const isNextDisabled = () => {
    if (currentStep === 1) return !isStep1Valid;
    if (currentStep === 2) return !isStep2Valid;
    return false;
  };

  if (submitStatus === 'success') {
    return (
      <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
        <Alert variant="success" title="Survey Submitted">Thank you for your feedback! Your responses have been recorded.</Alert>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Card padding="var(--ggui-spacing-8, 32px)" shadow="md" radius="lg">
        <Stack gap={24}>
          <Stack gap={12}>
            <Heading level={2}>Feedback Survey</Heading>
            <Stack direction="horizontal" justify="between" align="end">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {currentStep} of {totalSteps}</Text>
              <Box style={{ width: '120px' }}>
                <Progress value={(currentStep / totalSteps) * 100} />
              </Box>
            </Stack>
          </Stack>

          {submitStatus === 'error' && <Alert variant="error" title="Submission Failed">Please check your network and try again.</Alert>}

          <Box style={{ minHeight: '340px' }}>
            {currentStep === 1 && (
              <Stack gap={20} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Heading level={4}>Your Information</Heading>
                <Input id="name" label="Full Name" required placeholder="Jane Doe" value={formData.name} onChange={v => { setFormData(p => ({ ...p, name: v })); setTouched(p => ({ ...p, name: true })); }} error={touched.name && !formData.name.trim() ? 'Required' : undefined} />
                <Input id="email" label="Email Address" type="email" required placeholder="jane@example.com" value={formData.email} onChange={v => { setFormData(p => ({ ...p, email: v })); setTouched(p => ({ ...p, email: true })); }} error={touched.email && !isEmailValid ? 'Valid email required' : undefined} />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={20} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Heading level={4}>Satisfaction</Heading>
                <RadioGroup label="Experience Rating" options={satisfactionOptions} value={formData.satisfaction} onChange={v => setFormData(p => ({ ...p, satisfaction: v }))} />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={20} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Heading level={4}>Interests</Heading>
                <Stack gap={12}>
                  {featureOptions.map(f => (
                    <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={c => setFormData(p => ({ ...p, features: c ? [...p.features, f] : p.features.filter(x => x !== f) }))} />
                  ))}
                </Stack>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap={20} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Heading level={4}>Final Comments</Heading>
                <TextArea label="Anything else?" maxLength={500} showCount rows={6} value={formData.comments} onChange={v => setFormData(p => ({ ...p, comments: v }))} />
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap={16} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Heading level={4}>Review Your Answers</Heading>
                <Divider margin={0} />
                <Stack gap={12}>
                  <Box>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                    <Text>{formData.name}</Text>
                  </Box>
                  <Box>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                    <Text>{formData.email}</Text>
                  </Box>
                  <Box>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                    <Text>{satisfactionOptions.find(o => o.value === formData.satisfaction)?.label}</Text>
                  </Box>
                  <Box>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Features</Text>
                    <Text>{formData.features.join(', ') || 'No features selected'}</Text>
                  </Box>
                  <Box>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                    <Text>{formData.comments || 'No comments provided'}</Text>
                  </Box>
                </Stack>
              </Stack>
            )}
          </Box>

          <Divider margin={0} />

          <Stack direction="horizontal" justify="between">
            <Button variant="outline" disabled={currentStep === 1 || isSubmitting} onClick={handleBack}>Back</Button>
            {currentStep < totalSteps ? (
              <Button variant="primary" disabled={isNextDisabled()} onClick={handleNext}>Next</Button>
            ) : (
              <Button variant="primary" loading={isSubmitting} onClick={handleSubmit}>Submit Survey</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

