const CATEGORY_COLOR_MAP: Record<string, string> = {
  'diatomic nonmetal': 'var(--ggui-color-info-100, #cffafe)',
  'noble gas': 'var(--ggui-color-primary-100, #e0f2fe)',
  'alkali metal': 'var(--ggui-color-error-100, #fee2e2)',
  'alkaline earth metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'metalloid': 'var(--ggui-color-success-100, #dcfce7)',
  'polyatomic nonmetal': 'var(--ggui-color-info-200, #a5f3fc)',
  'post-transition metal': 'var(--ggui-color-success-200, #bbf7d0)',
  'transition metal': 'var(--ggui-color-neutral-100, #f3f4f6)',
  'lanthanide': 'var(--ggui-color-warning-200, #fde68a)',
  'actinide': 'var(--ggui-color-error-200, #fecaca)',
  'unknown': 'var(--ggui-color-neutral-50, #f9fafb)',
};

const getCategoryColor = (category?: string) => {
  if (!category) return CATEGORY_COLOR_MAP['unknown'];
  const normalized = category.toLowerCase();
  return CATEGORY_COLOR_MAP[normalized] || CATEGORY_COLOR_MAP['unknown'];
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return elements;
    return elements.map((el) => ({
      ...el,
      isMatch:
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query),
    }));
  }, [elements, searchQuery]);

  const uniqueCategories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap={32}>
        <Stack gap={16}>
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
            Interactive visualization of chemical elements. Select an element to view properties.
          </Text>
        </Stack>

        <Stack direction="horizontal" gap={24} align="center" wrap>
          <Box style={{ flex: '1 1 300px' }}>
             <SearchField
               value={searchQuery}
               onChange={setSearchQuery}
               placeholder="Search by name or symbol..."
             />
          </Box>
          <Stack direction="horizontal" gap={12} wrap style={{ flex: '1 1 400px' }}>
            {uniqueCategories.map((cat) => (
              <Stack key={cat} direction="horizontal" gap={8} align="center">
                <Box
                  borderRadius={4}
                  style={{ 
                    backgroundColor: getCategoryColor(cat), 
                    border: '1px solid var(--ggui-color-outline)',
                    width: '12px',
                    height: '12px'
                  }}
                />
                <Text variant="caption">{cat}</Text>
              </Stack>
            ))}
          </Stack>
        </Stack>

        <Box 
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1)',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-2)',
            background: 'var(--ggui-color-surfaceVariant)',
            borderRadius: 'var(--ggui-shape-radius-lg)',
            border: '1px solid var(--ggui-color-outlineVariant)',
          }}
        >
          {filteredElements.map((el) => {
            const isMatch = (el as any).isMatch !== false;
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            const bgColor = getCategoryColor(el.category);

            return (
              <button
                key={el.atomicNumber}
                onClick={() => setSelectedElement(el)}
                aria-label={el.name || el.symbol}
                style={{
                  gridColumn: el.col,
                  gridRow: el.row,
                  backgroundColor: bgColor,
                  border: isSelected
                    ? '2px solid var(--ggui-color-primary-600)'
                    : '1px solid var(--ggui-color-outline)',
                  borderRadius: 'var(--ggui-shape-radius-sm)',
                  aspectRatio: '1',
                  display: 'flex',
                  flexDirection: 'column',
                  padding: 'var(--ggui-spacing-1)',
                  cursor: 'pointer',
                  opacity: isMatch ? 1 : 0.2,
                  transition: 'all 200ms ease',
                  position: 'relative',
                  outline: 'none',
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                  transform: isSelected ? 'scale(1.05)' : 'none',
                  zIndex: isSelected ? 10 : 1,
                  color: 'var(--ggui-color-onSurface)',
                }}
              >
                <Text
                  variant="caption"
                  size="xs"
                  weight="medium"
                  style={{ position: 'absolute', top: 2, left: 4 }}
                >
                  {el.atomicNumber}
                </Text>
                <Box
                  style={{
                    display: 'flex',
                    flex: 1,
                    alignItems: 'center',
                    justifyContent: 'center',
                    pointerEvents: 'none'
                  }}
                >
                  <Text variant="bodyLarge" weight="bold">
                    {el.symbol}
                  </Text>
                </Box>
              </button>
            );
          })}
        </Box>

        {selectedElement && (
          <Card shadow="lg" padding={32} radius="xl">
            <Stack direction="horizontal" gap={48} align="center" wrap>
              <Box
                padding={24}
                borderRadius="xl"
                style={{
                  backgroundColor: getCategoryColor(selectedElement.category),
                  border: '1px solid var(--ggui-color-outline)',
                  minWidth: '160px',
                  textAlign: 'center',
                }}
              >
                <Stack gap={8} align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Atomic Number
                  </Text>
                  <Text variant="body" weight="bold" size="4xl">
                    {selectedElement.symbol}
                  </Text>
                  <Text variant="bodyLarge" weight="medium">
                    {selectedElement.atomicNumber}
                  </Text>
                </Stack>
              </Box>

              <Stack gap={24} style={{ flex: 1 }}>
                <Stack gap={4}>
                  <Heading level={2}>{selectedElement.name}</Heading>
                  <Box>
                    <Badge variant="primary" size="lg">
                      {selectedElement.category}
                    </Badge>
