import React, { useState, useEffect, useRef, useId } from 'react';
import { Card, Stack, Box, Text, Badge, Input, Button, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat title */
  title: string;
  /** Current user name */
  currentUser: string;
  /** Participant count badge */
  participantCount?: number;
  /** List of chat messages */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send message action. ActionId: sendMessage */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

/**
 * ChatInterface provides a conversation history and real-time message composition.
 * Features auto-scroll, consecutive message grouping, and optimistic state updates.
 */
export default function ChatInterface({ title, currentUser, participantCount = 0, messages = [], onSendMessage }: Props) {
  const [localMessages, setLocalMessages] = useState(messages);
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputId = useId();

  useEffect(() => {
    setLocalMessages(messages);
  }, [messages]);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [localMessages]);

  const handleSend = () => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const ts = new Date().toISOString();

    // Update local state for immediate feedback
    setLocalMessages((prev) => [...prev, { sender: currentUser, text: trimmed, timestamp: ts }]);

    // Wire the actionId: sendMessage (mapped here as onSendMessage)
    if (onSendMessage) {
      onSendMessage({ text: trimmed, timestamp: ts });
    }

    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card 
      shadow="md" 
      padding={0} 
      radius="lg" 
      style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        height: '600px', 
        background: 'var(--ggui-color-surface, #ffffff)', 
        border: '1px solid var(--ggui-color-outline, #d4d4d8)', 
        overflow: 'hidden' 
      }}
    >
      <Stack gap={0} style={{ height: '100%' }}>
        <Box paddingX={16} paddingY={12} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" gap={8} align="center">
              <Text variant="label" size="lg" weight="bold" color="var(--ggui-color-onSurface, #18181b)">{title}</Text>
              {participantCount > 0 && <Badge variant="primary" size="sm" pill>{participantCount}</Badge>}
            </Stack>
          </Stack>
        </Box>

        <Box padding={16} style={{ flex: 1, overflowY: 'auto' }}>
          <Stack gap={12}>
            {localMessages.map((msg, index) => {
              const isMe = msg.sender === currentUser;
              const isSeq = index > 0 && localMessages[index - 1].sender === msg.sender;
              const timeStr = msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '';

              return (
                <Stack key={`msg-${index}`} gap={4} align={isMe ? 'end' : 'start'} style={{ marginTop: isSeq ? '-8px' : '4px' }}>
                  {!isSeq && !isMe && msg.sender && (
                    <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">{msg.sender}</Text>
                  )}
                  <Stack direction="horizontal" gap={8} align="end" style={{ maxWidth: '85%' }}>
                    {isMe && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ opacity: 0.6, fontSize: '10px' }}>{timeStr}</Text>}
                    <Box 
                      paddingX={12} 
                      paddingY={8} 
                      background={isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'} 
                      borderRadius="var(--ggui-shape-radius-lg, 12px)" 
                      style={{ 
