                    </Box>
                    {!isMe && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ opacity: 0.6, fontSize: '10px' }}>{timeStr}</Text>}
                  </Stack>
                </Stack>
              );
            })}
            <div ref={messagesEndRef} aria-hidden="true" style={{ height: '1px' }} />
          </Stack>
        </Box>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

