              <Input label="Message" id={inputId} value={inputValue} onChange={(val: string) => setInputValue(val)} placeholder="Type a message..." size="md" onKeyDown={handleKeyDown} autoComplete="off" />
            </Box>
            <Button variant="primary" size="md" onClick={handleSend} disabled={!inputValue.trim()} aria-label="Send">Send</Button>
          </Stack>
