import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Card,
  Spinner,
  Icon,
  Box
} from '@ggui-ai/design/primitives';
import { Tag } from '@ggui-ai/design/components';
import { CardGrid } from '@ggui-ai/design/compositions';

interface StockData {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: StockData[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Stock Ticker Dashboard
 * Displays a responsive grid of stock price cards with live updates via agent data stream.
 */
export default function StockTickerDashboard({
  stocks = [],
  lastUpdated = '',
}: Props) {
  // State for live data initialization
  const [liveStocks, setLiveStocks] = useState<StockData[]>(stocks || []);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState(!stocks || stocks.length === 0);

  // Interaction: Stream Contract
  useEffect(() => {
    // We use the global addEventListener to catch ggui:agent-data events
    // dispatched by the platform's agent to synchronize prices.
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data && data.stocks) {
        setLiveStocks(data.stocks);
        if (data.lastUpdated) {
          setLiveLastUpdated(data.lastUpdated);
        }
        setIsConnecting(false);
      }
    };

    addEventListener('ggui:agent-data', handleAgentData);
    return () => removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  // Format the timestamp for display
  const formattedTime = liveLastUpdated
    ? new Date(liveLastUpdated).toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      })
    : '--:--:--';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4, 16px)">
      <Stack gap={24} aria-live="polite">

        {/* Dashboard Header */}
        <Stack direction="horizontal" justify="between" align="center" wrap gap={12}>
          <Stack gap={4}>
            <Heading level={2}>Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Live updates from indices and symbols
            </Text>
          </Stack>

          <Stack align="end" gap={0}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              LAST UPDATED
            </Text>
            <Text variant="bodySmall" weight="medium">
              {formattedTime}
            </Text>
          </Stack>
        </Stack>

        {/* Loading State or Data Grid */}
        {isConnecting ? (
          <Box
            paddingY={64}
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            <Spinner size={32} />
            <Text weight="medium">Connecting to stream...</Text>
          </Box>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={20} aria-label="Stock grid">
            {liveStocks.map((stock) => {
              const symbol = stock.symbol || '---';
              const name = stock.name || 'Unknown';
              const price = stock.price || 0;
              const isPositive = (stock.change || 0) >= 0;
              const absChange = Math.abs(stock.change || 0).toFixed(2);
              const absPercent = Math.abs(stock.changePercent || 0).toFixed(2);

              return (
                <Card
                  key={symbol}
                  padding={16}
                  radius="lg"
                  aria-label={`${symbol}, ${name}. Price: $${price.toFixed(2)}`}
                >
                  <Stack gap={12}>
                    {/* Identification */}
                    <Stack direction="horizontal" justify="between" align="start">
                      <Text weight="bold" size="xl">
                        {symbol}
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        truncate
                        style={{ maxWidth: '120px', textAlign: 'right' }}
                      >
                        {name}
                      </Text>
                    </Stack>

                    {/* Price Display */}
                    <Text size="3xl" weight="semibold">
                      ${price.toFixed(2)}
                    </Text>

                    {/* Metrics Tag */}
                    <Stack direction="horizontal" justify="end">
                      <Tag
                        variant={isPositive ? 'success' : 'error'}
                        size="md"
                        icon={
                          <Icon
                            name={isPositive ? 'chevron-up' : 'chevron-down'}
                            size={12}
                          />
                        }
                      >
                        {isPositive ? '+' : '-'}${absChange} ({absPercent}%)
                      </Tag>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

