  Input,
  Select,
  Toggle,
  Button,
  Progress,
  Divider,
  Badge
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  onComplete: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function OnboardingWizard({
  avatarOptions,
  roleOptions,
  initialProfile = {},
  onComplete
}: Props) {
  const [step, setStep] = useState(1);
  const totalSteps = 3;

  const [formData, setFormData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || (avatarOptions?.[0] || ''),
    role: initialProfile.role || '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme || 'light'
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  const validate = (s: number) => {
    const e: Record<string, string> = {};
    if (s === 1) {
      if (!formData.name.trim()) e.name = 'Required';
      if (!formData.email.trim()) e.email = 'Required';
      else if (!formData.email.includes('@')) e.email = 'Invalid';
    } else if (s === 2) {
      if (!formData.role) e.role = 'Required';
    }
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const update = (k: string, v: any) => {
    setFormData(prev => ({ ...prev, [k]: v }));
    if (errors[k]) {
      const ne = { ...errors };
      delete ne[k];
      setErrors(ne);
    }
  };

  const roleOpts = roleOptions.map(r => ({ value: r, label: r }));

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Card padding="var(--ggui-spacing-8, 32px)" shadow="md" radius="lg">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={3}>
                {step === 1 ? 'Profile' : step === 2 ? 'Preferences' : 'Review'}
              </Heading>
              <Text variant="bodySmall">Step {step} of 3</Text>
            </Stack>
            <Progress value={(step / 3) * 100} variant="default" size="md" />
          </Stack>

          <Divider margin={0} />

          <div style={{ display: step === 1 ? 'block' : 'none', animation: 'ggui-fadeIn 200ms ease-out' }}>
            <Stack gap="var(--ggui-spacing-6, 24px)">
              <Input label="Name" placeholder="Jane Doe" value={formData.name} onChange={v => update('name', v)} required error={errors.name} />
              <Input label="Email" type="email" placeholder="jane@example.com" value={formData.email} onChange={v => update('email', v)} required error={errors.email} />
              <Stack gap="var(--ggui-spacing-2, 8px)">
                <Text variant="label">Avatar</Text>
                <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
                  {avatarOptions && avatarOptions.map(a => (
                    <button key={a} type="button" onClick={() => update('avatar', a)} style={{ background: formData.avatar === a ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'transparent', border: `2px solid ${formData.avatar === a ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`, borderRadius: '50%', width: '56px', height: '56px', fontSize: '24px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{a}</button>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          </div>

          <div style={{ display: step === 2 ? 'block' : 'none', animation: 'ggui-fadeIn 200ms ease-out' }}>
            <Stack gap="var(--ggui-spacing-6, 24px)">
              <Select label="Role" value={formData.role} onChange={v => update('role', v)} options={roleOpts} required error={errors.role} />
              <Toggle label="Notifications" checked={formData.emailNotifications} onChange={v => update('emailNotifications', v)} />
              <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={v => update('theme', v ? 'dark' : 'light')} />
            </Stack>
          </div>

          <div style={{ display: step === 3 ? 'block' : 'none', animation: 'ggui-fadeIn 200ms ease-out' }}>
            <Stack gap="var(--ggui-spacing-6, 24px)">
              <Text variant="body">Please review your selections.</Text>
              <Box padding="var(--ggui-spacing-6, 24px)" borderRadius="var(--ggui-shape-radius-lg, 12px)" style={{ border: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
                <Stack gap="var(--ggui-spacing-6, 24px)">
                  <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4, 16px)">
                    <div style={{ fontSize: '32px', padding: '12px', background: 'var(--ggui-color-surfaceVariant, #f4f4f5)', borderRadius: '50%' }}>{formData.avatar}</div>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="label" weight="semibold">{formData.name}</Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
                    </Stack>
                  </Stack>
                  <Divider margin={0} />
                  <Stack direction="horizontal" justify="between" align="center"><Text variant="bodySmall">Role</Text><Badge variant="primary">{formData.role}</Badge></Stack>
                </Stack>
              </Box>
            </Stack>
          </div>

          <Stack direction="horizontal" justify="between" align="center">
            <Box style={{ visibility: step > 1 ? 'visible' : 'hidden' }}><Button variant="ghost" onClick={() => setStep(step - 1)}>Back</Button></Box>
            {step < 3 ? <Button variant="primary" onClick={() => { if (validate(step)) setStep(step + 1); }}>Next</Button> : <Button variant="primary" onClick={() => { if (validate(1) && validate(2)) onComplete(formData); }}>Complete Setup</Button>}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

