/**
 * WeatherCard Component
 *
 * A reusable weather information card displaying current conditions,
 * temperature, humidity, wind speed, and a 5-day forecast.
 *
 * Props Contract:
 * - city: string (required)
 * - temperature: number (required)
 * - condition: string (required)
 * - humidity: number (required)
 * - windSpeed: number (required)
 * - forecast: Array<{day?, icon?, high?, low?}> (required)
 * - unit?: string (optional, default "F")
 *
 * All data is passed via props. No internal state or data fetching.
 * Static display component with clean visual hierarchy.
 */

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getConditionBadgeVariant = (
  condition: string
): 'primary' | 'success' | 'warning' | 'error' | 'default' => {
  const cond = condition.toLowerCase();
  if (cond.includes('sunny') || cond.includes('clear')) return 'primary';
  if (cond.includes('cloud')) return 'default';
  if (cond.includes('rain')) return 'warning';
  if (cond.includes('storm') || cond.includes('thunder')) return 'error';
  return 'default';
};

const getWeatherEmoji = (condition: string): string => {
  const cond = condition.toLowerCase();
  if (cond.includes('sunny')) return '☀️';
  if (cond.includes('cloud')) return '☁️';
  if (cond.includes('rain')) return '🌧️';
  if (cond.includes('snow')) return '❄️';
  if (cond.includes('wind')) return '💨';
  return '⛅';
};

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'F',
  forecast,
}: Props) {
  const conditionEmoji = getWeatherEmoji(condition);
  const badgeVariant = getConditionBadgeVariant(condition);
  const todayDate = new Date().toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
  });

  return (
    <Card
      shadow="md"
      border={true}
      radius="lg"
      padding={24}
      style={{
        backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        {/* Header: City & Temperature */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack direction="vertical" gap={4}>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {todayDate}
            </Text>
          </Stack>
          <Text
            size="4xl"
            weight="bold"
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {temperature}°{unit}
          </Text>
        </Stack>

        {/* Condition: Icon & Text */}
        <Stack direction="horizontal" gap={12} align="center">
          <Text size="3xl">{conditionEmoji}</Text>
          <Stack direction="vertical" gap={4}>
            <Text
              size="lg"
              weight="normal"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {condition}
            </Text>
            <Badge
              variant={badgeVariant}
              size="sm"
              pill={true}
            >
              {condition}
            </Badge>
          </Stack>
        </Stack>

        {/* Humidity & Wind: Side-by-Side Stats */}
        <Stack
          direction="horizontal"
          gap={24}
          justify="around"
          style={{ marginTop: '8px' }}
        >
          {/* Humidity */}
          <Stack direction="vertical" align="center" gap={4}>
            <Text
              size="xl"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
            <Text
              size="xs"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" align="center" gap={4}>
            <Text
              size="xl"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} mph
            </Text>
            <Text
              size="xs"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
          </Stack>
        </Stack>

        {/* Divider */}
        <Divider
          orientation="horizontal"
          margin={16}
          color="var(--ggui-color-outline, #d4d4d8)"
        />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" gap={8} wrap={true} justify="between">
          {forecast.map((day, index) => (
            <Box
              key={index}
              padding={12}
