'use client';

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Progress,
  Heading,
  Text,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Button,
  Alert,
  Divider,
  Box,
  Badge,
} from '@ggui-ai/design/primitives';

interface SurveyAnswers {
  name: string;
  email: string;
  satisfactionRating: number;
  featureInterests: string[];
  comments: string;
}

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (answers: SurveyAnswers) => void | Promise<void>;
}

export default function GeneratedComponent({
  featureOptions = [],
  satisfactionLabels = [
    'Very Unsatisfied',
    'Unsatisfied',
    'Neutral',
    'Satisfied',
    'Very Satisfied',
  ],
  onSubmit,
}: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const TOTAL_STEPS = 5;

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [nameBlurred, setNameBlurred] = useState(false);
  const [emailBlurred, setEmailBlurred] = useState(false);

  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);
  const [submitError, setSubmitError] = useState('');

  const validateName = (value: string): string => {
    if (!value || !value.trim()) return 'Name is required';
    return '';
  };

  const validateEmail = (value: string): string => {
    if (!value) return 'Email is required';
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(value)) {
      return 'Please enter a valid email address';
    }
    return '';
  };

  const isStep1Valid = (): boolean => {
    return !validateName(name) && !validateEmail(email);
  };

  const handleNameChange = (value: string) => {
    setName(value);
    if (nameBlurred) {
      setNameError(validateName(value));
    }
  };

  const handleEmailChange = (value: string) => {
    setEmail(value);
    if (emailBlurred) {
      setEmailError(validateEmail(value));
    }
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    if (checked) {
      setSelectedFeatures([...selectedFeatures, feature]);
    } else {
      setSelectedFeatures(selectedFeatures.filter((f) => f !== feature));
    }
  };

  const handleNext = () => {
    if (currentStep === 1) {
      const nErr = validateName(name);
      const eErr = validateEmail(email);
      setNameError(nErr);
      setEmailError(eErr);
      if (nErr || eErr) return;
    }
    if (currentStep < TOTAL_STEPS) {
      setCurrentStep(currentStep + 1);
      setSubmitSuccess(false);
      setSubmitError('');
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setSubmitSuccess(false);
      setSubmitError('');
    }
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    setSubmitError('');
    setSubmitSuccess(false);

    try {
      const answers: SurveyAnswers = {
        name,
        email,
        satisfactionRating: parseInt(satisfactionRating, 10),
        featureInterests: selectedFeatures,
        comments,
      };

      if (onSubmit) {
        await onSubmit(answers);
      }

      setSubmitSuccess(true);
    } catch (error) {
      const msg =
        error instanceof Error ? error.message : 'Failed to submit survey';
      setSubmitError(msg);
    } finally {
      setIsSubmitting(false);
    }
  };

  const satisfactionOptions = satisfactionLabels.map((label, idx) => ({
    value: String(idx),
    label,
  }));

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
            Step {currentStep} of {TOTAL_STEPS}
          </Text>
          <Progress
            value={currentStep}
            max={TOTAL_STEPS}
            variant="default"
            size="md"
          />
        </Stack>

        <Card shadow="md" radius="lg" padding={32}>
          <Stack gap={20}>
            {currentStep === 1 && (
              <>
                <Stack gap={8}>
                  <Heading level={2} color="var(--ggui-color-primary-700, #0369a1)">
                    Your Information
                  </Heading>
                  <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                    Let&apos;s start with your basic details
                  </Text>
                </Stack>
                <Input
                  label="Name"
                  placeholder="Enter your full name"
                  value={name}
                  onChange={handleNameChange}
                  type="text"
                  error={nameBlurred ? nameError : ''}
                  required
                  size="md"
                />
                <Input
                  label="Email"
                  placeholder="Enter your email address"
                  value={email}
                  onChange={handleEmailChange}
                  type="email"
                  error={emailBlurred ? emailError : ''}
                  required
                  size="md"
                />
              </>
            )}

            {currentStep === 2 && (
              <>
                <Stack gap={8}>
                  <Heading level={2} color="var(--ggui-color-primary-700, #0369a1)">
                    How satisfied are you?
                  </Heading>
                  <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                    Rate your experience on a scale from 1 to 5
                  </Text>
                </Stack>
                <RadioGroup
                  label="Satisfaction Rating"
                  value={satisfactionRating}
                  onChange={setSatisfactionRating}
                  options={satisfactionOptions}
                  direction="horizontal"
                />
              </>
            )}

            {currentStep === 3 && (
              <>
                <Stack gap={8}>
                  <Heading level={2} color="var(--ggui-color-primary-700, #0369a1)">
                    What features interest you?
                  </Heading>
                  <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                    Select all that apply (optional)
                  </Text>
                </Stack>
                <Stack gap={12}>
                  {(featureOptions || []).length > 0 ? (
                    featureOptions.map((feature, idx) => (
                      <Checkbox
                        key={`feature-${idx}`}
                        label={feature}
                        checked={selectedFeatures.includes(feature)}
                        onChange={(c) => handleFeatureToggle(feature, c)}
                      />
                    ))
                  ) : (
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-neutral-500, #6b7280)"
                    >
                      No features available
                    </Text>
                  )}
                </Stack>
              </>
            )}

            {currentStep === 4 && (
              <>
                <Stack gap={8}>
                  <Heading level={2} color="var(--ggui-color-primary-700, #0369a1)">
                    Any additional comments?
                  </Heading>
                  <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                    Share your thoughts (optional, max 500 characters)
                  </Text>
                </Stack>
                <TextArea
                  label="Comments"
                  placeholder="Enter any additional feedback..."
                  value={comments}
                  onChange={setComments}
                  rows={4}
                  maxLength={500}
                  showCount
                />
              </>
            )}

            {currentStep === 5 && (
              <>
                <Stack gap={8}>
                  <Heading level={2} color="var(--ggui-color-primary-700, #0369a1)">
                    Review Your Answers
                  </Heading>
                  <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                    Please verify everything is correct before submitting
                  </Text>
                </Stack>
                <Stack gap={12}>
                  <Box
                    padding={12}
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                    borderRadius={8}
                  >
                    <Stack direction="horizontal" gap={12} align="center">
                      <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">
                        Name:
                      </Text>
                      <Text variant="body">{name}</Text>
                    </Stack>
                  </Box>
                  <Box
                    padding={12}
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                    borderRadius={8}
                  >
                    <Stack direction="horizontal" gap={12} align="center">
                      <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">
                        Email:
                      </Text>
                      <Text variant="body">{email}</Text>
                    </Stack>
                  </Box>
                  <Box
                    padding={12}
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                    borderRadius={8}
                  >
                    <Stack direction="horizontal" gap={12} align="center">
                      <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">
                        Satisfaction:
                      </Text>
                      <Text variant="body">
                        {satisfactionRating !== ''
                          ? satisfactionLabels[parseInt(satisfactionRating, 10)]
                          : 'Not selected'}
                      </Text>
                    </Stack>
                  </Box>
                  {selectedFeatures.length > 0 && (
                    <Box
                      padding={12}
                      background="var(--ggui-color-primary-50, #f0f9ff)"
                      borderRadius={8}
                    >
                      <Stack gap={8}>
                        <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">
                          Features Interested In:
                        </Text>
                        <Stack direction="horizontal" gap={8} wrap>
                          {selectedFeatures.map((f) => (
                            <Badge key={f} variant="primary" size="sm" pill>
                              {f}
                            </Badge>
                          ))}
                        </Stack>
                      </Stack>
                    </Box>
                  )}
                  {comments && (
                    <Box
                      padding={12}
                      background="var(--ggui-color-primary-50, #f0f9ff)"
                      borderRadius={8}
                    >
                      <Stack gap={4}>
                        <Text variant="label" weight="semibold" color="var(--ggui-color-primary-700, #0369a1)">
                          Comments:
                        </Text>
                        <Text variant="body">{comments}</Text>
                      </Stack>
                    </Box>
                  )}
                </Stack>
                <Divider margin={12} />
                {submitSuccess && (
                  <Alert
                    variant="success"
                    title="Survey Submitted"
                    closable
                    onClose={() => setSubmitSuccess(false)}
                  >
                    Thank you! Your survey has been submitted successfully.
                  </Alert>
                )}
                {submitError && (
                  <Alert
                    variant="error"
                    title="Submission Failed"
                    closable
                    onClose={() => setSubmitError('')}
                  >
                    {submitError}
                  </Alert>
                )}
              </>
            )}
          </Stack>
        </Card>

        <Stack direction="horizontal" gap={12} justify="between" align="center">
          <Button
            variant="ghost"
            size="md"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>

          {currentStep < TOTAL_STEPS ? (
            <Button
              variant="primary"
              size="md"
              onClick={handleNext}
              disabled={currentStep === 1 && !isStep1Valid()}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              size="md"
              onClick={handleSubmit}
              disabled={isSubmitting}
              loading={isSubmitting}
            >
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Heading,
  Input,
  Box,
  Card,
  Text,
  Badge,
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: ElementData[];
}

const categoryColorMap: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'alkaline-earth-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'transition-metal': 'var(--ggui-color-info-100, #cffafe)',
  'lanthanide': 'var(--ggui-color-success-100, #dcfce7)',
  'actinide': 'var(--ggui-color-error-100, #fee2e2)',
  'nonmetal': 'var(--ggui-color-neutral-100, #f3f4f6)',
  'halogen': 'var(--ggui-color-warning-100, #fef3c7)',
  'noble-gas': 'var(--ggui-color-primary-50, #f0f9ff)',
  'metalloid': 'var(--ggui-color-neutral-100, #f3f4f6)',
  'unknown': 'var(--ggui-color-neutral-200, #e5e7eb)',
};

function getCategoryBadgeVariant(
  category?: string
): 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info' {
  switch (category) {
    case 'alkali-metal':
    case 'halogen':
      return 'warning';
    case 'alkaline-earth-metal':
    case 'noble-gas':
      return 'primary';
    case 'transition-metal':
      return 'info';
    case 'lanthanide':
      return 'success';
    case 'actinide':
      return 'error';
    default:
      return 'default';
  }
}

export default function PeriodicTable({ elements }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElementIndex, setSelectedElementIndex] = useState<number | null>(
    null
  );

  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) {
      return elements;
    }
    const query = searchQuery.toLowerCase();
    return elements.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(query) || symbol.includes(query);
    });
  }, [elements, searchQuery]);

  const selectedElement =
    selectedElementIndex !== null && selectedElementIndex < elements.length
      ? elements[selectedElementIndex]
      : null;

  const uniqueCategories = Array.from(
    new Set(elements.map((el) => el.category ?? 'unknown'))
  ).sort();

  const handleElementClick = (index: number) => {
    setSelectedElementIndex(index);
  };

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack direction="vertical" gap={16}>
        <Heading level={1} align="center">
          Periodic Table of Elements
        </Heading>

        <Input
          label="Search elements"
          placeholder="Enter element name or symbol..."
          value={searchQuery}
          onChange={setSearchQuery}
          type="search"
        />

        <Stack direction="vertical" gap={8}>
          <Heading level={4}>Categories</Heading>
          <Stack
            direction="horizontal"
            gap={8}
            wrap={true}
            align="center"
          >
            {uniqueCategories.map((category) => (
              <Badge
                key={category}
                variant={getCategoryBadgeVariant(category)}
                size="sm"
              >
                {category}
              </Badge>
            ))}
          </Stack>
        </Stack>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2, 8px)',
            padding: 'var(--ggui-spacing-4, 16px)',
            backgroundColor: 'var(--ggui-color-surface, #fafafa)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          } as React.CSSProperties}
        >
          {filteredElements.map((element) => {
            if (element.row === undefined || element.col === undefined) {
              return null;
            }

            const elementIndex = elements.indexOf(element);
            const isSelected =
              selectedElementIndex !== null &&
              elementIndex === selectedElementIndex;

            return (
              <div
                key={`${element.symbol}-${element.atomicNumber}`}
                style={{
                  gridRow: element.row,
                  gridColumn: element.col,
                  cursor: 'pointer',
                  transition:
                    'box-shadow 200ms ease-in-out, transform 100ms ease-in-out',
                  transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                  boxShadow: isSelected
                    ? 'var(--ggui-shape-shadow-lg, 0 10px 15px -3px rgba(0,0,0,0.1))'
                    : 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                  padding: 'var(--ggui-spacing-3, 12px)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  backgroundColor: categoryColorMap[element.category ?? 'unknown'],
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  position: 'relative',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 'var(--ggui-spacing-1, 4px)',
                } as React.CSSProperties}
                onClick={() => handleElementClick(elementIndex)}
                role="button"
                tabIndex={0}
                aria-pressed={isSelected}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' || e.key === ' ') {
                    e.preventDefault();
                    handleElementClick(elementIndex);
                  }
                }}
              >
                {element.atomicNumber !== undefined && (
                  <span
                    style={{
                      position: 'absolute',
                      top: 'var(--ggui-spacing-1, 4px)',
                      left: 'var(--ggui-spacing-1, 4px)',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                      fontWeight: 'normal',
                    }}
                  >
                    {element.atomicNumber}
                  </span>
                )}

                <Text
                  size="2xl"
                  weight="bold"
                  color="var(--ggui-color-onSurface, #18181b)"
                  align="center"
                  as="div"
                >
                  {element.symbol ?? '?'}
                </Text>

                {element.name && (
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    align="center"
                    as="div"
                    size="xs"
                  >
                    {element.name}
                  </Text>
                )}
              </div>
            );
          })}
        </Box>

        <Card
          shadow="md"
          padding={20}
          radius="lg"
          border={true}
          style={{ marginTop: 'var(--ggui-spacing-4, 16px)' } as React.CSSProperties}
        >
          {selectedElement ? (
            <Stack direction="vertical" gap={12}>
              <Heading level={3}>{selectedElement.name ?? 'Unknown Element'}</Heading>

              <Stack direction="vertical" gap={8}>
                <Stack direction="horizontal" gap={12} align="center">
                  <Text variant="label" weight="semibold">
                    Symbol:
                  </Text>
                  <Text>{selectedElement.symbol ?? 'N/A'}</Text>
                </Stack>

                <Stack direction="horizontal" gap={12} align="center">
                  <Text variant="label" weight="semibold">
                    Atomic Number:
                  </Text>
                  <Text>
                    {selectedElement.atomicNumber !== undefined
                      ? selectedElement.atomicNumber
                      : 'N/A'}
                  </Text>
                </Stack>

                <Stack direction="horizontal" gap={12} align="center">
                  <Text variant="label" weight="semibold">
                    Atomic Weight:
                  </Text>
                  <Text>
                    {selectedElement.atomicWeight !== undefined
                      ? selectedElement.atomicWeight.toFixed(2)
                      : 'N/A'}
                  </Text>
                </Stack>

                <Stack direction="horizontal" gap={12} align="center">
                  <Text variant="label" weight="semibold">
                    Category:
                  </Text>
                  <Badge variant={getCategoryBadgeVariant(selectedElement.category)}>
                    {selectedElement.category ?? 'Unknown'}
                  </Badge>
                </Stack>
              </Stack>
            </Stack>
          ) : (
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              align="center"
            >
              Click an element to view details
            </Text>
          )}
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useRef, useEffect, useState } from 'react';
import {
  Card,
  Stack,
  Heading,
  Badge,
  Box,
  Text,
  Input,
  Button,
  Spacer,
} from '@ggui-ai/design/primitives';

interface ChatMessage {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface MessageGroup {
  sender?: string;
  messageList: ChatMessage[];
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: ChatMessage[];
  /** Callback for sending messages via sendMessage action */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { title, currentUser, participantCount, messages, onSendMessage } = props;
  const [messageInput, setMessageInput] = useState('');
  const messageListRef = useRef<HTMLDivElement>(null);
  const lastMessageRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    if (lastMessageRef.current) {
      lastMessageRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  // Group consecutive messages by sender
  const groupedMessages: MessageGroup[] = React.useMemo(() => {
    const groups: MessageGroup[] = [];
    let currentGroup: MessageGroup | null = null;

    for (let i = 0; i < messages.length; i++) {
      const msg = messages[i];
      if (!currentGroup || msg.sender !== currentGroup.sender) {
        if (currentGroup) {
          groups.push(currentGroup);
        }
        currentGroup = { sender: msg.sender, messageList: [msg] };
      } else {
        currentGroup.messageList.push(msg);
      }
    }

    if (currentGroup) {
      groups.push(currentGroup);
    }

    return groups;
  }, [messages]);

  // Handle send message - dispatch sendMessage action
  const handleSend = () => {
    const trimmedText = messageInput.trim();
    if (trimmedText.length === 0) return;

    const timestamp = new Date().toISOString();

    // Wire sendMessage action
    if (onSendMessage) {
      onSendMessage({ text: trimmedText, timestamp });
    }

    setMessageInput('');
  };

  // Format timestamp to HH:MM
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        hour12: true,
      });
    } catch {
      return '';
    }
  };

  return (
    <Card shadow="md" padding={0} border radius="lg">
      <Stack direction="vertical" gap={0} style={{ height: '100%', display: 'flex' }}>
        {/* Header */}
        <Stack
          direction="horizontal"
          gap={12}
          align="center"
          justify="between"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack direction="horizontal" gap={12} align="center">
            <Heading level={5}>{title}</Heading>
            {participantCount !== undefined && (
              <Badge variant="primary" size="sm" pill>
                {participantCount}
              </Badge>
            )}
          </Stack>
          <Spacer size="flex" />
        </Stack>

        {/* Message List - Scrollable Area */}
        <div
          ref={messageListRef}
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            backgroundColor: 'var(--ggui-color-surface, #fafafa)',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-2, 8px)',
          }}
        >
          {groupedMessages.length === 0 ? (
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              align="center"
              as="div"
              style={{ margin: 'auto' }}
            >
              No messages yet. Start the conversation!
            </Text>
          ) : (
            <>
              {groupedMessages.map((group, groupIdx) => (
                <Stack key={groupIdx} direction="vertical" gap={4} style={{ marginBottom: '4px' }}>
                  {/* Sender name label - only for non-current-user messages */}
                  {group.sender && group.sender !== currentUser && (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      weight="semibold"
                    >
                      {group.sender}
                    </Text>
                  )}

                  {/* Messages in group */}
                  {group.messageList.map((msg, msgIdx) => {
                    const isCurrentUser = msg.sender === currentUser;
                    const isLastMessage =
                      groupIdx === groupedMessages.length - 1 &&
                      msgIdx === group.messageList.length - 1;

                    return (
                      <div
                        key={msgIdx}
                        ref={isLastMessage ? lastMessageRef : null}
                        style={{
                          display: 'flex',
                          justifyContent: isCurrentUser ? 'flex-end' : 'flex-start',
                          gap: 'var(--ggui-spacing-2, 8px)',
                        }}
                      >
                        <Box
                          background={
                            isCurrentUser
                              ? 'var(--ggui-color-primary-600, #0284c7)'
                              : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                          }
                          borderRadius="var(--ggui-shape-radius-lg, 12px)"
                          padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                          style={{
                            maxWidth: '60%',
                            wordWrap: 'break-word',
                          }}
                        >
                          <Stack direction="vertical" gap={4}>
                            <Text
                              variant="body"
                              color={
                                isCurrentUser
                                  ? 'var(--ggui-color-neutral-50, #ffffff)'
                                  : 'var(--ggui-color-onSurface, #18181b)'
                              }
                              as="span"
                            >
                              {msg.text || ''}
                            </Text>
                            <Text
                              variant="caption"
                              color={
                                isCurrentUser
                                  ? 'var(--ggui-color-neutral-100, #f3f4f6)'
                                  : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                              }
                              as="span"
                            >
                              {formatTime(msg.timestamp)}
                            </Text>
                          </Stack>
                        </Box>
                      </div>
                    );
                  })}
                </Stack>
              ))}
            </>
          )}
        </div>

        {/* Input Area */}
        <Stack
          direction="horizontal"
          gap={8}
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Input
            label="Message"
            placeholder="Type a message..."
            value={messageInput}
            onChange={setMessageInput}
            size="md"
            style={{ flex: 1 }}
          />
          <Button
            variant="primary"
            size="md"
            disabled={messageInput.trim().length === 0}
            onClick={handleSend}
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Heading,
  Text,
  Divider,
  Card,
  Box,
  Spinner,
  Alert,
} from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = undefined,
}: Props) {
  const [displayStocks, setDisplayStocks] = useState<Stock[]>(stocks);
  const [displayTimestamp, setDisplayTimestamp] = useState<string | undefined>(
    lastUpdated
  );
  const [isConnecting, setIsConnecting] = useState<boolean>(!lastUpdated);
  const [connectionError, setConnectionError] = useState<string | undefined>();

  // Update display when props change (handles initial load and prop-driven updates)
  useEffect(() => {
    if (stocks && stocks.length > 0) {
      setDisplayStocks(stocks);
      setDisplayTimestamp(lastUpdated);
      setIsConnecting(false);
      setConnectionError(undefined);
    }
  }, [stocks, lastUpdated]);

  // Format timestamp for display
  const formatTimestamp = (timestamp?: string): string => {
    if (!timestamp) return 'Connecting...';
    try {
      return new Date(timestamp).toLocaleString();
    } catch {
      return 'Invalid date';
    }
  };

  // Determine color based on change
  const getChangeColor = (change?: number): string => {
    if (change === undefined || change === 0) {
      return 'var(--ggui-color-onSurfaceVariant, #52525b)';
    }
    return change > 0
      ? 'var(--ggui-color-success-600, #16a34a)'
      : 'var(--ggui-color-error-600, #dc2626)';
  };

  const getBorderColor = (change?: number): string => {
    if (change === undefined || change === 0) {
      return 'var(--ggui-color-outline, #d4d4d8)';
    }
    return change > 0
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)';
  };

  // Render connecting state
  if (isConnecting && displayStocks.length === 0) {
    return (
      <Container maxWidth="2xl" padding={24}>
        <Stack gap={16}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading
              level={2}
              color="var(--ggui-color-onSurface, #18181b)"
            >
              Market Watch
            </Heading>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Last Updated: {formatTimestamp()}
            </Text>
          </Stack>
          <Divider margin={16} />
          <Stack gap={24} align="center" justify="center">
            <Spinner
              size={32}
              color="var(--ggui-color-primary-600, #0284c7)"
            />
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              align="center"
            >
              Connecting to live market data...
            </Text>
          </Stack>
        </Stack>
      </Container>
    );
  }

  // Render error state
  if (connectionError) {
    return (
      <Container maxWidth="2xl" padding={24}>
        <Stack gap={16}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading
              level={2}
              color="var(--ggui-color-onSurface, #18181b)"
            >
              Market Watch
            </Heading>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Last Updated: {formatTimestamp(displayTimestamp)}
            </Text>
          </Stack>
          <Divider margin={16} />
          <Alert
            variant="error"
            title="Connection Error"
            closable
            onClose={() => setConnectionError(undefined)}
          >
            {connectionError}
          </Alert>
        </Stack>
      </Container>
    );
  }

  // Render empty state
  if (displayStocks.length === 0) {
    return (
      <Container maxWidth="2xl" padding={24}>
        <Stack gap={16}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading
              level={2}
              color="var(--ggui-color-onSurface, #18181b)"
            >
              Market Watch
            </Heading>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Last Updated: {formatTimestamp(displayTimestamp)}
            </Text>
          </Stack>
          <Divider margin={16} />
          <Text
            variant="body"
            align="center"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            No stocks to display
          </Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={16}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading
            level={2}
            color="var(--ggui-color-onSurface, #18181b)"
          >
            Market Watch
          </Heading>
          <Text
            variant="caption"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            Last Updated: {formatTimestamp(displayTimestamp)}
          </Text>
        </Stack>

        <Divider margin={16} />

        {/* Responsive Stock Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns:
              'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
            width: '100%',
          }}
        >
          {displayStocks.map((stock, index) => {
            const change = stock.change ?? 0;
            const changeColor = getChangeColor(change);
            const borderColor = getBorderColor(change);
            const isPositive = change > 0;
            const isNegative = change < 0;

            return (
              <Box
                key={`${stock.symbol || 'stock'}-${index}`}
                style={{
                  borderLeft: `4px solid ${borderColor}`,
                  borderRadius:
                    'var(--ggui-shape-radius-lg, 12px)',
                }}
              >
                <Card
                  shadow="md"
                  padding={20}
                  radius="lg"
                  border={true}
                  style={{
                    height: '100%',
                  }}
                >
                  <Stack gap={12}>
                    {/* Ticker Symbol */}
                    <Heading
                      level={4}
                      color={changeColor}
                      style={{
                        fontWeight: 'var(--ggui-font-weight-bold, 700)',
                        fontSize: 'var(--ggui-font-size-xl, 20px)',
                      }}
                    >
                      {stock.symbol?.toUpperCase() || 'N/A'}
                    </Heading>

                    {/* Company Name */}
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      truncate
                    >
                      {stock.name || '—'}
                    </Text>

                    {/* Price */}
                    <Text
                      style={{
                        fontSize: 'var(--ggui-font-size-2xl, 24px)',
                        fontWeight: 'var(--ggui-font-weight-bold, 700)',
                        color: 'var(--ggui-color-onSurface, #18181b)',
                        marginTop: 'var(--ggui-spacing-2, 8px)',
                      }}
                      as="p"
                    >
                      ${stock.price?.toFixed(2) ?? '0.00'}
                    </Text>

                    {/* Change Row */}
                    <Stack
                      direction="horizontal"
                      gap={8}
                      align="center"
                      style={{
                        marginTop: 'var(--ggui-spacing-2, 8px)',
                      }}
                    >
                      {/* Arrow Icon */}
                      <Text
                        as="span"
                        style={{
                          fontSize: 'var(--ggui-font-size-lg, 18px)',
                          fontWeight: 'var(--ggui-font-weight-bold, 700)',
                          color: changeColor,
                          lineHeight: '1',
                        }}
                      >
                        {isPositive ? '▲' : isNegative ? '▼' : '—'}
                      </Text>

                      {/* Change Amount */}
                      <Text
                        as="span"
                        style={{
                          fontWeight: 'var(--ggui-font-weight-bold, 700)',
                          color: changeColor,
                          fontSize: 'var(--ggui-font-size-sm, 14px)',
                        }}
                      >
                        {isPositive ? '+' : ''}
                        {stock.change?.toFixed(2) ?? '0.00'}
                      </Text>

                      {/* Change Percentage */}
                      <Text
                        as="span"
                        style={{
                          fontWeight: 'var(--ggui-font-weight-bold, 700)',
                          color: changeColor,
                          fontSize: 'var(--ggui-font-size-sm, 14px)',
                        }}
                      >
                        ({isPositive ? '+' : ''}
                        {(stock.changePercent ?? 0).toFixed(2)}%)
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              </Box>
            );
          })}
        </Box>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Box, Divider } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const conditionIconMap: Record<string, string> = {
  sunny: '☀️',
  clear: '☀️',
  cloudy: '☁️',
  'partly cloudy': '⛅',
  overcast: '☁️',
  rainy: '🌧️',
  rain: '🌧️',
  stormy: '⛈️',
  storm: '⛈️',
  thunderstorm: '⛈️',
  snowy: '❄️',
  snow: '❄️',
  foggy: '🌫️',
  fog: '🌫️',
  windy: '💨',
  hail: '🌨️',
  drizzle: '🌦️',
};

function getConditionIcon(condition: string): string {
  const key = condition.toLowerCase();
  for (const [k, v] of Object.entries(conditionIconMap)) {
    if (key.includes(k)) return v;
  }
  return '🌡️';
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  const conditionIcon = getConditionIcon(condition);

  return (
    <Card shadow="lg" padding={0} radius="xl" border>
      {/* Header: gradient background with city + condition */}
      <Box
        background="linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))"
        borderRadius="16px 16px 0 0"
        paddingX={24}
        paddingY={28}
      >
        <Stack direction="vertical" gap={4}>
          {/* City name */}
          <Text
            variant="overline"
            color="var(--ggui-color-primary-200, #bae6fd)"
            as="span"
          >
            {city}
          </Text>

          {/* Temperature + condition icon row */}
          <Stack direction="horizontal" align="center" gap={16} justify="between">
            {/* Large temperature */}
            <div
              aria-label={`Temperature: ${temperature}°${unit}`}
              style={{ lineHeight: 1.1 }}
            >
              <span
                style={{
                  fontSize: '4.5rem',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-neutral-50, #f9fafb)',
                  lineHeight: 1,
                  display: 'inline',
                }}
              >
                {temperature}°
              </span>
              <span
                style={{
                  fontSize: 'var(--ggui-font-size-2xl, 24px)',
                  fontWeight: 'var(--ggui-font-weight-medium, 500)',
                  color: 'var(--ggui-color-primary-200, #bae6fd)',
                  marginLeft: '2px',
                  display: 'inline',
                }}
              >
                {unit}
              </span>
            </div>

            {/* Condition icon + label */}
            <Stack direction="vertical" align="center" gap={4}>
              <span
                style={{ fontSize: '3.5rem', lineHeight: 1 }}
                role="img"
                aria-label={condition}
              >
                {conditionIcon}
              </span>
              <Text
                variant="label"
                color="var(--ggui-color-primary-100, #e0f2fe)"
                align="center"
              >
                {condition}
              </Text>
            </Stack>
          </Stack>
        </Stack>
      </Box>

      {/* Stats row: humidity + wind speed */}
      <Box
        background="var(--ggui-color-surfaceVariant, #f4f4f5)"
        paddingX={24}
        paddingY={16}
      >
        <Stack direction="horizontal" gap={0} justify="around" align="center">
          {/* Humidity */}
          <Stack direction="vertical" align="center" gap={4}>
            <Stack direction="horizontal" align="center" gap={6}>
              <span style={{ fontSize: '1.25rem' }} role="img" aria-label="Humidity">
                💧
              </span>
              <Text
                variant="bodyLarge"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {humidity}%
              </Text>
            </Stack>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
          </Stack>

          {/* Vertical divider */}
          <div
            style={{
              width: '1px',
              height: '40px',
              background: 'var(--ggui-color-outline, #d4d4d8)',
              flexShrink: 0,
            }}
            role="separator"
            aria-orientation="vertical"
          />

          {/* Wind Speed */}
          <Stack direction="vertical" align="center" gap={4}>
            <Stack direction="horizontal" align="center" gap={6}>
              <span style={{ fontSize: '1.25rem' }} role="img" aria-label="Wind">
                💨
              </span>
              <Text
                variant="bodyLarge"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {windSpeed} km/h
              </Text>
            </Stack>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
          </Stack>
        </Stack>
      </Box>

      <Divider margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

      {/* 5-Day Forecast Strip */}
      <Box paddingX={16} paddingY={16}>
        <Text
          variant="overline"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          as="p"
        >
          5-Day Forecast
        </Text>

        <Box margin="8px 0 0 0">
          <Stack direction="horizontal" gap={4} justify="between" align="stretch">
            {forecast.map((item: ForecastDay, index: number) => (
              <Box
                key={index}
                paddingX={8}
                paddingY={12}
                background="var(--ggui-color-surface, #fafafa)"
                borderRadius={8}
                margin={0}
              >
                <Stack direction="vertical" align="center" gap={6}>
                  {/* Day name */}
                  <Text
                    variant="caption"
                    weight="medium"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    align="center"
                  >
                    {item.day ?? '—'}
                  </Text>

                  {/* Weather icon */}
                  <span
                    style={{ fontSize: '1.5rem', lineHeight: 1 }}
                    role="img"
                    aria-label={item.icon ?? 'weather'}
                  >
                    {item.icon ?? '🌡️'}
                  </span>

                  {/* High temp */}
                  <Text
                    variant="label"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                    align="center"
                  >
                    {item.high !== undefined ? `${item.high}°` : '—'}
                  </Text>

                  {/* Low temp */}
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    align="center"
                  >
                    {item.low !== undefined ? `${item.low}°` : '—'}
                  </Text>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Box>
      </Box>
    </Card>
  );
}

import React, { useState, useCallback } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Checkbox,
  RadioGroup,
  Progress,
  Alert,
  Box,
  Divider,
  Badge,
  MotionKeyframes,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Called with all collected answers as a structured object */
  onSubmit?: (answers: SurveyAnswers) => void;
}

interface SurveyAnswers {
  name: string;
  email: string;
  satisfactionRating: string;
  featureInterests: string[];
  comments: string;
}

const TOTAL_STEPS = 4;
const MAX_COMMENTS = 500;

function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = [
      'Dashboard Analytics',
      'API Integrations',
      'Collaboration Tools',
      'Mobile App',
      'Advanced Reporting',
      'Custom Workflows',
    ],
    satisfactionLabels = [
      'Very Unsatisfied',
      'Unsatisfied',
      'Neutral',
      'Satisfied',
      'Very Satisfied',
    ],
    onSubmit,
  } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [showNameError, setShowNameError] = useState(false);
  const [showEmailError, setShowEmailError] = useState(false);

  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const getNameError = useCallback((v: string): string => {
    if (!v.trim()) return 'Name is required';
    return '';
  }, []);

  const getEmailError = useCallback((v: string): string => {
    if (!v.trim()) return 'Email is required';
    if (!isValidEmail(v)) return 'Please enter a valid email address';
    return '';
  }, []);

  const nameError = showNameError ? getNameError(name) : '';
  const emailError = showEmailError ? getEmailError(email) : '';

  const handleNameChange = (value: string) => {
    setName(value);
  };

  const handleEmailChange = (value: string) => {
    setEmail(value);
  };

  const isStep1Valid = !getNameError(name) && !getEmailError(email);
  const isStep2Valid = satisfactionRating !== '';
  const isStep3Valid = featureInterests.length > 0;

  const canProceed = (): boolean => {
    if (currentStep === 1) return isStep1Valid;
    if (currentStep === 2) return isStep2Valid;
    if (currentStep === 3) return isStep3Valid;
    return true;
  };

  const handleNext = () => {
    if (currentStep === 1) {
      setShowNameError(true);
      setShowEmailError(true);
      if (!isStep1Valid) return;
    }
    if (currentStep < TOTAL_STEPS) setCurrentStep((s) => s + 1);
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep((s) => s - 1);
  };

  const toggleFeature = (feature: string) => {
    setFeatureInterests((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  };

  const handleSubmit = async () => {
    setSubmitting(true);
    setSubmitError(null);
    const answers: SurveyAnswers = { name, email, satisfactionRating, featureInterests, comments };
    try {
      await onSubmit?.(answers);
      setSubmitted(true);
    } catch {
      setSubmitError('Something went wrong. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  const satisfactionOptions = satisfactionLabels.map((label, idx) => ({
    value: String(idx + 1),
    label: `${idx + 1} — ${label}`,
  }));

  const progressPercent = Math.round((currentStep / TOTAL_STEPS) * 100);
  const stepTitles = ['Personal Info', 'Satisfaction Rating', 'Feature Interests', 'Comments'];

  if (submitted) {
    return (
      <Box padding="var(--ggui-spacing-6, 24px)" background="var(--ggui-color-surface, #fafafa)">
        <MotionKeyframes />
        <div style={{ maxWidth: 560, margin: '0 auto', animation: 'ggui-scaleIn 300ms cubic-bezier(0.175, 0.885, 0.32, 1.275) both' }}>
          <Card shadow="md" padding={48} radius="xl">
            <Stack gap={24} align="center">
              <div aria-hidden="true" style={{ width: 64, height: 64, borderRadius: '50%', background: 'var(--ggui-color-success-500, #22c55e)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                <svg width={32} height={32} viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round">
                  <polyline points="20 6 9 17 4 12" />
                </svg>
              </div>
              <Stack gap={8} align="center">
                <Heading level={3} align="center">Thank You!</Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                  Your survey response has been submitted. We appreciate your feedback!
                </Text>
              </Stack>
            </Stack>
          </Card>
        </div>
      </Box>
    );
  }

  return (
    <Box padding="var(--ggui-spacing-6, 24px)" background="var(--ggui-color-surface, #fafafa)">
      <MotionKeyframes />
      <div style={{ maxWidth: 560, margin: '0 auto' }}>
        <Stack gap={24}>

          {/* Header */}
          <Stack gap={4}>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">Product Survey</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Help us improve by sharing your feedback
            </Text>
          </Stack>

          {/* Progress card */}
          <Card shadow="none" padding={20} radius="lg" border>
            <Stack gap={10}>
              <Stack direction="horizontal" justify="between" align="center">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Step {currentStep} of {TOTAL_STEPS}
                </Text>
                <Badge variant="primary" size="sm" pill={false}>
                  {stepTitles[currentStep - 1]}
                </Badge>
              </Stack>
              <Progress value={progressPercent} max={100} size="sm" />
              <Stack direction="horizontal" gap={6}>
                {Array.from({ length: TOTAL_STEPS }, (_, i) => (
                  <div
                    key={i}
                    aria-hidden="true"
                    style={{
                      flex: 1,
                      height: 4,
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      background: i + 1 <= currentStep ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)',
                      transition: 'background 0.25s ease',
                    }}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>

          {/* Step content */}
          <Card shadow="sm" padding={28} radius="xl">
            <div key={currentStep} style={{ animation: 'ggui-slideInUp 200ms cubic-bezier(0, 0, 0.2, 1) both' }}>

              {currentStep === 1 && (
                <Stack gap={20}>
                  <Stack gap={4}>
                    <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">Personal Information</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Tell us a bit about yourself</Text>
                  </Stack>
                  <Stack gap={16}>
                    <Input label="Full Name" placeholder="Enter your full name" value={name} onChange={handleNameChange} error={nameError || undefined} required />
                    <Input label="Email Address" type="email" placeholder="you@example.com" value={email} onChange={handleEmailChange} error={emailError || undefined} required />
                  </Stack>
                </Stack>
              )}

              {currentStep === 2 && (
                <Stack gap={20}>
                  <Stack gap={4}>
                    <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">Satisfaction Rating</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      On a scale of 1–{satisfactionLabels.length}, how satisfied are you with our product?
                    </Text>
                  </Stack>
                  <RadioGroup
                    label="Select your satisfaction level"
                    value={satisfactionRating}
                    onChange={setSatisfactionRating}
                    options={satisfactionOptions}
                    direction="vertical"
                  />
                </Stack>
              )}

              {currentStep === 3 && (
                <Stack gap={20}>
                  <Stack gap={4}>
                    <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">Feature Interests</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Which features are you most interested in? Select all that apply.</Text>
                  </Stack>
                  <fieldset style={{ border: 'none', padding: 0, margin: 0 }} aria-label="Feature options">
                    <Stack gap={12}>
                      {featureOptions.map((feature) => (
                        <Checkbox
                          key={feature}
                          label={feature}
                          checked={featureInterests.includes(feature)}
                          onChange={() => toggleFeature(feature)}
                        />
                      ))}
                    </Stack>
                  </fieldset>
                  {featureInterests.length === 0 ? (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Select at least one feature to continue</Text>
                  ) : (
                    <Box paddingX={12} paddingY={6} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius={8}>
                      <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)">
                        {featureInterests.length} feature{featureInterests.length !== 1 ? 's' : ''} selected
                      </Text>
                    </Box>
                  )}
                </Stack>
              )}

              {currentStep === 4 && (
                <Stack gap={20}>
                  <Stack gap={4}>
                    <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">Additional Comments</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Share any additional thoughts or feedback</Text>
                  </Stack>
                  <TextArea
                    label="Comments"
                    placeholder="Tell us anything else you'd like us to know..."
                    value={comments}
                    onChange={setComments}
                    rows={5}
                    maxLength={MAX_COMMENTS}
                    showCount
                    helperText="Optional — feel free to leave this blank"
                  />
                </Stack>
              )}

            </div>
          </Card>

          {/* Review panel */}
          {currentStep === TOTAL_STEPS && (
            <Card shadow="none" padding={24} radius="lg" border>
              <Stack gap={12}>
                <Stack gap={2}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Review Your Answers</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please confirm before submitting</Text>
                </Stack>
                <Divider margin={4} />
                <Stack direction="horizontal" gap={12} align="start">
                  <div style={{ width: 100, flexShrink: 0 }}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                  </div>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">{name}</Text>
                </Stack>
                <Stack direction="horizontal" gap={12} align="start">
                  <div style={{ width: 100, flexShrink: 0 }}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                  </div>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">{email}</Text>
                </Stack>
                <Divider margin={4} />
                <Stack direction="horizontal" gap={12} align="center">
                  <div style={{ width: 100, flexShrink: 0 }}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                  </div>
                  <Badge variant="primary" size="md" pill={false}>
                    {satisfactionRating} — {satisfactionLabels[parseInt(satisfactionRating, 10) - 1]}
                  </Badge>
                </Stack>
                <Divider margin={4} />
                <Stack direction="horizontal" gap={12} align="start">
                  <div style={{ width: 100, flexShrink: 0 }}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Features</Text>
                  </div>
                  <Stack direction="horizontal" gap={6} wrap>
                    {featureInterests.map((f) => (
                      <Badge key={f} variant="default" size="sm" pill={false}>{f}</Badge>
                    ))}
                  </Stack>
                </Stack>
                {comments.trim() && (
                  <>
                    <Divider margin={4} />
                    <Stack direction="horizontal" gap={12} align="start">
                      <div style={{ width: 100, flexShrink: 0 }}>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                      </div>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)" as="div">{comments}</Text>
                    </Stack>
                  </>
                )}
              </Stack>
            </Card>
          )}

          {/* Error */}
          {submitError && (
            <Alert variant="error" title="Submission failed" closable onClose={() => setSubmitError(null)}>
              {submitError}
            </Alert>
          )}

          {/* Navigation */}
          <Stack direction="horizontal" justify="between" align="center">
            <Button variant="ghost" size="md" onClick={handleBack} disabled={currentStep === 1} aria-label="Go to previous step">
              ← Back
            </Button>
            <Stack direction="horizontal" gap={8} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {currentStep} / {TOTAL_STEPS}
              </Text>
              {currentStep < TOTAL_STEPS ? (
                <Button variant="primary" size="md" onClick={handleNext} disabled={!canProceed()} aria-label={`Continue to step ${currentStep + 1}`}>
                  Next →
                </Button>
              ) : (
                <Button variant="primary" size="md" onClick={handleSubmit} loading={submitting} disabled={submitting} aria-label="Submit your survey responses">
                  Submit Survey
                </Button>
              )}
            </Stack>
          </Stack>

        </Stack>
      </div>
    </Box>
  );
}

