import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Card, Stack, Text, Heading, Box, Spinner, Badge, Container, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';

interface StockItem {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks: StockItem[];
  lastUpdated?: string;
}

type ConnectionStatus = 'connecting' | 'connected' | 'loading';

function formatPrice(price: number | undefined): string {
  if (price === undefined || price === null) return '—';
  return price.toFixed(2);
}

function formatChange(change: number | undefined): string {
  if (change === undefined || change === null) return '—';
  const sign = change >= 0 ? '+' : '';
  return `${sign}${change.toFixed(2)}`;
}

function formatPercent(pct: number | undefined): string {
  if (pct === undefined || pct === null) return '—';
  const sign = pct >= 0 ? '+' : '';
  return `${sign}${pct.toFixed(2)}%`;
}

function formatTimestamp(ts: string | undefined): string {
  if (!ts) return 'N/A';
  try {
    return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  } catch {
    return ts;
  }
}

function isPositive(val: number | undefined): boolean {
  return val !== undefined && val > 0;
}

function isNegative(val: number | undefined): boolean {
  return val !== undefined && val < 0;
}

function StockCard({ stock, index }: { stock: StockItem; index: number }) {
  const { motionEnabled } = useMotion();
  const positive = isPositive(stock.change);
  const negative = isNegative(stock.change);
  const neutral = !positive && !negative;

  const borderColor = positive
    ? 'var(--ggui-color-success-500, #22c55e)'
    : negative
    ? 'var(--ggui-color-error-500, #ef4444)'
    : 'var(--ggui-color-outline, #d4d4d8)';

  const changeColor = positive
    ? 'var(--ggui-color-success-600, #16a34a)'
    : negative
    ? 'var(--ggui-color-error-600, #dc2626)'
    : 'var(--ggui-color-onSurfaceVariant, #52525b)';

  const arrow = positive ? '▲' : negative ? '▼' : '●';

  return (
    <div
      style={{
        animation: motionEnabled ? `ggui-slideInUp 300ms cubic-bezier(0,0,0.2,1) ${index * 60}ms both` : 'none',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
        border: `2px solid ${borderColor}`,
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        padding: 'var(--ggui-spacing-4, 16px)',
        transition: 'box-shadow 200ms cubic-bezier(0.4,0,0.2,1), transform 200ms cubic-bezier(0.4,0,0.2,1)',
        cursor: 'default',
        boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
      }}
      onMouseEnter={(e) => {
        (e.currentTarget as HTMLDivElement).style.boxShadow = 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
        (e.currentTarget as HTMLDivElement).style.transform = 'translateY(-2px)';
      }}
      onMouseLeave={(e) => {
        (e.currentTarget as HTMLDivElement).style.boxShadow = 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))';
        (e.currentTarget as HTMLDivElement).style.transform = 'translateY(0)';
      }}
      role="article"
      aria-label={`${stock.symbol ?? 'Stock'} — ${stock.name ?? ''}`}
    >
      <Stack direction="vertical" gap={8}>
        <Stack direction="horizontal" align="center" justify="between">
          <Text as="span" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            {stock.symbol ?? '—'}
          </Text>
          {!neutral && (
            <Badge variant={positive ? 'success' : 'error'} size="sm" pill>
              {positive ? 'UP' : 'DOWN'}
            </Badge>
          )}
        </Stack>

        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
          {stock.name ?? '—'}
        </Text>

        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-outlineVariant, #e4e4e7)',
            margin: 'var(--ggui-spacing-1, 4px) 0',
          }}
          role="separator"
        />

        <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          ${formatPrice(stock.price)}
        </Text>

        <Stack direction="horizontal" align="center" gap={6}>
          <Text
            as="span"
            variant="label"
            color={changeColor}
            aria-label={`Change: ${formatChange(stock.change)}`}
          >
            {formatChange(stock.change)}
          </Text>
          <Text
            as="span"
            variant="label"
            color={changeColor}
            aria-label={`Change percent: ${formatPercent(stock.changePercent)}`}
          >
            <span aria-hidden="true" style={{ marginRight: 'var(--ggui-spacing-1, 4px)' }}>{arrow}</span>
            {formatPercent(stock.changePercent)}
          </Text>
        </Stack>
      </Stack>
    </div>
  );
}

function ConnectionBadge({ status }: { status: ConnectionStatus }) {
  if (status === 'connected') {
    return (
      <Stack direction="horizontal" align="center" gap={6}>
        <div
          style={{
            width: 'var(--ggui-spacing-2, 8px)',
            height: 'var(--ggui-spacing-2, 8px)',
            borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
            background: 'var(--ggui-color-success-500, #22c55e)',
            animation: 'ggui-pulse 2s ease-in-out infinite',
          }}
          aria-hidden="true"
        />
        <Text variant="caption" color="var(--ggui-color-success-600, #16a34a)">Live</Text>
      </Stack>
    );
  }
  if (status === 'connecting') {
    return (
      <Stack direction="horizontal" align="center" gap={6}>
        <Spinner size={12} color="var(--ggui-color-warning-500, #f59e0b)" />
        <Text variant="caption" color="var(--ggui-color-warning-600, #d97706)">Connecting…</Text>
      </Stack>
    );
  }
  return (
    <Stack direction="horizontal" align="center" gap={6}>
      <Spinner size={12} color="var(--ggui-color-primary-600, #0284c7)" />
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Loading…</Text>
    </Stack>
  );
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [stocks, setStocks] = useState<StockItem[]>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [status, setStatus] = useState<ConnectionStatus>('connecting');
  const [updatedSymbols, setUpdatedSymbols] = useState<Set<string>>(new Set());
  const flashTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => { setStocks(props.stocks ?? []); }, [props.stocks]);
  useEffect(() => { setLastUpdated(props.lastUpdated); }, [props.lastUpdated]);

  // Auto-transition to connected after a grace period
  useEffect(() => {
    const timer = setTimeout(() => {
      setStatus((prev) => (prev === 'connecting' ? 'connected' : prev));
    }, 2000);
    return () => clearTimeout(timer);
  }, []);

  // Stream Contract: ggui:agent-data event listener
  const handleAgentData = useCallback((event: Event) => {
    const { detail: data } = event as CustomEvent;
    if (!data) return;
    setStatus('connected');
    if (Array.isArray(data.stocks)) {
      const incoming: StockItem[] = data.stocks;
      const newSymbols = new Set<string>(
        incoming.map((s: StockItem) => s.symbol ?? '').filter(Boolean)
      );
      if (flashTimerRef.current) clearTimeout(flashTimerRef.current);
      setUpdatedSymbols(newSymbols);
      flashTimerRef.current = setTimeout(() => setUpdatedSymbols(new Set()), 800);
      setStocks(incoming);
    }
    if (data.lastUpdated) setLastUpdated(data.lastUpdated);
  }, []);

  useEffect(() => {
    const target = typeof globalThis !== 'undefined' ? (globalThis as unknown as EventTarget) : null;
    if (!target || typeof (target as Window & typeof globalThis).addEventListener !== 'function') return;
    const win = target as Window & typeof globalThis;
    win.addEventListener('ggui:agent-data', handleAgentData);
    return () => {
      win.removeEventListener('ggui:agent-data', handleAgentData);
      if (flashTimerRef.current) clearTimeout(flashTimerRef.current);
    };
  }, [handleAgentData]);

  const isLoading = stocks.length === 0 && status !== 'connected';

  return (
    <>
      <MotionKeyframes />
      <style>{`
        @keyframes ggui-pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.35; }
        }
        @keyframes ggui-flash {
          0% { opacity: 1; }
          40% { opacity: 0.65; background: var(--ggui-color-primary-50, #f0f9ff); }
          100% { opacity: 1; }
        }
      `}</style>

      <Box background="var(--ggui-color-surface, #fafafa)" padding="var(--ggui-spacing-6, 24px) 0">
        <Container maxWidth="2xl" padding="0 var(--ggui-spacing-6, 24px)">
          <Stack direction="vertical" gap={24}>

            {/* ── Header ── */}
            <div
              style={{
                background: 'linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))',
                borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
                padding: 'var(--ggui-spacing-6, 24px)',
                boxShadow: 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))',
                animation: motionEnabled ? 'ggui-fadeIn 400ms cubic-bezier(0,0,0.2,1) both' : 'none',
              }}
              role="banner"
            >
              <Stack direction="horizontal" align="center" justify="between" wrap>
                <Stack direction="vertical" gap={4}>
                  <Heading level={1} color="var(--ggui-color-neutral-50, #f9fafb)">
                    Market Watch
                  </Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-primary-200, #bae6fd)">
                    Real-time stock prices
                  </Text>
                </Stack>

                <Stack direction="vertical" align="end" gap={8}>
                  <ConnectionBadge status={status} />
                  <Stack direction="horizontal" align="center" gap={6}>
                    <Text variant="caption" color="var(--ggui-color-primary-200, #bae6fd)">
                      Last Updated:
                    </Text>
                    <Text
                      variant="caption"
                      weight="medium"
                      color="var(--ggui-color-neutral-50, #f9fafb)"
                      aria-live="polite"
                      aria-label={`Last updated at ${formatTimestamp(lastUpdated)}`}
                    >
                      {formatTimestamp(lastUpdated)}
                    </Text>
                  </Stack>
                </Stack>
              </Stack>
            </div>

            {/* ── Connecting / Loading State ── */}
            {isLoading && (
              <Card shadow="sm" padding={48}>
                <Stack direction="vertical" align="center" gap={16}>
                  <Spinner size={40} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                    {status === 'connecting' ? 'Connecting to market data…' : 'Loading stocks…'}
                  </Text>
                </Stack>
              </Card>
            )}

            {/* ── Stock Grid ── */}
            {stocks.length > 0 && (
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
                  gap: 'var(--ggui-spacing-4, 16px)',
                }}
                role="list"
                aria-label="Stock prices"
                aria-live="polite"
                aria-atomic="false"
              >
                {stocks.map((stock, index) => (
                  <div
                    key={stock.symbol ?? `stock-${index}`}
                    role="listitem"
                    style={{
                      animation: updatedSymbols.has(stock.symbol ?? '')
                        ? 'ggui-flash 600ms ease-out'
                        : 'none',
                    }}
                  >
                    <StockCard stock={stock} index={index} />
                  </div>
                ))}
              </div>
            )}

            {/* ── Empty connected state ── */}
            {stocks.length === 0 && status === 'connected' && (
              <Card shadow="sm" padding={48}>
                <Stack direction="vertical" align="center" gap={12}>
                  <Text size="3xl" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center" as="p">
                    📈
                  </Text>
                  <Text
                    variant="bodyLarge"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                    align="center"
                  >
                    No stocks to display
                  </Text>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    align="center"
                  >
                    Stock data will appear here once received.
                  </Text>
                </Stack>
              </Card>
            )}

            {/* ── Disclaimer ── */}
            {stocks.length > 0 && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                Prices may be delayed. Not financial advice.
              </Text>
            )}

          </Stack>
        </Container>
      </Box>
    </>
  );
}

import React, { useState, useCallback } from 'react';
import {
  Card, Stack, Text, Heading, Button, Input, Select, Toggle,
  Box, Divider, Progress, Badge, MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';

interface ProfileData {
  name?: string;
  email?: string;
  avatar?: string;
  role?: string;
  emailNotifications?: boolean;
  theme?: string;
}

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: ProfileData;
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Called with all profile data when user completes onboarding */
  onComplete?: (data: Required<ProfileData>) => void;
}

const TOTAL_STEPS = 3;
const STEP_LABELS = ['Profile Setup', 'Preferences', 'Review & Confirm'];

function isValidEmail(v: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

interface ReviewRowProps {
  label: string;
  value: React.ReactNode;
  isFirst?: boolean;
  isLast?: boolean;
}

function ReviewRow({ label, value, isFirst, isLast }: ReviewRowProps) {
  return (
    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingLeft: 'var(--ggui-spacing-4, 16px)', paddingRight: 'var(--ggui-spacing-4, 16px)', paddingTop: isFirst ? 'var(--ggui-spacing-4, 16px)' : 'var(--ggui-spacing-2, 8px)', paddingBottom: isLast ? 'var(--ggui-spacing-4, 16px)' : 'var(--ggui-spacing-2, 8px)', borderBottom: !isLast ? '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' : 'none', backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}>
      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{label}</Text>
      {typeof value === 'string'
        ? <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)">{value}</Text>
        : <div>{value}</div>}
    </div>
  );
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions, roleOptions, onComplete } = props;
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState(1);
  const [animDir, setAnimDir] = useState<'forward' | 'back'>('forward');

  const [name, setName] = useState(initialProfile.name ?? '');
  const [email, setEmail] = useState(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(initialProfile.avatar ?? (avatarOptions[0] ?? ''));
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  const [role, setRole] = useState(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialProfile.theme ?? 'light');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const roleSelectOptions = roleOptions.map((r) => ({ value: r, label: r }));

  const validateStep1 = useCallback((): boolean => {
    let ok = true;
    if (!name.trim()) { setNameError('Name is required'); ok = false; } else { setNameError(''); }
    if (!email.trim()) { setEmailError('Email is required'); ok = false; }
    else if (!isValidEmail(email)) { setEmailError('Please enter a valid email address'); ok = false; }
    else { setEmailError(''); }
    return ok;
  }, [name, email]);

  const isStep1Valid = name.trim().length > 0 && isValidEmail(email);
  const isStep2Valid = role.length > 0;

  const goNext = () => {
    if (currentStep === 1 && !validateStep1()) return;
    setAnimDir('forward');
    setCurrentStep((s) => Math.min(s + 1, TOTAL_STEPS));
  };
  const goBack = () => {
    setAnimDir('back');
    setCurrentStep((s) => Math.max(s - 1, 1));
  };
  const handleComplete = () => {
    setIsSubmitting(true);
    onComplete?.({ name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme });
    setIsSubmitting(false);
  };

  const stepAnim = motionEnabled
    ? (animDir === 'forward' ? 'ggui-slideInUp 250ms cubic-bezier(0,0,0.2,1) both' : 'ggui-slideInDown 250ms cubic-bezier(0,0,0.2,1) both')
    : 'none';
  const progressPct = ((currentStep - 1) / (TOTAL_STEPS - 1)) * 100;

  return (
    <>
      <MotionKeyframes />
      <Box background="var(--ggui-color-surface, #fafafa)" padding="var(--ggui-spacing-12, 48px) var(--ggui-spacing-4, 16px)">
        <div style={{ maxWidth: 540, margin: '0 auto' }}>

          {/* Header */}
          <div style={{ textAlign: 'center', marginBottom: 'var(--ggui-spacing-6, 24px)' }}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)" align="center">Account Setup</Heading>
            <div style={{ marginTop: 4 }}>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">Complete your profile to get started</Text>
            </div>
          </div>

          {/* Step Indicator */}
          <Card shadow="none" border padding={20} radius="lg">
            <Stack gap={16}>
              <div role="list" aria-label="Onboarding steps" style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between' }}>
                {STEP_LABELS.map((label, i) => {
                  const n = i + 1;
                  const done = n < currentStep;
                  const active = n === currentStep;
                  return (
                    <React.Fragment key={n}>
                      <div role="listitem" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6 }}>
                        <div
                          aria-current={active ? 'step' : undefined}
                          aria-label={`Step ${n}: ${label}${done ? ' (completed)' : active ? ' (current)' : ''}`}
                          style={{
                            width: 36, height: 36,
                            borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            backgroundColor: done || active ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-neutral-200, #e5e7eb)',
                            color: done || active ? 'var(--ggui-color-neutral-50, #f9fafb)' : 'var(--ggui-color-neutral-500, #6b7280)',
                            fontSize: 'var(--ggui-font-size-sm, 14px)',
                            fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                            transition: 'background-color 300ms ease-in-out',
                            flexShrink: 0, userSelect: 'none' as const,
                          }}
                        >
                          {done ? '✓' : n}
                        </div>
                        <Text variant="caption" align="center"
                          color={active ? 'var(--ggui-color-primary-700, #0369a1)' : done ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                          weight={active ? 'medium' : 'normal'}
                        >
                          {label}
                        </Text>
                      </div>
                      {i < STEP_LABELS.length - 1 && (
                        <div aria-hidden="true" style={{ flex: 1, height: 2, marginTop: 17, marginLeft: 8, marginRight: 8, backgroundColor: n < currentStep ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-neutral-200, #e5e7eb)', transition: 'background-color 300ms ease-in-out' }} />
                      )}
                    </React.Fragment>
                  );
                })}
              </div>
              <Progress value={progressPct} max={100} variant="default" size="sm" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">Step {currentStep} of {TOTAL_STEPS}</Text>
            </Stack>
          </Card>

          {/* Step Content */}
          <div style={{ marginTop: 'var(--ggui-spacing-4, 16px)' }}>
            <Card shadow="md" border padding={28} radius="lg">
              <div key={currentStep} style={{ animation: stepAnim }}>

                {/* Step 1 */}
                {currentStep === 1 && (
                  <Stack gap={20}>
                    <Stack gap={4}>
                      <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">Profile Setup</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Tell us a bit about yourself.</Text>
                    </Stack>
                    <Input label="Full Name" placeholder="Enter your full name" value={name} onChange={(v) => { setName(v); if (nameError) setNameError(''); }} required error={nameError || undefined} />
                    <Input label="Email Address" type="email" placeholder="you@example.com" value={email} onChange={(v) => { setEmail(v); if (emailError) setEmailError(''); }} required error={emailError || undefined} />
                    <Stack gap={8}>
                      <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                        Choose Your Avatar <span aria-hidden="true" style={{ color: 'var(--ggui-color-error-500, #ef4444)' }}>*</span>
                      </Text>
                      <div role="radiogroup" aria-label="Avatar selection" style={{ display: 'flex', gap: 'var(--ggui-spacing-2, 8px)', flexWrap: 'wrap' }}>
                        {avatarOptions.map((emoji) => {
                          const sel = avatar === emoji;
                          return (
                            <button
                              key={emoji} type="button" role="radio" aria-checked={sel}
                              aria-label={`Avatar: ${emoji}`}
                              onClick={() => setAvatar(emoji)}
                              onFocus={(e) => { e.currentTarget.style.outline = '2px solid var(--ggui-color-primary-600, #0284c7)'; e.currentTarget.style.outlineOffset = '2px'; }}
                              onBlur={(e) => { e.currentTarget.style.outline = 'none'; }}
                              style={{
                                width: 60, height: 60,
                                borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                                border: sel ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid var(--ggui-color-outline, #d4d4d8)',
                                backgroundColor: sel ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                                fontSize: 28, cursor: 'pointer',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                transition: 'border-color 200ms ease-in-out, background-color 200ms ease-in-out, transform 150ms ease-in-out, box-shadow 200ms ease-in-out',
                                transform: sel ? 'scale(1.08)' : 'scale(1)',
                                boxShadow: sel ? '0 0 0 3px var(--ggui-color-primary-200, #bae6fd)' : 'none',
                                outline: 'none',
                              }}
                            >
                              {emoji}
                            </button>
                          );
                        })}
                      </div>
                    </Stack>
                  </Stack>
                )}

                {/* Step 2 */}
                {currentStep === 2 && (
                  <Stack gap={20}>
                    <Stack gap={4}>
                      <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">Preferences</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Customize your experience.</Text>
                    </Stack>
                    <Select label="Your Role" value={role} onChange={setRole} options={roleSelectOptions} placeholder="Select your role" required />
                    <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)" paddingX={16} paddingY={14}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <Stack gap={2}>
                          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Email Notifications</Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Receive updates and alerts via email</Text>
                        </Stack>
                        <Toggle label="Email notifications" checked={emailNotifications} onChange={setEmailNotifications} size="md" />
                      </div>
                    </Box>
                    <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)" paddingX={16} paddingY={14}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <Stack gap={2}>
                          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">Theme Preference</Text>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{theme === 'dark' ? '🌙 Dark mode' : '☀️ Light mode'}</Text>
                        </Stack>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                          <span aria-hidden="true" style={{ fontSize: 16 }}>☀️</span>
                          <Toggle label={theme === 'dark' ? 'Switch to light mode' : 'Switch to dark mode'} checked={theme === 'dark'} onChange={(v) => setTheme(v ? 'dark' : 'light')} size="md" />
                          <span aria-hidden="true" style={{ fontSize: 16 }}>🌙</span>
                        </div>
                      </div>
                    </Box>
                  </Stack>
                )}

                {/* Step 3 */}
                {currentStep === 3 && (
                  <Stack gap={20}>
                    <Stack gap={4}>
                      <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">Review & Confirm</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Review your details before completing setup.</Text>
                    </Stack>

                    {/* Profile summary */}
                    <div style={{ borderRadius: 'var(--ggui-shape-radius-md, 8px)', border: '1px solid var(--ggui-color-outline, #d4d4d8)', overflow: 'hidden' }}>
                      <div style={{ backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)', padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)', borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)' }}>
                        <Text variant="overline" color="var(--ggui-color-primary-700, #0369a1)">Profile</Text>
                      </div>
                      <ReviewRow label="Avatar" value={<span style={{ fontSize: 24 }}>{avatar}</span>} isFirst />
                      <ReviewRow label="Name" value={name} />
                      <ReviewRow label="Email" value={email} isLast />
                    </div>

                    {/* Preferences summary */}
                    <div style={{ borderRadius: 'var(--ggui-shape-radius-md, 8px)', border: '1px solid var(--ggui-color-outline, #d4d4d8)', overflow: 'hidden' }}>
                      <div style={{ backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)', padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)', borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)' }}>
                        <Text variant="overline" color="var(--ggui-color-primary-700, #0369a1)">Preferences</Text>
                      </div>
                      <ReviewRow label="Role" value={role || '—'} isFirst />
                      <ReviewRow label="Email Notifications" value={<Badge variant={emailNotifications ? 'success' : 'default'} size="sm">{emailNotifications ? 'Enabled' : 'Disabled'}</Badge>} />
                      <ReviewRow label="Theme" value={<Badge variant="primary" size="sm">{theme === 'dark' ? '🌙 Dark' : '☀️ Light'}</Badge>} isLast />
                    </div>

                    <Box background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius="var(--ggui-shape-radius-md, 8px)" paddingX={16} paddingY={12}>
                      <Text variant="bodySmall" color="var(--ggui-color-primary-700, #0369a1)">
                        🎉 Everything looks great! Click "Complete Setup" to activate your account.
                      </Text>
                    </Box>
                  </Stack>
                )}

              </div>

              {/* Navigation */}
              <div style={{ marginTop: 'var(--ggui-spacing-6, 24px)' }}>
                <Divider margin={0} />
                <div style={{ display: 'flex', justifyContent: currentStep === 1 ? 'flex-end' : 'space-between', alignItems: 'center', marginTop: 'var(--ggui-spacing-4, 16px)' }}>
                  {currentStep > 1 && (
                    <Button variant="outline" onClick={goBack} aria-label="Go back to previous step">← Go Back</Button>
                  )}
                  {currentStep < TOTAL_STEPS && (
                    <Button variant="primary" onClick={goNext} disabled={currentStep === 1 ? !isStep1Valid : !isStep2Valid} aria-label={`Continue to step ${currentStep + 1}`}>
                      Next Step →
                    </Button>
                  )}
                  {currentStep === TOTAL_STEPS && (
                    <Button variant="primary" onClick={handleComplete} loading={isSubmitting} aria-label="Complete account setup">
                      Complete Setup ✓
                    </Button>
                  )}
                </div>
              </div>
            </Card>
          </div>

        </div>
      </Box>
    </>
  );
}
